  isActive: boolean;
  complianceLevel: 'Standard' | 'Strict' | 'Critical';
  history?: { timestamp: string; author: string; message: string }[];
  domainId: string;
}

export interface AuditLog {
  id: string;
  timestamp: string;
  userId: string;
  action: string;
  entityType: 'Process' | 'Task' | 'Instance' | 'System' | 'User' | 'Case' | 'Rule';
  entityId: string;
  details: string;
  severity: 'Info' | 'Warning' | 'Alert';
}

export interface TaskHistory {
  id: string;
  stepName: string;
  action: string;
  performer: string;
  timestamp: string;
  comments?: string;
}

export interface ProcessInstance {
  id: string;
  definitionId: string;
  definitionName: string;
  status: 'Active' | 'Completed' | 'Terminated' | 'Suspended';
  activeStepIds: string[];
  startDate: string;
  endDate?: string;
  dueDate?: string;
  variables: Record<string, any>;
  priority: TaskPriority;
  history: TaskHistory[];
  comments: Comment[];
  complianceVerified: boolean;
  domainId: string; 
}

// ---- ADAPTIVE CASE MANAGEMENT ----
export interface CaseStakeholder {
  userId: string;
  role: 'Owner' | 'Consultant' | 'Approver' | 'Auditor';
}
export interface CaseEvent {
  id: string;
  timestamp: string;
  type: 'Manual' | 'System' | 'Task Completion' | 'Rule Trigger';
  description: string;
  author: string;
}
export interface CasePolicy {
  id: string;
  description: string;
  isEnforced: boolean;
}
export interface Case {
  id: string;
  title: string;
  description: string;
  status: 'Open' | 'In Progress' | 'Pending Review' | 'Resolved' | 'Closed';
  priority: TaskPriority;
  createdAt: string;
  resolvedAt?: string;
