                  <NexFormGroup label="On Entry Script">
                      <div className="relative">
                        <textarea className="prop-input h-20 font-mono text-[10px]" placeholder="console.log('Entering step');" value={step.onEntryAction || ''} onChange={e => updateField('onEntryAction', e.target.value)} />
                        {step.onEntryAction && <Sparkles size={12} className="absolute right-2 bottom-2 text-amber-500 animate-pulse"/>}
                      </div>
                  </NexFormGroup>

                  <NexFormGroup label="On Exit Script">
                      <textarea className="prop-input h-20 font-mono text-[10px]" placeholder="execution.setVariable('status', 'done');" value={step.onExitAction || ''} onChange={e => updateField('onExitAction', e.target.value)} />
                  </NexFormGroup>
              </div>
          )}

          {/* TAB: POLICY (Retry, Timeout) */}
          {activeTab === 'policy' && (
              <div className="space-y-4">
                  <div className="flex items-center justify-between">
                      <h4 className="text-xs font-bold text-slate-700">Retry Policy</h4>
                      <label className="relative inline-flex items-center cursor-pointer">
                        <input type="checkbox" className="sr-only peer" checked={step.retryPolicy?.enabled || false} onChange={e => updateRetry('enabled', e.target.checked)} />
                        <div className="w-9 h-5 bg-slate-200 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-4 after:w-4 after:transition-all peer-checked:bg-blue-600"></div>
                      </label>
                  </div>

                  {step.retryPolicy?.enabled && (
                      <div className="p-3 bg-white border border-slate-200 rounded-sm space-y-3 animate-slide-up">
                          <NexFormGroup label="Strategy">
                              <select className="prop-input" value={step.retryPolicy?.strategy || 'fixed'} onChange={e => updateRetry('strategy', e.target.value)}>
                                  <option value="fixed">Fixed Delay</option>
                                  <option value="exponential">Exponential Backoff</option>
                                  <option value="linear">Linear Backoff</option>
                              </select>
                          </NexFormGroup>
                          <div className="grid grid-cols-2 gap-2">
                              <NexFormGroup label="Max Attempts">
                                  <input type="number" className="prop-input" value={step.retryPolicy?.maxAttempts || 3} onChange={e => updateRetry('maxAttempts', parseInt(e.target.value))} />
                              </NexFormGroup>
                              <NexFormGroup label="Delay (ms)">
                                  <input type="number" className="prop-input" value={step.retryPolicy?.delayMs || 1000} onChange={e => updateRetry('delayMs', parseInt(e.target.value))} />
                              </NexFormGroup>
                          </div>
                      </div>
                  )}

                  <div className="pt-4 border-t border-slate-200">
                      <NexFormGroup label="Loop Characteristics">
                          <label className="flex items-center gap-2 p-2 border border-slate-200 rounded-sm hover:bg-white cursor-pointer">
                              <input type="checkbox" checked={step.isMultiInstance || false} onChange={e => updateField('isMultiInstance', e.target.checked)} className="rounded-sm text-blue-600"/>
                              <div className="flex items-center gap-2">
                                  <RefreshCw size={14} className="text-slate-500"/>
                                  <span className="text-xs text-slate-700 font-medium">Multi-Instance (Parallel)</span>
                              </div>
                          </label>
                      </NexFormGroup>
                  </div>
              </div>
          )}

        </div>

        {/* Footer Actions */}
        <div className="p-4 border-t border-slate-200 bg-slate-50 flex justify-between items-center">
          <button onClick={() => onDelete(step.id)} className="text-rose-600 hover:bg-rose-50 p-2 rounded-sm transition-colors" title="Delete Step">
              <Trash2 size={16}/>
          </button>
          <div className="text-[9px] text-slate-400 font-mono">ID: {step.id}</div>
        </div>
      </aside>
    );
};

import React from 'react';
import { ProcessStep } from '../../types';
import { getStepTypeMetadata } from './designerUtils';
import { FunctionSquare, RefreshCw, Code, AlertCircle, Layers } from 'lucide-react';

interface NodeComponentProps {
  step: ProcessStep;
  isSelected: boolean;
}

export const NodeComponent: React.FC<NodeComponentProps> = ({ step, isSelected }) => {
  const { icon: Icon, color } = getStepTypeMetadata(step.type);

  // Logic Detection
  const hasRule = !!step.businessRuleId;
  const hasScript = !!step.onEntryAction || !!step.onExitAction;
  const hasRetry = step.retryPolicy?.enabled;
  const isLoop = step.isMultiInstance;
  const missingConfig = step.type === 'service-task' && !step.data?.url; // Simple validation example

  return (
    <div 
      data-node-id={step.id} 
      className={`absolute w-[200px] h-[80px] bg-panel border flex flex-col shadow-sm transition-all select-none group ${
        isSelected 
          ? 'border-active ring-1 ring-blue-600 z-node-active' 
          : 'border-default hover:border-tertiary z-node'
      }`} 
      style={{ 
        left: step.position?.x, 
        top: step.position?.y,
        borderRadius: 'var(--radius-base)' 
      }}
    >
      {/* Main Body */}
      <div className="flex items-center gap-3 px-3 pt-3 pb-1 flex-1 overflow-hidden">
        <div className={`w-8 h-8 flex items-center justify-center rounded-base bg-subtle border border-default relative shrink-0`}>
          <Icon size={16} className={color.replace('text-', 'text-opacity-80 text-')} />
          {missingConfig && (
             <div className="absolute -top-1 -right-1 bg-white rounded-full">
                <AlertCircle size={12} className="text-rose-500 fill-white"/>
             </div>
          )}
        </div>

        <div className="flex-1 min-w-0">
          <p className="text-[12px] font-bold text-primary truncate leading-tight">
            {step.name}
          </p>
          <p className="text-[10px] text-secondary uppercase tracking-wide truncate mt-0.5">
            {step.type.replace(/-/g, ' ')}
          </p>
        </div>
      </div>

      {/* Logic Badges Bar */}
      {(hasRule || hasScript || hasRetry || isLoop) && (
          <div className="px-3 pb-2 flex gap-1.5 items-center">
              {hasRule && (
                  <div className="flex items-center gap-0.5 px-1 py-0.5 bg-indigo-50 border border-indigo-100 rounded-[2px] text-[8px] font-bold text-indigo-700" title="Business Rule Attached">
                      <FunctionSquare size={8} /> RULE
                  </div>
              )}
              {hasScript && (
                  <div className="flex items-center gap-0.5 px-1 py-0.5 bg-amber-50 border border-amber-100 rounded-[2px] text-[8px] font-bold text-amber-700" title="Entry/Exit Script Active">
                      <Code size={8} /> FN
                  </div>
              )}
              {hasRetry && (
                  <div className="flex items-center gap-0.5 px-1 py-0.5 bg-blue-50 border border-blue-100 rounded-[2px] text-[8px] font-bold text-blue-700" title={`Retry Policy: ${step.retryPolicy?.maxAttempts}x`}>
                      <RefreshCw size={8} /> {step.retryPolicy?.maxAttempts}x
                  </div>
              )}
              {isLoop && (
                  <div className="ml-auto text-secondary" title="Multi-Instance Loop">
                      <Layers size={10} />
                  </div>
              )}
          </div>
      )}

      {/* Connector Handle */}
      <div 
        data-handle-id={step.id} 
        className="absolute -right-1.5 top-1/2 -translate-y-1/2 w-3 h-3 bg-tertiary border border-white rounded-full cursor-crosshair hover:bg-active hover:scale-125 transition-all z-tooltip opacity-0 group-hover:opacity-100"
      />
    </div>
  );
};

import React, { useState, useRef, useMemo, useEffect } from 'react';
import { ProcessStep, ProcessLink, ProcessStepType } from '../types';
import { useBPM } from '../contexts/BPMContext';
import { 
  Save, ZoomIn, ZoomOut, Sparkles, Cpu, LayoutPanelLeft, Trash2,
} from 'lucide-react';
import { PaletteSidebar } from './designer/PaletteSidebar';
import { NodeComponent } from './designer/NodeComponent';
import { PropertiesPanel } from './designer/PropertiesPanel';
import { CanvasContextMenu } from './designer/CanvasContextMenu'; // Imported
import { getStepTypeMetadata } from './designer/designerUtils';
import { generateProcessWorkflow } from '../services/geminiService';

const GRID_SIZE = 20;

export const ProcessDesigner: React.FC = () => {
  const { deployProcess, roles, addNotification, designerDraft, setDesignerDraft, navigateTo } = useBPM();
  const [processName, setProcessName] = useState('Strategic Workflow');
  const [steps, setSteps] = useState<ProcessStep[]>([]);
  const [links, setLinks] = useState<ProcessLink[]>([]);
  const [viewport, setViewport] = useState({ x: 50, y: 50, zoom: 1 });
  const [selectedId, setSelectedId] = useState<string | null>(null);

  // Context Menu & Clipboard State
  const [contextMenu, setContextMenu] = useState<{ position: { x: number; y: number }, targetId: string | null } | null>(null);
  const [clipboard, setClipboard] = useState<ProcessStep | null>(null);

  // AI States
  const [aiPrompt, setAiPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);

  const [paletteOpen, setPaletteOpen] = useState(true);

  const canvasRef = useRef<HTMLDivElement>(null);
  const isDragging = useRef(false);
  const dragStart = useRef({ x: 0, y: 0 });
  const dragTarget = useRef<'viewport' | 'node' | 'link'>('viewport');
  const activeId = useRef<string | null>(null);
  const ghostLink = useRef<{x1: number, y1: number, x2: number, y2: number} | null>(null);

  // Restore state from context if available
  useEffect(() => {
    if (designerDraft) {
        setSteps(designerDraft.steps);
        setLinks(designerDraft.links);
    }
  }, []);

  // Persist state to context on change
  useEffect(() => {
    setDesignerDraft({ steps, links });
  }, [steps, links, setDesignerDraft]);

  const snapToGrid = (val: number) => Math.round(val / GRID_SIZE) * GRID_SIZE;

  const screenToWorld = (sx: number, sy: number) => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const rect = canvasRef.current.getBoundingClientRect();
    return { 
      x: (sx - rect.left - viewport.x) / viewport.zoom, 
      y: (sy - rect.top - viewport.y) / viewport.zoom 
    };
  };

  // --- Actions ---

  const handleDeploy = async () => {
    const connectedSteps = steps.map(step => {
        const outgoingLinks = links.filter(l => l.sourceId === step.id);
        return {
            ...step,
            nextStepIds: outgoingLinks.map(l => l.targetId)
        };
    });

    await deployProcess({ 
        name: processName, 
        steps: connectedSteps, 
        links, 
        isActive: true, 
        version: 1 
    });
    addNotification('success', 'Process definition deployed successfully.');
  };

  const handleClear = () => {
    if(window.confirm('Clear current design?')) {
        setSteps([]);
        setLinks([]);
        setSelectedId(null);
    }
  };

  const handleAiGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!aiPrompt.trim()) return;
    setIsGenerating(true);
    try {
      const generatedSteps = await generateProcessWorkflow(aiPrompt);
      if (generatedSteps && generatedSteps.length > 0) {
        setSteps(generatedSteps);
        const newLinks: ProcessLink[] = [];
        for(let i=0; i < generatedSteps.length - 1; i++) {
          newLinks.push({ id: `link-auto-${i}`, sourceId: generatedSteps[i].id, targetId: generatedSteps[i+1].id });
        }
        setLinks(newLinks);
        addNotification('success', 'Model synthesized.');
        setAiPrompt('');
      }
    } catch (err) { addNotification('error', 'Generation failure.'); } finally { setIsGenerating(false); }
  };

  const handleSimulation = async () => {
    if (steps.length === 0) {
      addNotification('error', 'Canvas is empty. Add steps to simulate.');
      return;
    }
    navigateTo('simulation-report');
  };

  const addNode = (type: ProcessStepType, position?: { x: number, y: number }) => {
    const world = position || screenToWorld(window.innerWidth / 2, window.innerHeight / 2);
    const metadata = getStepTypeMetadata(type);
    const newNode: ProcessStep = {
      id: `node-${Date.now()}`, name: metadata.defaultName, type, description: '',
      position: { x: snapToGrid(world.x - (position ? 0 : 100)), y: snapToGrid(world.y - (position ? 0 : 40)) },
      requiredSkills: metadata.defaultSkills || [], data: {}
    };
    setSteps(prev => [...prev, newNode]);
    setSelectedId(newNode.id);
  };

  // --- Context Menu Handlers ---

  const handleContextMenu = (e: React.MouseEvent) => {
    e.preventDefault();
    const target = e.target as HTMLElement;
    const nodeEl = target.closest('[data-node-id]');
    const targetId = nodeEl ? nodeEl.getAttribute('data-node-id') : null;

    // Select the node immediately if right-clicked
    if (targetId) setSelectedId(targetId);

    setContextMenu({
      position: { x: e.clientX, y: e.clientY },
      targetId
    });
  };

  const handleMenuAction = (action: string, payload?: any) => {
    if (!contextMenu) return;
    const { targetId, position } = contextMenu;

    switch (action) {
      case 'delete':
        if (targetId) deleteStep(targetId);
        break;

      case 'duplicate':
        if (targetId) {
          const original = steps.find(s => s.id === targetId);
          if (original) {
            const newNode = {
              ...original,
              id: `node-${Date.now()}`,
              name: `${original.name} (Copy)`,
              position: { x: (original.position?.x || 0) + 20, y: (original.position?.y || 0) + 20 }
            };
            setSteps(prev => [...prev, newNode]);
            setSelectedId(newNode.id);
          }
        }
        break;

      case 'copy':
        if (targetId) {
          const node = steps.find(s => s.id === targetId);
          if (node) {
            setClipboard(node);
            addNotification('info', 'Copied to clipboard');
          }
        }
        break;

      case 'paste':
        if (clipboard) {
          const world = screenToWorld(position.x, position.y);
          const newNode = {
            ...clipboard,
            id: `node-${Date.now()}`,
            name: clipboard.name, 
            position: { x: snapToGrid(world.x), y: snapToGrid(world.y) }
          };
          setSteps(prev => [...prev, newNode]);
          setSelectedId(newNode.id);
          addNotification('success', 'Pasted component');
        } else {
          addNotification('info', 'Clipboard is empty');
        }
        break;

      case 'disconnect':
        if (targetId) {
          setLinks(prev => prev.filter(l => l.sourceId !== targetId && l.targetId !== targetId));
          addNotification('info', 'Links removed.');
        }
        break;

      case 'edit':
        // Already selected by context menu open logic, panel is open
        break;

      case 'add-node':
        // Calculate world coordinates for the click position
        const world = screenToWorld(position.x, position.y);
        addNode(payload, { x: world.x, y: world.y });
        break;

      case 'reset-view':
        setViewport({ x: 50, y: 50, zoom: 1 });
        break;

      case 'clear-canvas':
        handleClear();
        break;
    }
    setContextMenu(null);
  };

  // --- Pointer Events ---

  const handlePointerDown = (e: React.PointerEvent) => {
    // Hide context menu on left click
    if (contextMenu) setContextMenu(null);

    const target = e.target as HTMLElement;
    const nodeEl = target.closest('[data-node-id]');
    const handleEl = target.closest('[data-handle-id]');
    dragStart.current = { x: e.clientX, y: e.clientY };
    isDragging.current = true;

    if (handleEl) { 
        dragTarget.current = 'link'; 
        activeId.current = handleEl.getAttribute('data-handle-id'); 
        e.stopPropagation(); 
    } else if (nodeEl) { 
        dragTarget.current = 'node'; 
        activeId.current = nodeEl.getAttribute('data-node-id'); 
        setSelectedId(activeId.current); 
        e.stopPropagation(); 
    } else { 
        dragTarget.current = 'viewport'; 
        setSelectedId(null); 
    }
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isDragging.current) return;
    const dx = e.clientX - dragStart.current.x;
    const dy = e.clientY - dragStart.current.y;

    if (dragTarget.current === 'viewport') { 
        setViewport(prev => ({ ...prev, x: prev.x + dx, y: prev.y + dy })); 
    } else if (dragTarget.current === 'node' && activeId.current) {
        setSteps(prev => prev.map(s => s.id === activeId.current ? { ...s, position: { x: (s.position?.x || 0) + dx / viewport.zoom, y: (s.position?.y || 0) + dy / viewport.zoom } } : s));
    } else if (dragTarget.current === 'link' && activeId.current) {
        const sNode = steps.find(s => s.id === activeId.current);
        if (sNode && sNode.position) {
            const world = screenToWorld(e.clientX, e.clientY);
            // 200/80 should be tokens, but for JS logic keeping consistent with node dimensions
            ghostLink.current = { x1: sNode.position.x + 200, y1: sNode.position.y + 40, x2: world.x, y2: world.y };
            setViewport(v => ({...v})); // Force re-render for ghost link
        }
    }
    dragStart.current = { x: e.clientX, y: e.clientY };
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (dragTarget.current === 'link' && activeId.current) {
      const targetEl = document.elementFromPoint(e.clientX, e.clientY)?.closest('[data-node-id]');
      const tId = targetEl?.getAttribute('data-node-id');

      const sourceId = activeId.current;

      if (tId && sourceId && tId !== sourceId) {
        setLinks(prev => {
            if (prev.some(l => l.sourceId === sourceId && l.targetId === tId)) return prev;
            return [...prev, { id: `link-${Date.now()}`, sourceId, targetId: tId }];
        });
      }
    } else if (dragTarget.current === 'node' && activeId.current) {
       setSteps(prev => prev.map(s => s.id === activeId.current ? { ...s, position: { x: snapToGrid(s.position?.x || 0), y: snapToGrid(s.position?.y || 0) } } : s));
    }

    isDragging.current = false; 
    ghostLink.current = null; 
    activeId.current = null; 
    setViewport(v => ({...v}));
  };

  const selectedStep = useMemo(() => steps.find(s => s.id === selectedId), [selectedId, steps]);
  const updateStep = (updatedStep: ProcessStep) => setSteps(prev => prev.map(s => s.id === updatedStep.id ? updatedStep : s));
  const deleteStep = (id: string) => { 
      setSteps(prev => prev.filter(s => s.id !== id)); 
      setLinks(prev => prev.filter(l => l.sourceId !== id && l.targetId !== id)); 
      setSelectedId(null); 
  };

  return (
    <div className="h-[calc(100vh-100px)] flex flex-col bg-panel border border-default rounded-base shadow-sm overflow-hidden">
      {/* 1. Rigid Toolbar */}
      <div className="h-header bg-subtle border-b border-default flex items-center justify-between px-3 shrink-0">
         <div className="flex items-center gap-3">
            <button onClick={() => setPaletteOpen(!paletteOpen)} className={`p-1 rounded-base hover:bg-white border border-transparent hover:border-subtle ${paletteOpen ? 'text-blue-600' : 'text-secondary'}`}><LayoutPanelLeft size={16}/></button>
            <div className="h-4 w-px bg-default"></div>
            <input className="bg-transparent text-sm font-bold text-primary w-48 outline-none" value={processName} onChange={e => setProcessName(e.target.value)} />
         </div>
         <div className="flex items-center gap-2">
            <input className="h-7 w-64 bg-panel border border-default rounded-base px-2 text-xs" placeholder="Describe workflow for AI generation..." value={aiPrompt} onChange={e => setAiPrompt(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleAiGenerate(e)} disabled={isGenerating}/>
            <button className="p-1 text-secondary hover:text-primary" onClick={() => setViewport(v => ({...v, zoom: v.zoom * 1.1}))}><ZoomIn size={16}/></button>
            <button className="p-1 text-secondary hover:text-primary" onClick={() => setViewport(v => ({...v, zoom: v.zoom / 1.1}))}><ZoomOut size={16}/></button>
            <button className="p-1 text-secondary hover:text-rose-600" onClick={handleClear} title="Clear Canvas"><Trash2 size={16}/></button>
            <div className="h-4 w-px bg-default mx-1"></div>
            <button onClick={handleSimulation} className="flex items-center gap-1 px-3 py-1 bg-indigo-600 text-white rounded-base text-xs hover:bg-indigo-700 shadow-sm"><Cpu size={14}/> Simulate</button>
            <button onClick={handleDeploy} className="flex items-center gap-1 px-3 py-1 bg-brand-slate text-white rounded-base text-xs hover:bg-slate-900 shadow-sm"><Save size={14}/> Save</button>
         </div>
      </div>

      <div className="flex-1 flex overflow-hidden">
        {/* 2. Palette (Standard Sidebar) */}
        {paletteOpen && (
          <div className="w-56 border-r border-default bg-subtle overflow-y-auto">
             <PaletteSidebar onAddNode={addNode} />
          </div>
        )}

        {/* 3. Canvas (Grid) */}
        <div className="flex-1 relative bg-canvas overflow-hidden cursor-grab active:cursor-grabbing designer-grid"
             ref={canvasRef} 
             onPointerDown={handlePointerDown} 
             onPointerMove={handlePointerMove} 
             onPointerUp={handlePointerUp}
             onContextMenu={handleContextMenu}
        >
           <div style={{ transform: `translate(${viewport.x}px, ${viewport.y}px) scale(${viewport.zoom})`, transformOrigin: '0 0' }}>
              {/* SVG Overlay for Links - MUST be pointer-events-none to allow clicking nodes through it */}
              <svg className="overflow-visible absolute top-0 left-0 pointer-events-none" style={{ width: '100%', height: '100%' }}>
                <defs><marker id="arrow" viewBox="0 0 10 10" refX="10" refY="5" markerWidth="6" markerHeight="6" orient="auto"><path d="M 0 0 L 10 5 L 0 10 z" fill="#64748b"/></marker></defs>
                {links.map(l => {
                  const s = steps.find(n => n.id === l.sourceId); 
                  const t = steps.find(n => n.id === l.targetId);
                  if (!s || !t || !s.position || !t.position) return null;

                  // Calculate link coordinates based on node dimensions (200x80)
                  const x1 = s.position.x + 200; 
                  const y1 = s.position.y + 40; 
                  const x2 = t.position.x; 
                  const y2 = t.position.y + 40;

                  return <path key={l.id} d={`M ${x1} ${y1} C ${x1+50} ${y1}, ${x2-50} ${y2}, ${x2} ${y2}`} stroke="#64748b" strokeWidth="2" fill="none" markerEnd="url(#arrow)"/>;
                })}
                {ghostLink.current && <path d={`M ${ghostLink.current.x1} ${ghostLink.current.y1} L ${ghostLink.current.x2} ${ghostLink.current.y2}`} stroke="#94a3b8" strokeWidth="2" strokeDasharray="5,5" fill="none"/>}
              </svg>

              {/* Nodes Layer */}
              {steps.map(step => <NodeComponent key={step.id} step={step} isSelected={selectedId === step.id} />)}
           </div>
        </div>

        {/* 4. Properties (Rigid Right Panel) */}
        {selectedStep && (
          <div className="w-72 border-l border-default bg-panel overflow-y-auto shadow-xl z-20">
             <PropertiesPanel step={selectedStep} onUpdate={updateStep} onDelete={deleteStep} roles={roles} />
          </div>
        )}
      </div>

      {/* Context Menu Overlay */}
      {contextMenu && (
        <CanvasContextMenu 
          position={contextMenu.position} 
          targetId={contextMenu.targetId} 
          onClose={() => setContextMenu(null)}
          onAction={handleMenuAction}
        />
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { ProcessStep, UserRole, IOMapping, RetryPolicy } from '../../types';
import { useBPM } from '../../contexts/BPMContext';
import { 
  Trash2, Compass, X, ExternalLink, 
  Settings, Database, RefreshCw, ArrowRightLeft, 
  Braces, ShieldAlert, Plus, Minimize2, Key, Sparkles, FunctionSquare
} from 'lucide-react';
import { NexFormGroup } from '../shared/NexUI';
import { getStepTypeMetadata } from './designerUtils';

// Mock upstream variables for autocomplete demo
const SUGGESTED_VARS = [
    'request.amount', 'request.requesterId', 'approval.status', 
    'user.email', 'system.date', 'invoice.id', 'fraud.score'
];

export const PropertiesPanel = ({ 
  step, 
  onUpdate, 
  onDelete, 
  roles 
}: { 
  step: ProcessStep | undefined; 
  onUpdate: (step: ProcessStep) => void; 
  onDelete: (id: string) => void; 
  roles: UserRole[]; 
}) => {
    const { rules, navigateTo } = useBPM();
    const [activeTab, setActiveTab] = useState<'config' | 'data' | 'logic' | 'policy'>('config');

    if (!step) {
      return (
        <aside className="hidden md:flex w-full h-full flex-col items-center justify-center text-center p-8 bg-white border-l border-slate-300">
          <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mb-4 border border-slate-200">
            <Compass size={32} strokeWidth={1} className="text-slate-300" />
          </div>
          <h3 className="text-sm font-bold text-slate-800">Inspector</h3>
          <p className="text-xs text-slate-500 mt-2 max-w-[200px]">Select a component to configure properties.</p>
        </aside>
      );
    }

    const meta = getStepTypeMetadata(step.type);

    const updateField = (field: keyof ProcessStep, value: any) => { onUpdate({ ...step, [field]: value }); };
    const updateDataField = (key: string, value: any) => { onUpdate({ ...step, data: { ...step.data, [key]: value } }); };

    // --- Data Mapping Helpers ---
    const addMapping = (type: 'inputs' | 'outputs') => {
        const newMap: IOMapping = { source: '', target: '' };
        onUpdate({ ...step, [type]: [...(step[type] || []), newMap] });
    };

    const updateMapping = (type: 'inputs' | 'outputs', index: number, field: keyof IOMapping, value: string) => {
        const list = [...(step[type] || [])];
        list[index] = { ...list[index], [field]: value };
        onUpdate({ ...step, [type]: list });
    };

    const removeMapping = (type: 'inputs' | 'outputs', index: number) => {
        const list = [...(step[type] || [])];
        list.splice(index, 1);
        onUpdate({ ...step, [type]: list });
    };

    // --- Retry Policy Helpers ---
    const updateRetry = (field: keyof RetryPolicy, value: any) => {
        const current = step.retryPolicy || { enabled: false, maxAttempts: 3, strategy: 'fixed', delayMs: 1000 };
        onUpdate({ ...step, retryPolicy: { ...current, [field]: value } });
    };

    return (
      <aside className="w-full h-full bg-white border-l border-slate-300 flex flex-col shadow-xl z-20">
        {/* Header */}
        <div className="h-10 flex items-center justify-between px-4 border-b border-slate-300 bg-slate-50">
          <div className="flex items-center gap-2">
            <meta.icon size={14} className={meta.color} />
            <h3 className="text-xs font-bold text-slate-800 uppercase tracking-wider">{meta.category}</h3>
            <span className="text-[10px] text-slate-400 font-mono">| {step.type}</span>
          </div>
          <button onClick={() => onUpdate({ ...step, id: step.id } as any)} className="text-slate-400 hover:text-slate-800"><Minimize2 size={14}/></button>
        </div>

        {/* Identity Block (Always Visible) */}
        <div className="p-4 border-b border-slate-100 bg-white">
            <input 
              type="text" 
              className="text-sm font-bold text-slate-900 w-full outline-none border-b border-transparent focus:border-blue-500 placeholder:text-slate-300 transition-all mb-1" 
              value={step.name} 
              onChange={e => updateField('name', e.target.value)}
              placeholder="Step Name"
            />
            <input 
              type="text"
              className="text-xs text-slate-500 w-full outline-none bg-transparent"
              value={step.description || ''}
              onChange={e => updateField('description', e.target.value)}
              placeholder="Add technical description..."
            />
        </div>

        {/* Tabs */}
        <div className="flex border-b border-slate-200 bg-slate-50/50">
            {[
                { id: 'config', icon: Settings, label: 'Config' },
                { id: 'data', icon: Database, label: 'Wiring' },
                { id: 'logic', icon: FunctionSquare, label: 'Rules' },
                { id: 'policy', icon: ShieldAlert, label: 'Policy' }
            ].map(tab => (
                <button 
                    key={tab.id}
                    onClick={() => setActiveTab(tab.id as any)}
                    className={`flex-1 py-2 flex items-center justify-center gap-1.5 text-[10px] font-bold uppercase transition-all border-b-2 ${activeTab === tab.id ? 'border-blue-600 text-blue-600 bg-white' : 'border-transparent text-slate-500 hover:bg-white hover:text-slate-700'}`}
                >
                    <tab.icon size={12}/> {tab.label}
                </button>
            ))}
        </div>

        <div className="flex-1 p-4 overflow-y-auto no-scrollbar bg-slate-50/30">

          {/* TAB: CONFIGURATION (Dynamic based on type) */}
          {activeTab === 'config' && (
             <div className="space-y-4">
                {/* User Task Specifics */}
                {step.type === 'user-task' && (
                    <div className="space-y-4">
                        <NexFormGroup label="Role Assignment">
                            <select className="prop-input" value={step.role || ''} onChange={e => updateField('role', e.target.value)}>
                                <option value="">Unassigned</option>
                                {roles.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
                            </select>
                        </NexFormGroup>
                        <NexFormGroup label="Candidate Groups">
                            <input className="prop-input" placeholder="group1, group2" value={step.data?.candidateGroups || ''} onChange={e => updateDataField('candidateGroups', e.target.value)} />
                        </NexFormGroup>
                        <NexFormGroup label="SLA Deadline">
                            <div className="flex gap-2">
                                <input type="number" className="prop-input w-20" value={step.data?.slaValue || 2} onChange={e => updateDataField('slaValue', e.target.value)} />
                                <select className="prop-input flex-1" value={step.data?.slaUnit || 'Days'} onChange={e => updateDataField('slaUnit', e.target.value)}>
                                    <option>Hours</option><option>Days</option><option>Weeks</option>
                                </select>
                            </div>
                        </NexFormGroup>
                    </div>
                )}

                {/* Gateway Specifics */}
                {meta.category === 'Gateways' && (
                    <div className="space-y-4">
                        <NexFormGroup label="Default Route ID">
                            <input className="prop-input font-mono" placeholder="Flow ID" value={step.data?.defaultFlow || ''} onChange={e => updateDataField('defaultFlow', e.target.value)} />
                        </NexFormGroup>
                        {step.type === 'exclusive-gateway' && (
                            <NexFormGroup label="Condition Expression (CEL)">
                                <textarea className="prop-input h-24 font-mono text-xs" placeholder="amount > 1000 && approved == true" value={step.data?.condition || ''} onChange={e => updateDataField('condition', e.target.value)} />
                            </NexFormGroup>
                        )}
                    </div>
                )}

                {/* Service / Integration Specifics */}
                {(meta.category === 'Data & Integration' || meta.category === 'Cloud Infra' || step.type === 'service-task') && (
                    <div className="space-y-4">
                        <NexFormGroup label="Endpoint / Resource">
                            <input className="prop-input font-mono" placeholder="https://api..." value={step.data?.url || step.data?.arn || ''} onChange={e => updateDataField(step.data?.arn ? 'arn' : 'url', e.target.value)} />
                        </NexFormGroup>
                        <NexFormGroup label="Method / Action">
                            <select className="prop-input" value={step.data?.method || 'POST'} onChange={e => updateDataField('method', e.target.value)}>
                                <option>GET</option><option>POST</option><option>PUT</option><option>DELETE</option>
                            </select>
                        </NexFormGroup>
                        <NexFormGroup label="Auth Header">
                            <div className="flex gap-2">
                                <Key size={16} className="mt-2 text-slate-400"/>
                                <select className="prop-input" value={step.data?.authProfile || ''} onChange={e => updateDataField('authProfile', e.target.value)}>
                                    <option value="">None</option>
                                    <option value="vault-stripe">Stripe Prod</option>
                                    <option value="vault-aws">AWS Main</option>
                                </select>
                            </div>
                        </NexFormGroup>
                    </div>
                )}
             </div>
          )}

          {/* TAB: DATA WIRING (IO Mapping) */}
          {activeTab === 'data' && (
              <div className="space-y-6">
                  {/* Inputs */}
                  <div>
                      <div className="flex items-center justify-between mb-2">
                          <h4 className="text-[10px] font-bold text-slate-500 uppercase flex items-center gap-1"><ArrowRightLeft size={10}/> Input Mapping</h4>
                          <button onClick={() => addMapping('inputs')} className="text-blue-600 hover:text-blue-800"><Plus size={14}/></button>
                      </div>
                      <div className="space-y-2">
                          {(!step.inputs || step.inputs.length === 0) && <div className="text-xs text-slate-400 italic p-2 border border-dashed rounded-sm">No input maps defined.</div>}
                          {step.inputs?.map((map, i) => (
                              <div key={i} className="flex gap-1 items-center">
                                  <div className="relative flex-1">
                                      <input 
                                        className="prop-input font-mono text-[10px] h-7" 
                                        placeholder="Process Var" 
                                        value={map.source} 
                                        list={`vars-${i}`}
                                        onChange={e => updateMapping('inputs', i, 'source', e.target.value)} 
                                      />
                                      <datalist id={`vars-${i}`}>
                                          {SUGGESTED_VARS.map(v => <option key={v} value={v} />)}
                                      </datalist>
                                  </div>
                                  <span className="text-slate-400">â†’</span>
                                  <input className="prop-input font-mono text-[10px] h-7 flex-1" placeholder="Task Param" value={map.target} onChange={e => updateMapping('inputs', i, 'target', e.target.value)} />
                                  <button onClick={() => removeMapping('inputs', i)} className="text-slate-400 hover:text-rose-500"><X size={12}/></button>
                              </div>
                          ))}
                      </div>
                  </div>

                  <div className="h-px bg-slate-200"></div>

                  {/* Outputs */}
                  <div>
                      <div className="flex items-center justify-between mb-2">
                          <h4 className="text-[10px] font-bold text-slate-500 uppercase flex items-center gap-1"><Braces size={10}/> Output Mapping</h4>
                          <button onClick={() => addMapping('outputs')} className="text-blue-600 hover:text-blue-800"><Plus size={14}/></button>
                      </div>
                      <div className="space-y-2">
                          {(!step.outputs || step.outputs.length === 0) && <div className="text-xs text-slate-400 italic p-2 border border-dashed rounded-sm">No output maps defined.</div>}
                          {step.outputs?.map((map, i) => (
                              <div key={i} className="flex gap-1 items-center">
                                  <input className="prop-input font-mono text-[10px] h-7" placeholder="Task Result" value={map.source} onChange={e => updateMapping('outputs', i, 'source', e.target.value)} />
                                  <span className="text-slate-400">â†’</span>
                                  <div className="relative flex-1">
                                      <input 
                                        className="prop-input font-mono text-[10px] h-7" 
                                        placeholder="Process Var" 
                                        value={map.target} 
                                        list={`out-vars-${i}`}
                                        onChange={e => updateMapping('outputs', i, 'target', e.target.value)} 
                                      />
                                      <datalist id={`out-vars-${i}`}>
                                          {SUGGESTED_VARS.map(v => <option key={v} value={v} />)}
                                      </datalist>
                                  </div>
                                  <button onClick={() => removeMapping('outputs', i)} className="text-slate-400 hover:text-rose-500"><X size={12}/></button>
                              </div>
                          ))}
                      </div>
                  </div>
              </div>
          )}

          {/* TAB: LOGIC (Rules & Triggers) */}
          {activeTab === 'logic' && (
              <div className="space-y-4">
                  <NexFormGroup label="Pre-Flight Rule" helpText="Execute business rule before step starts">
                        <select className="prop-input" value={step.businessRuleId || ''} onChange={e => updateField('businessRuleId', e.target.value)}>
                            <option value="">None</option>
                            {rules.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
                        </select>
                        {step.businessRuleId && (
                            <button onClick={() => navigateTo('rules', step.businessRuleId)} className="mt-1 text-[10px] text-blue-600 flex items-center gap-1 hover:underline">
                                Edit Rule <ExternalLink size={10}/>
                            </button>
                        )}
                  </NexFormGroup>

                  <NexFormGroup label="On Entry Script">
                      <div className="relative">
                        <textarea className="prop-input h-20 font-mono text-[10px]" placeholder="console.log('Entering step');" value={step.onEntryAction || ''} onChange={e => updateField('onEntryAction', e.target.value)} />
                        {step.onEntryAction && <Sparkles size={12} className="absolute right-2 bottom-2 text-amber-500 animate-pulse"/>}
                      </div>
                  </NexFormGroup>

                  <NexFormGroup label="On Exit Script">
                      <textarea className="prop-input h-20 font-mono text-[10px]" placeholder="execution.setVariable('status', 'done');" value={step.onExitAction || ''} onChange={e => updateField('onExitAction', e.target.value)} />
                  </NexFormGroup>
              </div>
          )}

          {/* TAB: POLICY (Retry, Timeout) */}
          {activeTab === 'policy' && (
              <div className="space-y-4">
                  <div className="flex items-center justify-between">
                      <h4 className="text-xs font-bold text-slate-700">Retry Policy</h4>
                      <label className="relative inline-flex items-center cursor-pointer">
                        <input type="checkbox" className="sr-only peer" checked={step.retryPolicy?.enabled || false} onChange={e => updateRetry('enabled', e.target.checked)} />
                        <div className="w-9 h-5 bg-slate-200 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-4 after:w-4 after:transition-all peer-checked:bg-blue-600"></div>
                      </label>
                  </div>

                  {step.retryPolicy?.enabled && (
                      <div className="p-3 bg-white border border-slate-200 rounded-sm space-y-3 animate-slide-up">
                          <NexFormGroup label="Strategy">
                              <select className="prop-input" value={step.retryPolicy?.strategy || 'fixed'} onChange={e => updateRetry('strategy', e.target.value)}>
                                  <option value="fixed">Fixed Delay</option>
                                  <option value="exponential">Exponential Backoff</option>
                                  <option value="linear">Linear Backoff</option>
                              </select>
                          </NexFormGroup>
                          <div className="grid grid-cols-2 gap-2">
                              <NexFormGroup label="Max Attempts">
                                  <input type="number" className="prop-input" value={step.retryPolicy?.maxAttempts || 3} onChange={e => updateRetry('maxAttempts', parseInt(e.target.value))} />
                              </NexFormGroup>
                              <NexFormGroup label="Delay (ms)">
                                  <input type="number" className="prop-input" value={step.retryPolicy?.delayMs || 1000} onChange={e => updateRetry('delayMs', parseInt(e.target.value))} />
                              </NexFormGroup>
                          </div>
                      </div>
                  )}

                  <div className="pt-4 border-t border-slate-200">
                      <NexFormGroup label="Loop Characteristics">
                          <label className="flex items-center gap-2 p-2 border border-slate-200 rounded-sm hover:bg-white cursor-pointer">
                              <input type="checkbox" checked={step.isMultiInstance || false} onChange={e => updateField('isMultiInstance', e.target.checked)} className="rounded-sm text-blue-600"/>
                              <div className="flex items-center gap-2">
                                  <RefreshCw size={14} className="text-slate-500"/>
                                  <span className="text-xs text-slate-700 font-medium">Multi-Instance (Parallel)</span>
                              </div>
                          </label>
                      </NexFormGroup>
                  </div>
              </div>
          )}

        </div>

        {/* Footer Actions */}
        <div className="p-4 border-t border-slate-200 bg-slate-50 flex justify-between items-center">
          <button onClick={() => onDelete(step.id)} className="text-rose-600 hover:bg-rose-50 p-2 rounded-sm transition-colors" title="Delete Step">
              <Trash2 size={16}/>
          </button>
          <div className="text-[9px] text-slate-400 font-mono">ID: {step.id}</div>
        </div>
      </aside>
    );
};

import React, { useState, useMemo } from 'react';
import { Task, TaskStatus, TaskPriority } from '../types';
import { useBPM } from '../contexts/BPMContext';
import { 
  Search, CheckSquare, Layers, Clock, AlertCircle, UserPlus, Settings,
  CheckCircle, XCircle, Paperclip, LayoutGrid, List as ListIcon, 
  User, Calendar, Star, PauseCircle, ArrowDown, ArrowUp, X,
