        </div>

        {/* 3. Task List Area */}
        <div className="flex-1 overflow-y-auto bg-panel min-h-0">
            {viewMode === 'list' && (
                <div className="divide-y divide-subtle">
                    {filteredTasks.map(t => (
                        <TaskListItem 
                            key={t.id} 
                            task={t} 
                            isSelected={selectedTask?.id === t.id}
                            isChecked={selectedIds.has(t.id)}
