                            <th className="p-3 cursor-pointer hover:text-blue-600" onClick={() => handleSort('title')}>Title {sortConfig.key === 'title' && (sortConfig.dir === 'asc' ? <ArrowUp size={10} className="inline"/> : <ArrowDown size={10} className="inline"/>)}</th>
