        <div 
          key={n.id} 
          onClick={() => n.deepLink && navigateTo(n.deepLink.view, n.deepLink.id)}
          className={`flex items-center gap-3 p-3 rounded-base border pointer-events-auto animate-slide-up shadow-md cursor-pointer text-sm ${
