};

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { useBPM } from '../contexts/BPMContext';
import { 
  CheckCircle, AlertTriangle, 
  X, Activity, Send, Clock, PlayCircle
} from 'lucide-react';
import { NexButton } from './shared/NexUI';

interface Props {
  instanceId: string;
  onClose: () => void;
}

export const ProcessInstanceViewer: React.FC<Props> = ({ instanceId, onClose }) => {
  const { instances, processes, addInstanceComment } = useBPM();

  const instance = instances.find(i => i.id === instanceId);
  const process = processes.find(p => p.id === instance?.definitionId);

  const [viewport, setViewport] = useState({ x: 0, y: 0, zoom: 1 });
  const [rightPanelTab, setRightPanelTab] = useState<'info' | 'variables' | 'comments'>('info');
  const [showAdminPanel, setShowAdminPanel] = useState(true);
  const [variableJson, setVariableJson] = useState('');
  const [newComment, setNewComment] = useState('');
  const [showMetrics, setShowMetrics] = useState(false);

  const canvasRef = useRef<HTMLDivElement>(null);
  const isDragging = useRef(false);
  const dragStart = useRef({ x: 0, y: 0 });

  useEffect(() => {
    if (instance) setVariableJson(JSON.stringify(instance.variables, null, 2));

    if (process && instance && instance.activeStepIds.length > 0 && canvasRef.current) {
      const activeStep = process.steps.find(s => s.id === instance.activeStepIds[0]);
      if (activeStep?.position) {
        setViewport({
          x: (canvasRef.current.clientWidth / 2) - activeStep.position.x - 90,
          y: (canvasRef.current.clientHeight / 2) - activeStep.position.y - 40,
          zoom: 1
        });
      }
    }
  }, [instanceId, process]);

  // Calculate executed path links
  const executedLinks = useMemo(() => {
      if (!instance || !process) return [];
      // Sort history by time
      const sortedHistory = [...instance.history].sort((a,b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime());

      const takenPaths: Set<string> = new Set();

      // We map step IDs to find links between them.
      // Note: Instance history records step names, we need IDs. In a real app history would save ID.
      // Assuming we can map back via name or we enhanced AuditLog to include ID.
      // For this demo, let's map by name which is brittle but works for mocks.

      const stepIdByName = new Map(process.steps.map(s => [s.name, s.id]));

      // Start node
      const startNode = process.steps.find(s => s.type === 'start');
      let previousStepId = startNode?.id;

      sortedHistory.forEach(h => {
          const currentStepId = stepIdByName.get(h.stepName);
          if (previousStepId && currentStepId) {
              const link = process.links?.find(l => l.sourceId === previousStepId && l.targetId === currentStepId);
              if (link) takenPaths.add(link.id);
              previousStepId = currentStepId;
          }
      });

      return Array.from(takenPaths);
  }, [instance, process]);

  if (!instance || !process) return null;

  const handlePointerDown = (e: React.PointerEvent) => {
    isDragging.current = true;
    dragStart.current = { x: e.clientX, y: e.clientY };
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isDragging.current) return;
    setViewport(prev => ({ ...prev, x: prev.x + (e.clientX - dragStart.current.x), y: prev.y + (e.clientY - dragStart.current.y) }));
    dragStart.current = { x: e.clientX, y: e.clientY };
  };

  const handlePointerUp = () => { isDragging.current = false; };

  // Health Logic
  const isHealthy = instance.status === 'Active' || instance.status === 'Completed';

  const handleAddComment = () => {
      if(!newComment.trim()) return;
      if (addInstanceComment) {
          addInstanceComment(instance.id, newComment);
      }
      setNewComment('');
  };

  return (
    <div className="fixed inset-0 bg-slate-100 z-[100] flex flex-col animate-fade-in overflow-hidden">
      <div className="h-12 bg-white border-b border-slate-300 flex items-center justify-between px-4 z-50 shadow-sm">
        <div className="flex items-center gap-3">
           <button onClick={onClose} className="p-1.5 hover:bg-slate-100 rounded-sm text-slate-500"><X size={18}/></button>
           <div className="h-5 w-px bg-slate-200"></div>
           <div className="flex items-center gap-3">
             <h2 className="font-bold text-slate-800 text-sm tracking-tight">{process.name}</h2>
             <span className={`px-2 py-0.5 rounded-sm text-[10px] font-bold uppercase border ${instance.status === 'Active' ? 'bg-emerald-50 text-emerald-700 border-emerald-200' : 'bg-rose-50 text-rose-700 border-rose-200'}`}>{instance.status}</span>
             <span className="text-[10px] text-slate-400 font-mono">{instance.id}</span>
           </div>
        </div>
        <div className="flex items-center gap-2">
            <label className="flex items-center gap-2 text-xs font-bold text-slate-600 mr-4 cursor-pointer select-none">
                <input type="checkbox" checked={showMetrics} onChange={e => setShowMetrics(e.target.checked)} className="rounded-sm text-blue-600"/>
                Show Metrics
            </label>
            <button onClick={() => setShowAdminPanel(!showAdminPanel)} className={`p-1.5 rounded-sm ${showAdminPanel ? 'bg-slate-200 text-slate-900' : 'text-slate-500 hover:bg-slate-100'}`}><Activity size={18}/></button>
        </div>
      </div>

      <div className="flex-1 flex overflow-hidden relative">
        <div 
          ref={canvasRef}
          className="flex-1 relative bg-[#f0f2f5] touch-none designer-grid"
          onPointerDown={handlePointerDown}
          onPointerMove={handlePointerMove}
          onPointerUp={handlePointerUp}
        >
          <div style={{ transform: `translate(${viewport.x}px, ${viewport.y}px) scale(${viewport.zoom})`, transformOrigin: '0 0' }}>
             <svg className="overflow-visible absolute top-0 left-0 pointer-events-none">
                {process.steps.flatMap(step => (step.nextStepIds || []).map(targetId => {
                  const t = process.steps.find(s => s.id === targetId);
                  const link = process.links?.find(l => l.sourceId === step.id && l.targetId === t?.id);

                  if (!t || !step.position || !t.position) return null;
                  const x1=step.position.x+200; const y1=step.position.y+40;
                  const x2=t.position.x; const y2=t.position.y+40;

                  const isTraversed = link && executedLinks.includes(link.id);

                  return (
                      <g key={`${step.id}-${targetId}`}>
                          {/* Base Line */}
                          <path d={`M ${x1} ${y1} C ${x1+50} ${y1}, ${x2-50} ${y2}, ${x2} ${y2}`} stroke={isTraversed ? "#10b981" : "#cbd5e1"} strokeWidth={isTraversed ? 4 : 2} fill="none" className="transition-all duration-1000 ease-out"/>
                          {/* Animated Dash for Active Paths */}
                          {isTraversed && (
                              <path d={`M ${x1} ${y1} C ${x1+50} ${y1}, ${x2-50} ${y2}, ${x2} ${y2}`} stroke="#ffffff" strokeWidth="2" strokeDasharray="10,10" fill="none" className="animate-[dash_1s_linear_infinite] opacity-30"/>
                          )}
                      </g>
                  );
                }))}
             </svg>

             {process.steps.map(step => {
               const isActive = instance.activeStepIds.includes(step.id);
               const isVisited = instance.history.some(h => h.stepName === step.name); // Proxy check using name

               // Mock Metrics
               const avgDuration = step.metrics?.avgDuration || (Math.floor(Math.random() * 120) + 10);
               const errorRate = step.metrics?.errorRate || Math.floor(Math.random() * 5);

               return (
               <div key={step.id} className={`absolute w-[200px] h-[80px] rounded-sm border flex flex-col p-3 transition-all ${isActive ? 'bg-white border-emerald-500 ring-4 ring-emerald-500/20 z-10' : (isVisited ? 'bg-white border-emerald-200' : 'bg-white border-slate-300 opacity-60')}`} style={{ left: step.position?.x, top: step.position?.y }}>
                  <div className="text-[9px] font-bold uppercase text-slate-400 mb-1 flex justify-between">
                      {step.type}
                      {isActive && <span className="text-emerald-600 animate-pulse flex items-center gap-1"><PlayCircle size={10}/> LIVE</span>}
                  </div>
                  <div className="text-xs font-bold truncate text-slate-800">{step.name}</div>

                  {showMetrics && (
                      <div className="mt-auto pt-2 border-t border-slate-100 flex justify-between text-[9px] font-mono text-slate-500">
                          <span className="flex items-center gap-1" title="Avg Duration"><Clock size={10}/> {avgDuration}m</span>
                          <span className={`flex items-center gap-1 ${errorRate > 2 ? 'text-rose-600' : 'text-slate-500'}`} title="Error Rate"><AlertTriangle size={10}/> {errorRate}%</span>
                      </div>
                  )}
               </div>
             )})}
          </div>
        </div>

        {showAdminPanel && (
          <aside className="w-80 bg-white border-l border-slate-300 flex flex-col shadow-xl z-20">
             <div className="p-3 border-b border-slate-200 bg-slate-50 flex items-center justify-between">
                <h3 className="font-bold text-slate-700 text-xs uppercase tracking-wider">Monitor</h3>
             </div>

             <div className="flex border-b border-slate-200">
                {['info', 'variables', 'comments'].map(tab => (
                  <button key={tab} onClick={() => setRightPanelTab(tab as any)} className={`flex-1 py-2 text-[10px] font-bold uppercase tracking-wider transition-all ${rightPanelTab === tab ? 'bg-white text-blue-600 border-b-2 border-blue-600' : 'bg-slate-50 text-slate-500 hover:bg-white'}`}>{tab}</button>
                ))}
             </div>

             <div className="p-4 flex-1 overflow-y-auto space-y-4">
                {rightPanelTab === 'info' && (
                  <div className="space-y-4">
                     <div className={`p-3 border rounded-sm ${isHealthy ? 'bg-emerald-50 border-emerald-200' : 'bg-rose-50 border-rose-200'}`}>
                        <h4 className={`text-[10px] font-bold uppercase mb-1 ${isHealthy ? 'text-emerald-700' : 'text-rose-700'}`}>Health Check</h4>
                        <div className="flex justify-between items-center">
                           <span className={`text-xl font-black ${isHealthy ? 'text-emerald-900' : 'text-rose-900'}`}>{isHealthy ? 'Optimal' : 'Attention'}</span>
                           {isHealthy ? <CheckCircle size={20} className="text-emerald-500"/> : <AlertTriangle size={20} className="text-rose-500"/>}
                        </div>
                     </div>

                     <div className="space-y-3">
                        <h4 className="text-[10px] font-bold text-slate-400 uppercase border-b border-slate-100 pb-1">Audit Trail</h4>
                        {instance.history.map((h, i) => (
                          <div key={i} className="flex gap-3 items-start p-2 hover:bg-slate-50 rounded-sm transition-colors border border-transparent hover:border-slate-100 cursor-pointer">
                             <div className="w-6 h-6 rounded-sm bg-slate-200 flex items-center justify-center font-bold text-[10px] shrink-0 text-slate-600">{h.performer[0]}</div>
                             <div>
                                <div className="text-xs font-bold text-slate-800">{h.stepName}</div>
                                <div className="text-[10px] text-slate-500">{h.action}</div>
                                <div className="text-[9px] text-slate-400 font-mono mt-0.5">{new Date(h.timestamp).toLocaleTimeString()}</div>
                             </div>
                          </div>
                        ))}
                     </div>
                  </div>
                )}

                {rightPanelTab === 'variables' && (
                  <textarea 
                     className="w-full h-full min-h-[400px] bg-slate-50 text-slate-700 p-3 rounded-sm font-mono text-xs border border-slate-200 outline-none focus:border-blue-400 resize-none"
                     value={variableJson}
                     onChange={e => setVariableJson(e.target.value)}
                  />
                )}

                {rightPanelTab === 'comments' && (
                    <div className="flex flex-col h-full">
                        <div className="flex-1 space-y-4 mb-4">
                            {(!instance.comments || instance.comments.length === 0) && (
                                <div className="text-center py-8 text-slate-400 italic text-xs">No comments recorded.</div>
                            )}
                            {(instance.comments || []).map((c, i) => (
                                <div key={i} className="bg-slate-50 p-2 rounded-sm border border-slate-200">
                                    <div className="flex justify-between items-center mb-1">
                                        <span className="text-[10px] font-bold text-slate-700">{c.userName}</span>
                                        <span className="text-[9px] text-slate-400">{new Date(c.timestamp).toLocaleTimeString()}</span>
                                    </div>
                                    <p className="text-xs text-slate-600">{c.text}</p>
                                </div>
                            ))}
                        </div>
                        <div className="pt-2 border-t border-slate-200 flex gap-2">
                            <input 
                                className="prop-input" 
                                placeholder="Add note..." 
                                value={newComment} 
                                onChange={e => setNewComment(e.target.value)} 
                                onKeyDown={e => e.key === 'Enter' && handleAddComment()}
                            />
                            <NexButton size="sm" icon={Send} onClick={handleAddComment}>Post</NexButton>
                        </div>
                    </div>
                )}
             </div>
          </aside>
        )}
      </div>
      <style>{`
        @keyframes dash {
          to {
            stroke-dashoffset: -20;
          }
        }
      `}</style>
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { ProcessStep, BusinessRule, Task } from '../types';

const getClient = () => {
  if (!process.env.API_KEY) return null;
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

export interface SimulationResult {
  agentName: string;
  persona: string;
  sentiment: 'positive' | 'critical' | 'neutral';
  score: number;
  critique: string;
  recommendations: string[];
}

export const generateProcessWorkflow = async (prompt: string): Promise<ProcessStep[]> => {
  const ai = getClient();
  const fallback: ProcessStep[] = [
    { id: 'start', name: 'Start', type: 'start', description: 'Process Started', position: { x: 50, y: 100 } },
    { id: 'task1', name: 'Initial Review', type: 'user-task', role: 'manager', description: 'Manual verification', position: { x: 300, y: 100 } },
    { id: 'end', name: 'End', type: 'end', description: 'Process Ended', position: { x: 600, y: 100 } }
  ];

  if (!ai) return fallback;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `Design an enterprise BPMN workflow for: "${prompt}". Return as JSON array of steps. Include roles, logic-heavy descriptions, and grid-snapped positions.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.STRING },
              name: { type: Type.STRING },
              type: { type: Type.STRING, enum: ['start', 'user-task', 'service-task', 'decision', 'end'] },
              description: { type: Type.STRING },
              role: { type: Type.STRING },
              position: {
                type: Type.OBJECT,
                properties: {
                  x: { type: Type.NUMBER },
                  y: { type: Type.NUMBER }
                }
              }
            },
            required: ["id", "name", "type", "description", "position"]
          }
        }
      }
    });

    if (response.text) {
      return JSON.parse(response.text) as ProcessStep[];
    }
    return fallback;
  } catch (error) {
    console.error("Workflow Generation Error:", error);
    return fallback;
  }
};

export const runWorkflowSimulation = async (steps: ProcessStep[]): Promise<SimulationResult[]> => {
  const ai = getClient();
  if (!ai) return [];

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `Perform a "Murder Board" simulation on this BPMN workflow: ${JSON.stringify(steps)}. 
      Simulate 3 agents: 1. Chronos (Efficiency Architect), 2. Draco (Risk Skeptic), 3. Veda (Compliance Auditor). 
      Each must give a score (0-100), a detailed critique, and 2 actionable recommendations.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              agentName: { type: Type.STRING },
              persona: { type: Type.STRING },
              sentiment: { type: Type.STRING, enum: ['positive', 'critical', 'neutral'] },
              score: { type: Type.NUMBER },
              critique: { type: Type.STRING },
              recommendations: {
                type: Type.ARRAY,
                items: { type: Type.STRING }
              }
            },
            required: ["agentName", "persona", "sentiment", "score", "critique", "recommendations"]
          }
        }
      }
    });

    if (response.text) {
      return JSON.parse(response.text) as SimulationResult[];
    }
    return [];
  } catch (error) {
    console.error("Simulation Error:", error);
    return [];
  }
};

export const getProcessInsights = async (processData: any): Promise<string> => {
  const ai = getClient();
  if (!ai) return "AI Insights unavailable. Ensure API key is configured.";

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Analyze this BPM workflow for bottlenecks or inefficiencies: ${JSON.stringify(processData)}. Provide 3 actionable executive bullets.`,
      config: {
        thinkingConfig: { thinkingBudget: 0 }
      }
    });
    return response.text || "Operational analysis complete. No critical bottlenecks detected.";
  } catch (error) {
    return "Analyzing workflow topology... focus on parallel gateway synchronization.";
  }
};

export const generateRuleFromText = async (prompt: string): Promise<Partial<BusinessRule>> => {
  const ai = getClient();
  if (!ai) throw new Error("AI not configured");

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Translate this natural language business rule into a structured JSON object compatible with a rules engine.
    User Input: "${prompt}"

    Structure:
    - Conditions: nested groups (AND/OR). Operators: eq, neq, gt, lt, contains.
    - Action: SET_VARIABLE, ROUTE_TO, or SEND_NOTIFICATION.

    Example Output:
    {
      "name": "High Value Invoice",
      "description": "Auto-route high value invoices to CFO",
      "conditions": { "id": "g1", "type": "AND", "children": [{ "id": "c1", "fact": "amount", "operator": "gt", "value": 50000 }] },
      "action": { "type": "ROUTE_TO", "params": { "role": "CFO" } },
      "priority": 1
    }`,
    config: {
      responseMimeType: "application/json"
    }
  });

  return JSON.parse(response.text || '{}');
};

export const explainRuleLogic = async (rule: BusinessRule): Promise<string> => {
  const ai = getClient();
  if (!ai) return "Logic explanation unavailable.";

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Explain this business rule logic in one clear, professional sentence for a non-technical manager: ${JSON.stringify(rule)}`
  });

  return response.text || "Logic evaluation pending.";
};

export const summarizeTaskContext = async (task: Task): Promise<{ summary: string; sentiment: string; nextAction: string }> => {
  const ai = getClient();
  if (!ai) return { 
    summary: "AI summarization unavailable.", 
    sentiment: "Neutral", 
    nextAction: "Review details manually." 
  };

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Analyze this enterprise task context.
      Task: ${JSON.stringify(task)}

      Return a JSON object with:
      1. summary: A concise 2-sentence executive summary of the task and its history.
      2. sentiment: The overall sentiment of the comments (Positive, Neutral, Negative, Urgent).
      3. nextAction: The recommended next action for the user (e.g., "Approve immediately", "Request more info").`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING },
            sentiment: { type: Type.STRING },
            nextAction: { type: Type.STRING }
          }
        }
      }
    });

    if (response.text) {
      return JSON.parse(response.text);
    }
    return { summary: "Analysis failed.", sentiment: "Neutral", nextAction: "Review" };
  } catch (e) {
    return { summary: "Analysis failed.", sentiment: "Neutral", nextAction: "Review" };
  }
};

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { useBPM } from '../contexts/BPMContext';
import { 
  CheckCircle, AlertTriangle, 
  X, Activity, Send, Clock, PlayCircle, Rewind, FastForward, Pause, Play, History
} from 'lucide-react';
import { NexButton } from './shared/NexUI';

interface Props {
  instanceId: string;
  onClose: () => void;
}

export const ProcessInstanceViewer: React.FC<Props> = ({ instanceId, onClose }) => {
  const { instances, processes, addInstanceComment } = useBPM();

  const instance = instances.find(i => i.id === instanceId);
  const process = processes.find(p => p.id === instance?.definitionId);

  const [viewport, setViewport] = useState({ x: 0, y: 0, zoom: 1 });
  const [rightPanelTab, setRightPanelTab] = useState<'info' | 'variables' | 'comments'>('info');
  const [showAdminPanel, setShowAdminPanel] = useState(true);
  const [variableJson, setVariableJson] = useState('');
  const [newComment, setNewComment] = useState('');
  const [showMetrics, setShowMetrics] = useState(false);

  // Time Travel State
  const [playbackIndex, setPlaybackIndex] = useState<number>(-1); // -1 means live/latest
  const [isPlaying, setIsPlaying] = useState(false);

  const canvasRef = useRef<HTMLDivElement>(null);
  const isDragging = useRef(false);
  const dragStart = useRef({ x: 0, y: 0 });

  useEffect(() => {
    if (instance) {
        setVariableJson(JSON.stringify(instance.variables, null, 2));
        // Reset playback when instance loads
        setPlaybackIndex(instance.history.length - 1);
    }

    if (process && instance && instance.activeStepIds.length > 0 && canvasRef.current) {
      const activeStep = process.steps.find(s => s.id === instance.activeStepIds[0]);
      if (activeStep?.position) {
        setViewport({
          x: (canvasRef.current.clientWidth / 2) - activeStep.position.x - 90,
          y: (canvasRef.current.clientHeight / 2) - activeStep.position.y - 40,
          zoom: 1
        });
      }
    }
  }, [instanceId, process]);

  // Playback Loop
  useEffect(() => {
      let interval: any;
      if (isPlaying && instance) {
          interval = setInterval(() => {
              setPlaybackIndex(prev => {
                  if (prev >= instance.history.length - 1) {
                      setIsPlaying(false);
                      return prev;
                  }
                  return prev + 1;
              });
          }, 1000);
      }
      return () => clearInterval(interval);
  }, [isPlaying, instance]);

  // Derived State for Time Travel
  const currentHistoryItem = instance && playbackIndex >= 0 && playbackIndex < instance.history.length 
      ? instance.history[playbackIndex] 
      : null;

  // Calculate executed path links UP TO the playback index
  const executedLinks = useMemo(() => {
      if (!instance || !process) return [];

      const sortedHistory = [...instance.history].sort((a,b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime());

      // Filter history based on playback
      const visibleHistory = playbackIndex === -1 ? sortedHistory : sortedHistory.slice(0, playbackIndex + 1);

      const takenPaths: Set<string> = new Set();
      const stepIdByName = new Map(process.steps.map(s => [s.name, s.id]));

      const startNode = process.steps.find(s => s.type === 'start');
      let previousStepId = startNode?.id;

      visibleHistory.forEach(h => {
          const currentStepId = stepIdByName.get(h.stepName);
          if (previousStepId && currentStepId) {
              const link = process.links?.find(l => l.sourceId === previousStepId && l.targetId === currentStepId);
              if (link) takenPaths.add(link.id);
              previousStepId = currentStepId;
          }
      });

      return Array.from(takenPaths);
  }, [instance, process, playbackIndex]);

  // Determine Active Steps based on Playback
  // If playing back, the "active" step is the one in the current history item
  const displayActiveStepIds = useMemo(() => {
      if (!instance || !process) return [];
      if (playbackIndex === -1 || playbackIndex === instance.history.length - 1) return instance.activeStepIds;

      // Find the step ID corresponding to the current history item
      if (currentHistoryItem) {
          const step = process.steps.find(s => s.name === currentHistoryItem.stepName);
          return step ? [step.id] : [];
      }
      return [];
  }, [instance, process, playbackIndex, currentHistoryItem]);


  if (!instance || !process) return null;

  const handlePointerDown = (e: React.PointerEvent) => {
    isDragging.current = true;
    dragStart.current = { x: e.clientX, y: e.clientY };
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isDragging.current) return;
    setViewport(prev => ({ ...prev, x: prev.x + (e.clientX - dragStart.current.x), y: prev.y + (e.clientY - dragStart.current.y) }));
    dragStart.current = { x: e.clientX, y: e.clientY };
  };

  const handlePointerUp = () => { isDragging.current = false; };

  // Health Logic
  const isHealthy = instance.status === 'Active' || instance.status === 'Completed';

  const handleAddComment = () => {
      if(!newComment.trim()) return;
      if (addInstanceComment) {
          addInstanceComment(instance.id, newComment);
      }
      setNewComment('');
  };

  return (
    <div className="fixed inset-0 bg-slate-100 z-[100] flex flex-col animate-fade-in overflow-hidden">
      <div className="h-12 bg-white border-b border-slate-300 flex items-center justify-between px-4 z-50 shadow-sm">
        <div className="flex items-center gap-3">
           <button onClick={onClose} className="p-1.5 hover:bg-slate-100 rounded-sm text-slate-500"><X size={18}/></button>
           <div className="h-5 w-px bg-slate-200"></div>
           <div className="flex items-center gap-3">
             <h2 className="font-bold text-slate-800 text-sm tracking-tight">{process.name}</h2>
             <span className={`px-2 py-0.5 rounded-sm text-[10px] font-bold uppercase border ${instance.status === 'Active' ? 'bg-emerald-50 text-emerald-700 border-emerald-200' : 'bg-rose-50 text-rose-700 border-rose-200'}`}>{instance.status}</span>
             <span className="text-[10px] text-slate-400 font-mono">{instance.id}</span>
           </div>
        </div>
        <div className="flex items-center gap-2">
            <label className="flex items-center gap-2 text-xs font-bold text-slate-600 mr-4 cursor-pointer select-none">
                <input type="checkbox" checked={showMetrics} onChange={e => setShowMetrics(e.target.checked)} className="rounded-sm text-blue-600"/>
                Show Metrics
            </label>
            <button onClick={() => setShowAdminPanel(!showAdminPanel)} className={`p-1.5 rounded-sm ${showAdminPanel ? 'bg-slate-200 text-slate-900' : 'text-slate-500 hover:bg-slate-100'}`}><Activity size={18}/></button>
        </div>
      </div>

      <div className="flex-1 flex overflow-hidden relative">
        <div 
          ref={canvasRef}
          className="flex-1 relative bg-[#f0f2f5] touch-none designer-grid"
          onPointerDown={handlePointerDown}
          onPointerMove={handlePointerMove}
          onPointerUp={handlePointerUp}
        >
          <div style={{ transform: `translate(${viewport.x}px, ${viewport.y}px) scale(${viewport.zoom})`, transformOrigin: '0 0' }}>
             <svg className="overflow-visible absolute top-0 left-0 pointer-events-none">
                {process.steps.flatMap(step => (step.nextStepIds || []).map(targetId => {
                  const t = process.steps.find(s => s.id === targetId);
                  const link = process.links?.find(l => l.sourceId === step.id && l.targetId === t?.id);

                  if (!t || !step.position || !t.position) return null;
                  const x1=step.position.x+200; const y1=step.position.y+40;
                  const x2=t.position.x; const y2=t.position.y+40;

                  const isTraversed = link && executedLinks.includes(link.id);

                  return (
                      <g key={`${step.id}-${targetId}`}>
                          {/* Base Line */}
                          <path d={`M ${x1} ${y1} C ${x1+50} ${y1}, ${x2-50} ${y2}, ${x2} ${y2}`} stroke={isTraversed ? "#10b981" : "#cbd5e1"} strokeWidth={isTraversed ? 4 : 2} fill="none" className="transition-all duration-1000 ease-out"/>
                          {/* Animated Dash for Active Paths */}
                          {isTraversed && (
                              <path d={`M ${x1} ${y1} C ${x1+50} ${y1}, ${x2-50} ${y2}, ${x2} ${y2}`} stroke="#ffffff" strokeWidth="2" strokeDasharray="10,10" fill="none" className="animate-[dash_1s_linear_infinite] opacity-30"/>
                          )}
                      </g>
                  );
                }))}
             </svg>

             {process.steps.map(step => {
               const isActive = displayActiveStepIds.includes(step.id);
               // Visited if in history UP TO playback index
               const isVisited = instance.history.slice(0, playbackIndex + 1).some(h => h.stepName === step.name);

               // Mock Metrics
               const avgDuration = step.metrics?.avgDuration || (Math.floor(Math.random() * 120) + 10);
               const errorRate = step.metrics?.errorRate || Math.floor(Math.random() * 5);

               return (
               <div key={step.id} className={`absolute w-[200px] h-[80px] rounded-sm border flex flex-col p-3 transition-all ${isActive ? 'bg-white border-emerald-500 ring-4 ring-emerald-500/20 z-10 shadow-lg scale-105' : (isVisited ? 'bg-white border-emerald-200' : 'bg-white border-slate-300 opacity-60')}`} style={{ left: step.position?.x, top: step.position?.y }}>
                  <div className="text-[9px] font-bold uppercase text-slate-400 mb-1 flex justify-between">
                      {step.type}
                      {isActive && <span className="text-emerald-600 animate-pulse flex items-center gap-1"><PlayCircle size={10}/> LIVE</span>}
                  </div>
                  <div className="text-xs font-bold truncate text-slate-800">{step.name}</div>

                  {showMetrics && (
                      <div className="mt-auto pt-2 border-t border-slate-100 flex justify-between text-[9px] font-mono text-slate-500">
                          <span className="flex items-center gap-1" title="Avg Duration"><Clock size={10}/> {avgDuration}m</span>
                          <span className={`flex items-center gap-1 ${errorRate > 2 ? 'text-rose-600' : 'text-slate-500'}`} title="Error Rate"><AlertTriangle size={10}/> {errorRate}%</span>
                      </div>
                  )}
               </div>
             )})}
          </div>
        </div>

        {/* Time Travel Controls (Bottom Overlay) */}
        <div className="absolute bottom-6 left-6 right-6 lg:right-96 bg-white/90 backdrop-blur border border-slate-200 rounded-sm p-4 shadow-xl z-40 flex flex-col gap-2 animate-slide-up">
            <div className="flex items-center justify-between text-xs font-bold text-slate-600 uppercase tracking-wider">
                <span className="flex items-center gap-2"><History size={14}/> Time Travel Debugger</span>
                <span>{currentHistoryItem ? new Date(currentHistoryItem.timestamp).toLocaleString() : 'Live'}</span>
            </div>
            <div className="flex items-center gap-4">
                <button onClick={() => setIsPlaying(!isPlaying)} className={`p-2 rounded-full text-white transition-all ${isPlaying ? 'bg-amber-500 hover:bg-amber-600' : 'bg-blue-600 hover:bg-blue-700'}`}>
                    {isPlaying ? <Pause size={16}/> : <Play size={16}/>}
                </button>
                <div className="flex-1 relative h-8 flex items-center">
                    <div className="absolute left-0 right-0 h-1.5 bg-slate-200 rounded-full"></div>
                    <div className="absolute left-0 h-1.5 bg-blue-500 rounded-full transition-all duration-300" style={{ width: `${((playbackIndex + 1) / instance.history.length) * 100}%` }}></div>
                    <input 
                        type="range" 
                        min={-1} 
                        max={instance.history.length - 1} 
                        value={playbackIndex} 
                        onChange={(e) => { setPlaybackIndex(parseInt(e.target.value)); setIsPlaying(false); }}
                        className="absolute inset-0 w-full opacity-0 cursor-pointer"
                    />
                    {instance.history.map((h, i) => (
                        <div key={i} className="absolute w-2 h-2 rounded-full bg-white border-2 border-slate-300 top-1/2 -translate-y-1/2 pointer-events-none" style={{ left: `${((i + 1) / instance.history.length) * 100}%`, transform: 'translateX(-50%) translateY(-50%)' }} title={h.stepName}></div>
                    ))}
                </div>
                <button onClick={() => setPlaybackIndex(-1)} className="p-2 text-slate-500 hover:text-blue-600" title="Jump to Live"><FastForward size={16}/></button>
            </div>
            <div className="text-center text-[10px] text-slate-400 font-mono">
                {currentHistoryItem ? `Step ${playbackIndex + 1}/${instance.history.length}: ${currentHistoryItem.action} @ ${currentHistoryItem.stepName}` : 'Viewing Latest State'}
            </div>
        </div>

        {showAdminPanel && (
          <aside className="w-80 bg-white border-l border-slate-300 flex flex-col shadow-xl z-20">
             <div className="p-3 border-b border-slate-200 bg-slate-50 flex items-center justify-between">
                <h3 className="font-bold text-slate-700 text-xs uppercase tracking-wider">Monitor</h3>
             </div>

             <div className="flex border-b border-slate-200">
                {['info', 'variables', 'comments'].map(tab => (
                  <button key={tab} onClick={() => setRightPanelTab(tab as any)} className={`flex-1 py-2 text-[10px] font-bold uppercase tracking-wider transition-all ${rightPanelTab === tab ? 'bg-white text-blue-600 border-b-2 border-blue-600' : 'bg-slate-50 text-slate-500 hover:bg-white'}`}>{tab}</button>
                ))}
             </div>

             <div className="p-4 flex-1 overflow-y-auto space-y-4">
                {rightPanelTab === 'info' && (
                  <div className="space-y-4">
                     <div className={`p-3 border rounded-sm ${isHealthy ? 'bg-emerald-50 border-emerald-200' : 'bg-rose-50 border-rose-200'}`}>
                        <h4 className={`text-[10px] font-bold uppercase mb-1 ${isHealthy ? 'text-emerald-700' : 'text-rose-700'}`}>Health Check</h4>
                        <div className="flex justify-between items-center">
                           <span className={`text-xl font-black ${isHealthy ? 'text-emerald-900' : 'text-rose-900'}`}>{isHealthy ? 'Optimal' : 'Attention'}</span>
                           {isHealthy ? <CheckCircle size={20} className="text-emerald-500"/> : <AlertTriangle size={20} className="text-rose-500"/>}
                        </div>
                     </div>

                     <div className="space-y-3">
                        <h4 className="text-[10px] font-bold text-slate-400 uppercase border-b border-slate-100 pb-1">Audit Trail</h4>
                        {instance.history.map((h, i) => (
                          <div 
                            key={i} 
                            onClick={() => { setPlaybackIndex(i); setIsPlaying(false); }}
                            className={`flex gap-3 items-start p-2 rounded-sm transition-colors border cursor-pointer ${playbackIndex === i ? 'bg-blue-50 border-blue-200' : 'hover:bg-slate-50 border-transparent hover:border-slate-100'}`}
                          >
                             <div className="w-6 h-6 rounded-sm bg-slate-200 flex items-center justify-center font-bold text-[10px] shrink-0 text-slate-600">{h.performer[0]}</div>
                             <div>
                                <div className="text-xs font-bold text-slate-800">{h.stepName}</div>
                                <div className="text-[10px] text-slate-500">{h.action}</div>
                                <div className="text-[9px] text-slate-400 font-mono mt-0.5">{new Date(h.timestamp).toLocaleTimeString()}</div>
                             </div>
                          </div>
                        ))}
                     </div>
                  </div>
                )}

                {rightPanelTab === 'variables' && (
                  <textarea 
                     className="w-full h-full min-h-[400px] bg-slate-50 text-slate-700 p-3 rounded-sm font-mono text-xs border border-slate-200 outline-none focus:border-blue-400 resize-none"
                     value={variableJson}
                     onChange={e => setVariableJson(e.target.value)}
                  />
                )}

                {rightPanelTab === 'comments' && (
                    <div className="flex flex-col h-full">
                        <div className="flex-1 space-y-4 mb-4">
                            {(!instance.comments || instance.comments.length === 0) && (
                                <div className="text-center py-8 text-slate-400 italic text-xs">No comments recorded.</div>
                            )}
                            {(instance.comments || []).map((c, i) => (
                                <div key={i} className="bg-slate-50 p-2 rounded-sm border border-slate-200">
                                    <div className="flex justify-between items-center mb-1">
                                        <span className="text-[10px] font-bold text-slate-700">{c.userName}</span>
                                        <span className="text-[9px] text-slate-400">{new Date(c.timestamp).toLocaleTimeString()}</span>
                                    </div>
                                    <p className="text-xs text-slate-600">{c.text}</p>
                                </div>
                            ))}
                        </div>
                        <div className="pt-2 border-t border-slate-200 flex gap-2">
                            <input 
                                className="prop-input" 
                                placeholder="Add note..." 
                                value={newComment} 
                                onChange={e => setNewComment(e.target.value)} 
                                onKeyDown={e => e.key === 'Enter' && handleAddComment()}
                            />
                            <NexButton size="sm" icon={Send} onClick={handleAddComment}>Post</NexButton>
                        </div>
                    </div>
                )}
             </div>
          </aside>
        )}
      </div>
      <style>{`
        @keyframes dash {
          to {
            stroke-dashoffset: -20;
          }
        }
      `}</style>
    </div>
  );
};

import React, { useState, useRef, useMemo, useEffect } from 'react';
import { ProcessStep, ProcessLink, ProcessStepType } from '../types';
import { useBPM } from '../contexts/BPMContext';
import { 
  Save, ZoomIn, ZoomOut, Sparkles, Cpu, LayoutPanelLeft, Trash2, Thermometer
} from 'lucide-react';
import { PaletteSidebar } from './designer/PaletteSidebar';
import { NodeComponent } from './designer/NodeComponent';
import { PropertiesPanel } from './designer/PropertiesPanel';
import { CanvasContextMenu } from './designer/CanvasContextMenu'; // Imported
import { getStepTypeMetadata } from './designer/designerUtils';
import { generateProcessWorkflow } from '../services/geminiService';

const GRID_SIZE = 20;

export const ProcessDesigner: React.FC = () => {
  const { deployProcess, roles, addNotification, designerDraft, setDesignerDraft, navigateTo } = useBPM();
  const [processName, setProcessName] = useState('Strategic Workflow');
  const [steps, setSteps] = useState<ProcessStep[]>([]);
  const [links, setLinks] = useState<ProcessLink[]>([]);
  const [viewport, setViewport] = useState({ x: 50, y: 50, zoom: 1 });
  const [selectedId, setSelectedId] = useState<string | null>(null);

  // Context Menu & Clipboard State
  const [contextMenu, setContextMenu] = useState<{ position: { x: number; y: number }, targetId: string | null } | null>(null);
  const [clipboard, setClipboard] = useState<ProcessStep | null>(null);

  // AI & Heatmap States
  const [aiPrompt, setAiPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [showHeatmap, setShowHeatmap] = useState(false);

  const [paletteOpen, setPaletteOpen] = useState(true);

  const canvasRef = useRef<HTMLDivElement>(null);
  const isDragging = useRef(false);
  const dragStart = useRef({ x: 0, y: 0 });
  const dragTarget = useRef<'viewport' | 'node' | 'link'>('viewport');
  const activeId = useRef<string | null>(null);
  const ghostLink = useRef<{x1: number, y1: number, x2: number, y2: number} | null>(null);

  // Restore state from context if available
  useEffect(() => {
    if (designerDraft) {
        setSteps(designerDraft.steps);
        setLinks(designerDraft.links);
    }
  }, []);

  // Persist state to context on change
  useEffect(() => {
    setDesignerDraft({ steps, links });
  }, [steps, links, setDesignerDraft]);

  const snapToGrid = (val: number) => Math.round(val / GRID_SIZE) * GRID_SIZE;

  const screenToWorld = (sx: number, sy: number) => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const rect = canvasRef.current.getBoundingClientRect();
    return { 
      x: (sx - rect.left - viewport.x) / viewport.zoom, 
      y: (sy - rect.top - viewport.y) / viewport.zoom 
    };
  };

  // --- Actions ---

  const handleDeploy = async () => {
    const connectedSteps = steps.map(step => {
        const outgoingLinks = links.filter(l => l.sourceId === step.id);
        return {
            ...step,
            nextStepIds: outgoingLinks.map(l => l.targetId)
        };
    });

    await deployProcess({ 
        name: processName, 
        steps: connectedSteps, 
        links, 
        isActive: true, 
        version: 1 
    });
    addNotification('success', 'Process definition deployed successfully.');
  };

  const handleClear = () => {
    if(window.confirm('Clear current design?')) {
        setSteps([]);
        setLinks([]);
        setSelectedId(null);
    }
  };

  const handleAiGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!aiPrompt.trim()) return;
    setIsGenerating(true);
    try {
      const generatedSteps = await generateProcessWorkflow(aiPrompt);
      if (generatedSteps && generatedSteps.length > 0) {
        setSteps(generatedSteps);
        const newLinks: ProcessLink[] = [];
        for(let i=0; i < generatedSteps.length - 1; i++) {
          newLinks.push({ id: `link-auto-${i}`, sourceId: generatedSteps[i].id, targetId: generatedSteps[i+1].id });
        }
        setLinks(newLinks);
        addNotification('success', 'Model synthesized.');
        setAiPrompt('');
      }
    } catch (err) { addNotification('error', 'Generation failure.'); } finally { setIsGenerating(false); }
  };

  const handleSimulation = async () => {
    if (steps.length === 0) {
      addNotification('error', 'Canvas is empty. Add steps to simulate.');
      return;
    }
    navigateTo('simulation-report');
  };

  const addNode = (type: ProcessStepType, position?: { x: number, y: number }) => {
    const world = position || screenToWorld(window.innerWidth / 2, window.innerHeight / 2);
    const metadata = getStepTypeMetadata(type);
    const newNode: ProcessStep = {
      id: `node-${Date.now()}`, name: metadata.defaultName, type, description: '',
      position: { x: snapToGrid(world.x - (position ? 0 : 100)), y: snapToGrid(world.y - (position ? 0 : 40)) },
      requiredSkills: metadata.defaultSkills || [], data: {}
    };
    setSteps(prev => [...prev, newNode]);
    setSelectedId(newNode.id);
  };

  // --- Context Menu Handlers ---

  const handleContextMenu = (e: React.MouseEvent) => {
    e.preventDefault();
    const target = e.target as HTMLElement;
    const nodeEl = target.closest('[data-node-id]');
    const targetId = nodeEl ? nodeEl.getAttribute('data-node-id') : null;

    // Select the node immediately if right-clicked
    if (targetId) setSelectedId(targetId);

    setContextMenu({
      position: { x: e.clientX, y: e.clientY },
      targetId
    });
  };

  const handleMenuAction = (action: string, payload?: any) => {
    if (!contextMenu) return;
    const { targetId, position } = contextMenu;

    switch (action) {
      case 'delete':
        if (targetId) deleteStep(targetId);
        break;

      case 'duplicate':
        if (targetId) {
          const original = steps.find(s => s.id === targetId);
          if (original) {
            const newNode = {
              ...original,
              id: `node-${Date.now()}`,
              name: `${original.name} (Copy)`,
              position: { x: (original.position?.x || 0) + 20, y: (original.position?.y || 0) + 20 }
            };
            setSteps(prev => [...prev, newNode]);
            setSelectedId(newNode.id);
          }
        }
        break;

      case 'copy':
        if (targetId) {
          const node = steps.find(s => s.id === targetId);
          if (node) {
            setClipboard(node);
            addNotification('info', 'Copied to clipboard');
          }
        }
        break;

      case 'paste':
        if (clipboard) {
          const world = screenToWorld(position.x, position.y);
          const newNode = {
            ...clipboard,
            id: `node-${Date.now()}`,
            name: clipboard.name, 
            position: { x: snapToGrid(world.x), y: snapToGrid(world.y) }
          };
          setSteps(prev => [...prev, newNode]);
          setSelectedId(newNode.id);
          addNotification('success', 'Pasted component');
        } else {
          addNotification('info', 'Clipboard is empty');
        }
        break;

      case 'disconnect':
        if (targetId) {
          setLinks(prev => prev.filter(l => l.sourceId !== targetId && l.targetId !== targetId));
          addNotification('info', 'Links removed.');
        }
        break;

      case 'edit':
        // Already selected by context menu open logic, panel is open
        break;

      case 'add-node':
        // Calculate world coordinates for the click position
        const world = screenToWorld(position.x, position.y);
        addNode(payload, { x: world.x, y: world.y });
        break;

      case 'reset-view':
        setViewport({ x: 50, y: 50, zoom: 1 });
        break;

      case 'clear-canvas':
        handleClear();
        break;
    }
    setContextMenu(null);
  };

  // --- Pointer Events ---

  const handlePointerDown = (e: React.PointerEvent) => {
    // Hide context menu on left click
    if (contextMenu) setContextMenu(null);

    const target = e.target as HTMLElement;
    const nodeEl = target.closest('[data-node-id]');
    const handleEl = target.closest('[data-handle-id]');
    dragStart.current = { x: e.clientX, y: e.clientY };
    isDragging.current = true;

    if (handleEl) { 
        dragTarget.current = 'link'; 
        activeId.current = handleEl.getAttribute('data-handle-id'); 
        e.stopPropagation(); 
    } else if (nodeEl) { 
        dragTarget.current = 'node'; 
        activeId.current = nodeEl.getAttribute('data-node-id'); 
        setSelectedId(activeId.current); 
        e.stopPropagation(); 
    } else { 
        dragTarget.current = 'viewport'; 
        setSelectedId(null); 
    }
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isDragging.current) return;
    const dx = e.clientX - dragStart.current.x;
    const dy = e.clientY - dragStart.current.y;

    if (dragTarget.current === 'viewport') { 
        setViewport(prev => ({ ...prev, x: prev.x + dx, y: prev.y + dy })); 
    } else if (dragTarget.current === 'node' && activeId.current) {
        setSteps(prev => prev.map(s => s.id === activeId.current ? { ...s, position: { x: (s.position?.x || 0) + dx / viewport.zoom, y: (s.position?.y || 0) + dy / viewport.zoom } } : s));
    } else if (dragTarget.current === 'link' && activeId.current) {
        const sNode = steps.find(s => s.id === activeId.current);
        if (sNode && sNode.position) {
            const world = screenToWorld(e.clientX, e.clientY);
            // 200/80 should be tokens, but for JS logic keeping consistent with node dimensions
            ghostLink.current = { x1: sNode.position.x + 200, y1: sNode.position.y + 40, x2: world.x, y2: world.y };
            setViewport(v => ({...v})); // Force re-render for ghost link
        }
    }
    dragStart.current = { x: e.clientX, y: e.clientY };
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (dragTarget.current === 'link' && activeId.current) {
      const targetEl = document.elementFromPoint(e.clientX, e.clientY)?.closest('[data-node-id]');
      const tId = targetEl?.getAttribute('data-node-id');

      const sourceId = activeId.current;

      if (tId && sourceId && tId !== sourceId) {
        setLinks(prev => {
            if (prev.some(l => l.sourceId === sourceId && l.targetId === tId)) return prev;
            return [...prev, { id: `link-${Date.now()}`, sourceId, targetId: tId }];
        });
      }
    } else if (dragTarget.current === 'node' && activeId.current) {
       setSteps(prev => prev.map(s => s.id === activeId.current ? { ...s, position: { x: snapToGrid(s.position?.x || 0), y: snapToGrid(s.position?.y || 0) } } : s));
    }

    isDragging.current = false; 
    ghostLink.current = null; 
    activeId.current = null; 
    setViewport(v => ({...v}));
  };

  const selectedStep = useMemo(() => steps.find(s => s.id === selectedId), [selectedId, steps]);
  const updateStep = (updatedStep: ProcessStep) => setSteps(prev => prev.map(s => s.id === updatedStep.id ? updatedStep : s));
  const deleteStep = (id: string) => { 
      setSteps(prev => prev.filter(s => s.id !== id)); 
      setLinks(prev => prev.filter(l => l.sourceId !== id && l.targetId !== id)); 
      setSelectedId(null); 
  };

  // Mock Heatmap Data Generation
  const getHeatmapColor = (stepId: string) => {
      // Deterministic pseudo-random based on ID string char codes
      const score = stepId.split('').reduce((a,b) => a + b.charCodeAt(0), 0) % 100;
      if (score > 80) return 'bg-rose-500/30 border-rose-500 shadow-[0_0_15px_rgba(244,63,94,0.5)]';
      if (score > 50) return 'bg-amber-500/30 border-amber-500 shadow-[0_0_15px_rgba(245,158,11,0.5)]';
      return 'bg-emerald-500/30 border-emerald-500 shadow-[0_0_15px_rgba(16,185,129,0.5)]';
  };

  return (
    <div className="h-[calc(100vh-100px)] flex flex-col bg-panel border border-default rounded-base shadow-sm overflow-hidden">
      {/* 1. Rigid Toolbar */}
      <div className="h-header bg-subtle border-b border-default flex items-center justify-between px-3 shrink-0">
         <div className="flex items-center gap-3">
            <button onClick={() => setPaletteOpen(!paletteOpen)} className={`p-1 rounded-base hover:bg-white border border-transparent hover:border-subtle ${paletteOpen ? 'text-blue-600' : 'text-secondary'}`}><LayoutPanelLeft size={16}/></button>
            <div className="h-4 w-px bg-default"></div>
            <input className="bg-transparent text-sm font-bold text-primary w-48 outline-none" value={processName} onChange={e => setProcessName(e.target.value)} />
         </div>
         <div className="flex items-center gap-2">
            <input className="h-7 w-64 bg-panel border border-default rounded-base px-2 text-xs" placeholder="Describe workflow for AI generation..." value={aiPrompt} onChange={e => setAiPrompt(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleAiGenerate(e)} disabled={isGenerating}/>
            <button className="p-1 text-secondary hover:text-primary" onClick={() => setViewport(v => ({...v, zoom: v.zoom * 1.1}))}><ZoomIn size={16}/></button>
            <button className="p-1 text-secondary hover:text-primary" onClick={() => setViewport(v => ({...v, zoom: v.zoom / 1.1}))}><ZoomOut size={16}/></button>
            <button className="p-1 text-secondary hover:text-rose-600" onClick={handleClear} title="Clear Canvas"><Trash2 size={16}/></button>

            <div className="h-4 w-px bg-default mx-1"></div>

            <button 
                onClick={() => setShowHeatmap(!showHeatmap)} 
                className={`p-1 rounded-base transition-colors ${showHeatmap ? 'bg-rose-100 text-rose-600' : 'text-secondary hover:text-primary'}`} 
                title="Toggle Heatmap"
            >
                <Thermometer size={16}/>
            </button>

            <button onClick={handleSimulation} className="flex items-center gap-1 px-3 py-1 bg-indigo-600 text-white rounded-base text-xs hover:bg-indigo-700 shadow-sm"><Cpu size={14}/> Simulate</button>
            <button onClick={handleDeploy} className="flex items-center gap-1 px-3 py-1 bg-brand-slate text-white rounded-base text-xs hover:bg-slate-900 shadow-sm"><Save size={14}/> Save</button>
         </div>
      </div>

      <div className="flex-1 flex overflow-hidden">
        {/* 2. Palette (Standard Sidebar) */}
        {paletteOpen && (
          <div className="w-56 border-r border-default bg-subtle overflow-y-auto">
             <PaletteSidebar onAddNode={addNode} />
          </div>
        )}

        {/* 3. Canvas (Grid) */}
        <div className="flex-1 relative bg-canvas overflow-hidden cursor-grab active:cursor-grabbing designer-grid"
             ref={canvasRef} 
             onPointerDown={handlePointerDown} 
             onPointerMove={handlePointerMove} 
             onPointerUp={handlePointerUp}
             onContextMenu={handleContextMenu}
        >
           <div style={{ transform: `translate(${viewport.x}px, ${viewport.y}px) scale(${viewport.zoom})`, transformOrigin: '0 0' }}>
              {/* SVG Overlay for Links - MUST be pointer-events-none to allow clicking nodes through it */}
              <svg className="overflow-visible absolute top-0 left-0 pointer-events-none" style={{ width: '100%', height: '100%' }}>
                <defs><marker id="arrow" viewBox="0 0 10 10" refX="10" refY="5" markerWidth="6" markerHeight="6" orient="auto"><path d="M 0 0 L 10 5 L 0 10 z" fill="#64748b"/></marker></defs>
                {links.map(l => {
                  const s = steps.find(n => n.id === l.sourceId); 
                  const t = steps.find(n => n.id === l.targetId);
                  if (!s || !t || !s.position || !t.position) return null;

                  // Calculate link coordinates based on node dimensions (200x80)
                  const x1 = s.position.x + 200; 
                  const y1 = s.position.y + 40; 
                  const x2 = t.position.x; 
                  const y2 = t.position.y + 40;

                  return <path key={l.id} d={`M ${x1} ${y1} C ${x1+50} ${y1}, ${x2-50} ${y2}, ${x2} ${y2}`} stroke="#64748b" strokeWidth="2" fill="none" markerEnd="url(#arrow)"/>;
                })}
                {ghostLink.current && <path d={`M ${ghostLink.current.x1} ${ghostLink.current.y1} L ${ghostLink.current.x2} ${ghostLink.current.y2}`} stroke="#94a3b8" strokeWidth="2" strokeDasharray="5,5" fill="none"/>}
              </svg>

              {/* Nodes Layer */}
              {steps.map(step => (
                  <div key={step.id} className="relative">
                      <NodeComponent step={step} isSelected={selectedId === step.id} />
                      {showHeatmap && step.position && (
                          <div 
                            className={`absolute pointer-events-none z-30 inset-0 rounded-base border-2 ${getHeatmapColor(step.id)}`}
                            style={{ 
                                left: step.position.x, 
                                top: step.position.y,
                                width: '200px', 
                                height: '80px',
                                backdropFilter: 'blur(1px)'
                            }}
                          >
                              <div className="absolute -top-6 left-1/2 -translate-x-1/2 bg-black text-white text-[10px] font-bold px-2 py-0.5 rounded-full whitespace-nowrap shadow-lg">
                                  Avg: {Math.floor(Math.random() * 200)}ms
                              </div>
                          </div>
                      )}
                  </div>
              ))}
           </div>
        </div>

        {/* 4. Properties (Rigid Right Panel) */}
        {selectedStep && (
          <div className="w-72 border-l border-default bg-panel overflow-y-auto shadow-xl z-20">
             <PropertiesPanel step={selectedStep} onUpdate={updateStep} onDelete={deleteStep} roles={roles} />
          </div>
        )}
      </div>

      {/* Context Menu Overlay */}
      {contextMenu && (
        <CanvasContextMenu 
          position={contextMenu.position} 
          targetId={contextMenu.targetId} 
          onClose={() => setContextMenu(null)}
          onAction={handleMenuAction}
        />
      )}
    </div>
  );
};

