import React from 'react';
import { ProcessStep } from '../../types';
import { getStepTypeMetadata } from './designerUtils';
import { FunctionSquare, RefreshCw, Code, AlertCircle, Layers } from 'lucide-react';

interface NodeComponentProps {
  step: ProcessStep;
  isSelected: boolean;
}

export const NodeComponent: React.FC<NodeComponentProps> = ({ step, isSelected }) => {
  const { icon: Icon, color } = getStepTypeMetadata(step.type);

  // Logic Detection
  const hasRule = !!step.businessRuleId;
  const hasScript = !!step.onEntryAction || !!step.onExitAction;
  const hasRetry = step.retryPolicy?.enabled;
  const isLoop = step.isMultiInstance;
  const missingConfig = step.type === 'service-task' && !step.data?.url;

  return (
    <div 
      data-node-id={step.id} 
      className={`absolute w-[200px] h-[80px] bg-panel border flex flex-col shadow-sm transition-all select-none group ${
        isSelected 
          ? 'border-active ring-1 ring-blue-600 z-node-active' 
          : 'border-default hover:border-tertiary z-node'
      }`} 
      style={{ 
        left: step.position?.x, 
        top: step.position?.y,
        borderRadius: 'var(--radius-base)' 
      }}
    >
      {/* Input Handle (Left) - Always visible as a target anchor */}
      <div className="absolute -left-1.5 top-1/2 -translate-y-1/2 w-3 h-3 bg-white border border-slate-400 rounded-full z-10 transition-colors group-hover:border-blue-500" />

      {/* Main Body */}
      <div className="flex items-center gap-3 px-3 pt-3 pb-1 flex-1 overflow-hidden">
        <div className={`w-8 h-8 flex items-center justify-center rounded-base bg-subtle border border-default relative shrink-0`}>
          <Icon size={16} className={color.replace('text-', 'text-opacity-80 text-')} />
          {missingConfig && (
             <div className="absolute -top-1 -right-1 bg-white rounded-full">
                <AlertCircle size={12} className="text-rose-500 fill-white"/>
             </div>
          )}
        </div>

        <div className="flex-1 min-w-0">
          <p className="text-[12px] font-bold text-primary truncate leading-tight">
            {step.name}
          </p>
          <p className="text-[10px] text-secondary uppercase tracking-wide truncate mt-0.5">
            {step.type.replace(/-/g, ' ')}
          </p>
        </div>
      </div>

      {/* Logic Badges Bar */}
      {(hasRule || hasScript || hasRetry || isLoop) && (
          <div className="px-3 pb-2 flex gap-1.5 items-center">
              {hasRule && (
                  <div className="flex items-center gap-0.5 px-1 py-0.5 bg-indigo-50 border border-indigo-100 rounded-[2px] text-[8px] font-bold text-indigo-700" title="Business Rule Attached">
                      <FunctionSquare size={8} /> RULE
                  </div>
              )}
              {hasScript && (
                  <div className="flex items-center gap-0.5 px-1 py-0.5 bg-amber-50 border border-amber-100 rounded-[2px] text-[8px] font-bold text-amber-700" title="Entry/Exit Script Active">
                      <Code size={8} /> FN
                  </div>
              )}
              {hasRetry && (
                  <div className="flex items-center gap-0.5 px-1 py-0.5 bg-blue-50 border border-blue-100 rounded-[2px] text-[8px] font-bold text-blue-700" title={`Retry Policy: ${step.retryPolicy?.maxAttempts}x`}>
                      <RefreshCw size={8} /> {step.retryPolicy?.maxAttempts}x
                  </div>
              )}
              {isLoop && (
                  <div className="ml-auto text-secondary" title="Multi-Instance Loop">
                      <Layers size={10} />
                  </div>
              )}
          </div>
      )}

      {/* Output Connector Handle (Right) */}
      <div 
        data-handle-id={step.id} 
        className="absolute -right-1.5 top-1/2 -translate-y-1/2 w-3 h-3 bg-white border border-slate-400 rounded-full cursor-crosshair hover:bg-blue-600 hover:border-blue-600 transition-all z-tooltip opacity-0 group-hover:opacity-100 shadow-sm"
      />
    </div>
  );
};

import React, { useState, useRef, useMemo, useEffect } from 'react';
import { ProcessStep, ProcessLink, ProcessStepType } from '../types';
import { useBPM } from '../contexts/BPMContext';
import { 
  Save, ZoomIn, ZoomOut, Sparkles, Cpu, LayoutPanelLeft, Trash2, Thermometer
} from 'lucide-react';
import { PaletteSidebar } from './designer/PaletteSidebar';
import { NodeComponent } from './designer/NodeComponent';
import { PropertiesPanel } from './designer/PropertiesPanel';
import { CanvasContextMenu } from './designer/CanvasContextMenu'; // Imported
import { getStepTypeMetadata } from './designer/designerUtils';
import { generateProcessWorkflow } from '../services/geminiService';

const GRID_SIZE = 20;
const NODE_WIDTH = 200;
const NODE_HEIGHT = 80;

export const ProcessDesigner: React.FC = () => {
  const { deployProcess, roles, addNotification, designerDraft, setDesignerDraft, navigateTo } = useBPM();
  const [processName, setProcessName] = useState('Strategic Workflow');
  const [steps, setSteps] = useState<ProcessStep[]>([]);
  const [links, setLinks] = useState<ProcessLink[]>([]);
  const [viewport, setViewport] = useState({ x: 50, y: 50, zoom: 1 });
  const [selectedId, setSelectedId] = useState<string | null>(null);

  // Context Menu & Clipboard State
  const [contextMenu, setContextMenu] = useState<{ position: { x: number; y: number }, targetId: string | null } | null>(null);
  const [clipboard, setClipboard] = useState<ProcessStep | null>(null);

  // AI & Heatmap States
  const [aiPrompt, setAiPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [showHeatmap, setShowHeatmap] = useState(false);

  const [paletteOpen, setPaletteOpen] = useState(true);

  const canvasRef = useRef<HTMLDivElement>(null);
  const isDragging = useRef(false);
  const dragStart = useRef({ x: 0, y: 0 });
  const dragTarget = useRef<'viewport' | 'node' | 'link'>('viewport');
  const activeId = useRef<string | null>(null);
  const ghostLink = useRef<{x1: number, y1: number, x2: number, y2: number} | null>(null);

  // Restore state from context if available
  useEffect(() => {
    if (designerDraft) {
        setSteps(designerDraft.steps);
        setLinks(designerDraft.links);
    }
  }, []);

  // Persist state to context on change
  useEffect(() => {
    setDesignerDraft({ steps, links });
  }, [steps, links, setDesignerDraft]);

  const snapToGrid = (val: number) => Math.round(val / GRID_SIZE) * GRID_SIZE;

  const screenToWorld = (sx: number, sy: number) => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const rect = canvasRef.current.getBoundingClientRect();
    return { 
      x: (sx - rect.left - viewport.x) / viewport.zoom, 
      y: (sy - rect.top - viewport.y) / viewport.zoom 
    };
  };

  // --- Actions ---

  const handleDeploy = async () => {
    const connectedSteps = steps.map(step => {
        const outgoingLinks = links.filter(l => l.sourceId === step.id);
        return {
            ...step,
            nextStepIds: outgoingLinks.map(l => l.targetId)
        };
    });

    await deployProcess({ 
        name: processName, 
        steps: connectedSteps, 
        links, 
        isActive: true, 
        version: 1 
    });
    addNotification('success', 'Process definition deployed successfully.');
  };

  const handleClear = () => {
    if(window.confirm('Clear current design?')) {
        setSteps([]);
        setLinks([]);
        setSelectedId(null);
    }
  };

  const handleAiGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!aiPrompt.trim()) return;
    setIsGenerating(true);
    try {
      const generatedSteps = await generateProcessWorkflow(aiPrompt);
      if (generatedSteps && generatedSteps.length > 0) {
        setSteps(generatedSteps);
        const newLinks: ProcessLink[] = [];
        for(let i=0; i < generatedSteps.length - 1; i++) {
          newLinks.push({ id: `link-auto-${i}`, sourceId: generatedSteps[i].id, targetId: generatedSteps[i+1].id });
        }
        setLinks(newLinks);
        addNotification('success', 'Model synthesized.');
        setAiPrompt('');
      }
    } catch (err) { addNotification('error', 'Generation failure.'); } finally { setIsGenerating(false); }
  };

  const handleSimulation = async () => {
    if (steps.length === 0) {
      addNotification('error', 'Canvas is empty. Add steps to simulate.');
      return;
    }
    navigateTo('simulation-report');
  };

  const addNode = (type: ProcessStepType, position?: { x: number, y: number }) => {
    const world = position || screenToWorld(window.innerWidth / 2, window.innerHeight / 2);
    const metadata = getStepTypeMetadata(type);
    const newNode: ProcessStep = {
      id: `node-${Date.now()}`, name: metadata.defaultName, type, description: '',
      position: { x: snapToGrid(world.x - (position ? 0 : NODE_WIDTH / 2)), y: snapToGrid(world.y - (position ? 0 : NODE_HEIGHT / 2)) },
      requiredSkills: metadata.defaultSkills || [], data: {}
    };
    setSteps(prev => [...prev, newNode]);
    setSelectedId(newNode.id);
  };

  // --- Context Menu Handlers ---

  const handleContextMenu = (e: React.MouseEvent) => {
    e.preventDefault();
    const target = e.target as HTMLElement;
    const nodeEl = target.closest('[data-node-id]');
    const targetId = nodeEl ? nodeEl.getAttribute('data-node-id') : null;

    // Select the node immediately if right-clicked
    if (targetId) setSelectedId(targetId);

    setContextMenu({
      position: { x: e.clientX, y: e.clientY },
      targetId
    });
  };

  const handleMenuAction = (action: string, payload?: any) => {
    if (!contextMenu) return;
    const { targetId, position } = contextMenu;

    switch (action) {
      case 'delete':
        if (targetId) deleteStep(targetId);
        break;

      case 'duplicate':
        if (targetId) {
          const original = steps.find(s => s.id === targetId);
          if (original) {
            const newNode = {
              ...original,
              id: `node-${Date.now()}`,
              name: `${original.name} (Copy)`,
              position: { x: (original.position?.x || 0) + 20, y: (original.position?.y || 0) + 20 }
            };
            setSteps(prev => [...prev, newNode]);
            setSelectedId(newNode.id);
          }
        }
        break;

      case 'copy':
        if (targetId) {
          const node = steps.find(s => s.id === targetId);
          if (node) {
            setClipboard(node);
            addNotification('info', 'Copied to clipboard');
          }
        }
        break;

      case 'paste':
        if (clipboard) {
          const world = screenToWorld(position.x, position.y);
          const newNode = {
            ...clipboard,
            id: `node-${Date.now()}`,
            name: clipboard.name, 
            position: { x: snapToGrid(world.x), y: snapToGrid(world.y) }
          };
          setSteps(prev => [...prev, newNode]);
          setSelectedId(newNode.id);
          addNotification('success', 'Pasted component');
        } else {
          addNotification('info', 'Clipboard is empty');
        }
        break;

      case 'disconnect':
        if (targetId) {
          setLinks(prev => prev.filter(l => l.sourceId !== targetId && l.targetId !== targetId));
          addNotification('info', 'Links removed.');
        }
        break;

      case 'edit':
        // Already selected by context menu open logic, panel is open
        break;

      case 'add-node':
        // Calculate world coordinates for the click position
        const world = screenToWorld(position.x, position.y);
        addNode(payload, { x: world.x, y: world.y });
        break;

      case 'reset-view':
        setViewport({ x: 50, y: 50, zoom: 1 });
        break;

      case 'clear-canvas':
        handleClear();
        break;
    }
    setContextMenu(null);
  };

  // --- Pointer Events ---

  const handlePointerDown = (e: React.PointerEvent) => {
    // Hide context menu on left click
    if (contextMenu) setContextMenu(null);

    const target = e.target as HTMLElement;
    const nodeEl = target.closest('[data-node-id]');
    const handleEl = target.closest('[data-handle-id]');
    dragStart.current = { x: e.clientX, y: e.clientY };
    isDragging.current = true;

    if (handleEl) { 
        dragTarget.current = 'link'; 
        activeId.current = handleEl.getAttribute('data-handle-id'); 
        e.stopPropagation(); 
    } else if (nodeEl) { 
        dragTarget.current = 'node'; 
        activeId.current = nodeEl.getAttribute('data-node-id'); 
        setSelectedId(activeId.current); 
        e.stopPropagation(); 
    } else { 
        dragTarget.current = 'viewport'; 
        setSelectedId(null); 
    }
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isDragging.current) return;
    const dx = e.clientX - dragStart.current.x;
    const dy = e.clientY - dragStart.current.y;

    if (dragTarget.current === 'viewport') { 
        setViewport(prev => ({ ...prev, x: prev.x + dx, y: prev.y + dy })); 
    } else if (dragTarget.current === 'node' && activeId.current) {
        setSteps(prev => prev.map(s => s.id === activeId.current ? { ...s, position: { x: (s.position?.x || 0) + dx / viewport.zoom, y: (s.position?.y || 0) + dy / viewport.zoom } } : s));
    } else if (dragTarget.current === 'link' && activeId.current) {
        const sNode = steps.find(s => s.id === activeId.current);
        if (sNode && sNode.position) {
            const world = screenToWorld(e.clientX, e.clientY);

            // Check for sticky target
            let targetX = world.x;
            let targetY = world.y;
            const el = document.elementFromPoint(e.clientX, e.clientY);
            const targetNodeEl = el?.closest('[data-node-id]');

            if (targetNodeEl) {
                const tid = targetNodeEl.getAttribute('data-node-id');
                if (tid && tid !== activeId.current) {
                    const tNode = steps.find(s => s.id === tid);
                    if (tNode && tNode.position) {
                        // Snap to Left handle of target
                        targetX = tNode.position.x;
                        targetY = tNode.position.y + (NODE_HEIGHT / 2);
                    }
                }
            }

            ghostLink.current = { 
                x1: sNode.position.x + NODE_WIDTH, 
                y1: sNode.position.y + (NODE_HEIGHT / 2), 
                x2: targetX, 
                y2: targetY 
            };
            setViewport(v => ({...v})); // Force re-render for ghost link
        }
    }
    dragStart.current = { x: e.clientX, y: e.clientY };
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (dragTarget.current === 'link' && activeId.current) {
      const targetEl = document.elementFromPoint(e.clientX, e.clientY)?.closest('[data-node-id]');
      const tId = targetEl?.getAttribute('data-node-id');

      const sourceId = activeId.current;

      if (tId && sourceId && tId !== sourceId) {
        setLinks(prev => {
            if (prev.some(l => l.sourceId === sourceId && l.targetId === tId)) return prev;
            return [...prev, { id: `link-${Date.now()}`, sourceId, targetId: tId }];
        });
      }
    } else if (dragTarget.current === 'node' && activeId.current) {
       setSteps(prev => prev.map(s => s.id === activeId.current ? { ...s, position: { x: snapToGrid(s.position?.x || 0), y: snapToGrid(s.position?.y || 0) } } : s));
    }

    isDragging.current = false; 
    ghostLink.current = null; 
    activeId.current = null; 
    setViewport(v => ({...v}));
  };

  const selectedStep = useMemo(() => steps.find(s => s.id === selectedId), [selectedId, steps]);
  const updateStep = (updatedStep: ProcessStep) => setSteps(prev => prev.map(s => s.id === updatedStep.id ? updatedStep : s));
  const deleteStep = (id: string) => { 
      setSteps(prev => prev.filter(s => s.id !== id)); 
      setLinks(prev => prev.filter(l => l.sourceId !== id && l.targetId !== id)); 
      setSelectedId(null); 
  };

  // Mock Heatmap Data Generation
  const getHeatmapColor = (stepId: string) => {
      const score = stepId.split('').reduce((a,b) => a + b.charCodeAt(0), 0) % 100;
      if (score > 80) return 'bg-rose-500/30 border-rose-500 shadow-[0_0_15px_rgba(244,63,94,0.5)]';
      if (score > 50) return 'bg-amber-500/30 border-amber-500 shadow-[0_0_15px_rgba(245,158,11,0.5)]';
      return 'bg-emerald-500/30 border-emerald-500 shadow-[0_0_15px_rgba(16,185,129,0.5)]';
  };

  return (
    <div className="h-[calc(100vh-100px)] flex flex-col bg-panel border border-default rounded-base shadow-sm overflow-hidden">
      {/* 1. Rigid Toolbar */}
      <div className="h-header bg-subtle border-b border-default flex items-center justify-between px-3 shrink-0">
         <div className="flex items-center gap-3">
            <button onClick={() => setPaletteOpen(!paletteOpen)} className={`p-1 rounded-base hover:bg-white border border-transparent hover:border-subtle ${paletteOpen ? 'text-blue-600' : 'text-secondary'}`}><LayoutPanelLeft size={16}/></button>
            <div className="h-4 w-px bg-default"></div>
            <input className="bg-transparent text-sm font-bold text-primary w-48 outline-none" value={processName} onChange={e => setProcessName(e.target.value)} />
         </div>
         <div className="flex items-center gap-2">
            <input className="h-7 w-64 bg-panel border border-default rounded-base px-2 text-xs" placeholder="Describe workflow for AI generation..." value={aiPrompt} onChange={e => setAiPrompt(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleAiGenerate(e)} disabled={isGenerating}/>
            <button className="p-1 text-secondary hover:text-primary" onClick={() => setViewport(v => ({...v, zoom: v.zoom * 1.1}))}><ZoomIn size={16}/></button>
            <button className="p-1 text-secondary hover:text-primary" onClick={() => setViewport(v => ({...v, zoom: v.zoom / 1.1}))}><ZoomOut size={16}/></button>
            <button className="p-1 text-secondary hover:text-rose-600" onClick={handleClear} title="Clear Canvas"><Trash2 size={16}/></button>

            <div className="h-4 w-px bg-default mx-1"></div>

            <button 
                onClick={() => setShowHeatmap(!showHeatmap)} 
                className={`p-1 rounded-base transition-colors ${showHeatmap ? 'bg-rose-100 text-rose-600' : 'text-secondary hover:text-primary'}`} 
                title="Toggle Heatmap"
            >
                <Thermometer size={16}/>
            </button>

            <button onClick={handleSimulation} className="flex items-center gap-1 px-3 py-1 bg-indigo-600 text-white rounded-base text-xs hover:bg-indigo-700 shadow-sm"><Cpu size={14}/> Simulate</button>
            <button onClick={handleDeploy} className="flex items-center gap-1 px-3 py-1 bg-brand-slate text-white rounded-base text-xs hover:bg-slate-900 shadow-sm"><Save size={14}/> Save</button>
         </div>
      </div>

      <div className="flex-1 flex overflow-hidden">
        {/* 2. Palette (Standard Sidebar) */}
        {paletteOpen && (
          <div className="w-56 border-r border-default bg-subtle overflow-y-auto">
             <PaletteSidebar onAddNode={addNode} />
          </div>
        )}

        {/* 3. Canvas (Grid) */}
        <div className="flex-1 relative bg-canvas overflow-hidden cursor-grab active:cursor-grabbing designer-grid"
             ref={canvasRef} 
             onPointerDown={handlePointerDown} 
             onPointerMove={handlePointerMove} 
             onPointerUp={handlePointerUp}
             onContextMenu={handleContextMenu}
        >
           <div style={{ transform: `translate(${viewport.x}px, ${viewport.y}px) scale(${viewport.zoom})`, transformOrigin: '0 0' }}>
              {/* SVG Overlay for Links - MUST be pointer-events-none to allow clicking nodes through it */}
              <svg className="overflow-visible absolute top-0 left-0 pointer-events-none" style={{ width: '100%', height: '100%' }}>
                <defs><marker id="arrow" viewBox="0 0 10 10" refX="10" refY="5" markerWidth="6" markerHeight="6" orient="auto"><path d="M 0 0 L 10 5 L 0 10 z" fill="#64748b"/></marker></defs>
                {links.map(l => {
                  const s = steps.find(n => n.id === l.sourceId); 
                  const t = steps.find(n => n.id === l.targetId);
                  if (!s || !t || !s.position || !t.position) return null;

                  // Link Source: Right Center of Source Node
                  const x1 = s.position.x + NODE_WIDTH; 
                  const y1 = s.position.y + (NODE_HEIGHT / 2); 

                  // Link Target: Left Center of Target Node
                  const x2 = t.position.x; 
                  const y2 = t.position.y + (NODE_HEIGHT / 2);

                  return <path key={l.id} d={`M ${x1} ${y1} C ${x1+50} ${y1}, ${x2-50} ${y2}, ${x2} ${y2}`} stroke="#64748b" strokeWidth="2" fill="none" markerEnd="url(#arrow)"/>;
                })}
                {ghostLink.current && <path d={`M ${ghostLink.current.x1} ${ghostLink.current.y1} C ${ghostLink.current.x1+50} ${ghostLink.current.y1}, ${ghostLink.current.x2-50} ${ghostLink.current.y2}, ${ghostLink.current.x2} ${ghostLink.current.y2}`} stroke="#94a3b8" strokeWidth="2" strokeDasharray="5,5" fill="none"/>}
              </svg>

              {/* Nodes Layer */}
              {steps.map(step => (
                  <div key={step.id} className="relative">
                      <NodeComponent step={step} isSelected={selectedId === step.id} />
                      {showHeatmap && step.position && (
                          <div 
                            className={`absolute pointer-events-none z-30 inset-0 rounded-base border-2 ${getHeatmapColor(step.id)}`}
                            style={{ 
                                left: step.position.x, 
                                top: step.position.y,
                                width: `${NODE_WIDTH}px`, 
                                height: `${NODE_HEIGHT}px`,
                                backdropFilter: 'blur(1px)'
                            }}
                          >
                              <div className="absolute -top-6 left-1/2 -translate-x-1/2 bg-black text-white text-[10px] font-bold px-2 py-0.5 rounded-full whitespace-nowrap shadow-lg">
                                  Avg: {Math.floor(Math.random() * 200)}ms
                              </div>
                          </div>
                      )}
                  </div>
              ))}
           </div>
        </div>

        {/* 4. Properties (Rigid Right Panel) */}
        {selectedStep && (
          <div className="w-72 border-l border-default bg-panel overflow-y-auto shadow-xl z-20">
             <PropertiesPanel step={selectedStep} onUpdate={updateStep} onDelete={deleteStep} roles={roles} />
          </div>
        )}
      </div>

      {/* Context Menu Overlay */}
      {contextMenu && (
        <CanvasContextMenu 
          position={contextMenu.position} 
          targetId={contextMenu.targetId} 
          onClose={() => setContextMenu(null)}
          onAction={handleMenuAction}
        />
      )}
    </div>
  );
};

import React, { memo } from 'react';
import { ProcessStep } from '../../types';
import { getStepTypeMetadata } from './designerUtils';
import { FunctionSquare, RefreshCw, Code, AlertCircle, Layers } from 'lucide-react';

interface NodeComponentProps {
  step: ProcessStep;
  isSelected: boolean;
}

// Optimization: Use React.memo so nodes don't re-render when other nodes move
export const NodeComponent = memo(({ step, isSelected }: NodeComponentProps) => {
  const { icon: Icon, color } = getStepTypeMetadata(step.type);

  // Logic Detection
  const hasRule = !!step.businessRuleId;
  const hasScript = !!step.onEntryAction || !!step.onExitAction;
  const hasRetry = step.retryPolicy?.enabled;
  const isLoop = step.isMultiInstance;
  const missingConfig = step.type === 'service-task' && !step.data?.url;

  // Handle Styles
  const handleStyle = "absolute w-2.5 h-2.5 bg-white border border-slate-400 rounded-full z-20 transition-all opacity-0 group-hover:opacity-100 hover:bg-blue-600 hover:border-blue-600 hover:scale-125 cursor-crosshair";

  return (
    <div 
      data-node-id={step.id} 
      className={`absolute w-[200px] h-[80px] bg-panel border flex flex-col shadow-sm transition-shadow select-none group ${
        isSelected 
          ? 'border-active ring-2 ring-blue-500/20 z-node-active shadow-md' 
          : 'border-default hover:border-tertiary z-node'
      }`} 
      style={{ 
        left: step.position?.x, 
        top: step.position?.y,
        borderRadius: 'var(--radius-base)',
        // Performance: hint browser to promote to own layer
        willChange: 'transform, left, top' 
      }}
    >
      {/* 4-Way Connection Handles */}
      {/* Left (Input) */}
      <div data-handle-pos="left" data-handle-id={step.id} className={`${handleStyle} -left-1.5 top-1/2 -translate-y-1/2`} />
      {/* Right (Output) */}
      <div data-handle-pos="right" data-handle-id={step.id} className={`${handleStyle} -right-1.5 top-1/2 -translate-y-1/2`} />
      {/* Top */}
      <div data-handle-pos="top" data-handle-id={step.id} className={`${handleStyle} left-1/2 -translate-x-1/2 -top-1.5`} />
      {/* Bottom */}
      <div data-handle-pos="bottom" data-handle-id={step.id} className={`${handleStyle} left-1/2 -translate-x-1/2 -bottom-1.5`} />

      {/* Main Body */}
      <div className="flex items-center gap-3 px-3 pt-3 pb-1 flex-1 overflow-hidden pointer-events-none">
        <div className={`w-8 h-8 flex items-center justify-center rounded-base bg-subtle border border-default relative shrink-0`}>
          <Icon size={16} className={color.replace('text-', 'text-opacity-80 text-')} />
          {missingConfig && (
             <div className="absolute -top-1 -right-1 bg-white rounded-full">
                <AlertCircle size={12} className="text-rose-500 fill-white"/>
             </div>
          )}
        </div>

        <div className="flex-1 min-w-0">
          <p className="text-[12px] font-bold text-primary truncate leading-tight">
            {step.name}
          </p>
          <p className="text-[10px] text-secondary uppercase tracking-wide truncate mt-0.5">
            {step.type.replace(/-/g, ' ')}
          </p>
        </div>
      </div>

      {/* Logic Badges Bar */}
      {(hasRule || hasScript || hasRetry || isLoop) && (
          <div className="px-3 pb-2 flex gap-1.5 items-center pointer-events-none">
              {hasRule && (
                  <div className="flex items-center gap-0.5 px-1 py-0.5 bg-indigo-50 border border-indigo-100 rounded-[2px] text-[8px] font-bold text-indigo-700">
                      <FunctionSquare size={8} /> RULE
                  </div>
              )}
              {hasScript && (
                  <div className="flex items-center gap-0.5 px-1 py-0.5 bg-amber-50 border border-amber-100 rounded-[2px] text-[8px] font-bold text-amber-700">
                      <Code size={8} /> FN
                  </div>
              )}
              {hasRetry && (
                  <div className="flex items-center gap-0.5 px-1 py-0.5 bg-blue-50 border border-blue-100 rounded-[2px] text-[8px] font-bold text-blue-700">
                      <RefreshCw size={8} /> {step.retryPolicy?.maxAttempts}x
                  </div>
              )}
              {isLoop && (
                  <div className="ml-auto text-secondary">
                      <Layers size={10} />
                  </div>
              )}
          </div>
      )}
    </div>
  );
}, (prev, next) => {
    // Custom comparison to reduce re-renders
    return (
        prev.step.position?.x === next.step.position?.x &&
        prev.step.position?.y === next.step.position?.y &&
        prev.step.name === next.step.name &&
        prev.step.businessRuleId === next.step.businessRuleId &&
        prev.isSelected === next.isSelected
    );
});

import React, { useState, useRef, useMemo, useEffect, useCallback } from 'react';
import { ProcessStep, ProcessLink, ProcessStepType } from '../types';
import { useBPM } from '../contexts/BPMContext';
import { 
  Save, ZoomIn, ZoomOut, Sparkles, Cpu, LayoutPanelLeft, Trash2, Thermometer
} from 'lucide-react';
import { PaletteSidebar } from './designer/PaletteSidebar';
import { NodeComponent } from './designer/NodeComponent';
import { PropertiesPanel } from './designer/PropertiesPanel';
import { CanvasContextMenu } from './designer/CanvasContextMenu';
import { getStepTypeMetadata } from './designer/designerUtils';
import { generateProcessWorkflow } from '../services/geminiService';

const GRID_SIZE = 20;
const NODE_WIDTH = 200;
const NODE_HEIGHT = 80;

// Optimized Path Calculation (Smart Routing)
// Determines the best connection points based on relative position
const getSmartPath = (x1: number, y1: number, x2: number, y2: number) => {
    // Define handle positions relative to center
    const sourceHandles = {
        right: { x: x1 + NODE_WIDTH, y: y1 + NODE_HEIGHT / 2 },
        left: { x: x1, y: y1 + NODE_HEIGHT / 2 },
        bottom: { x: x1 + NODE_WIDTH / 2, y: y1 + NODE_HEIGHT },
        top: { x: x1 + NODE_WIDTH / 2, y: y1 }
    };

    const targetHandles = {
        right: { x: x2 + NODE_WIDTH, y: y2 + NODE_HEIGHT / 2 },
        left: { x: x2, y: y2 + NODE_HEIGHT / 2 },
        bottom: { x: x2 + NODE_WIDTH / 2, y: y2 + NODE_HEIGHT },
        top: { x: x2 + NODE_WIDTH / 2, y: y2 }
    };

    // Simple heuristic: choose closest pair of handles
    let minDist = Infinity;
    let start = sourceHandles.right;
    let end = targetHandles.left;
    let startSide = 'right';
    let endSide = 'left';

    // Check logical combinations
    const pairs = [
        { s: 'right', t: 'left' },
        { s: 'left', t: 'right' },
        { s: 'bottom', t: 'top' },
        { s: 'top', t: 'bottom' },
        { s: 'right', t: 'top' }, // Corner cases
        { s: 'bottom', t: 'left' }
    ];

    pairs.forEach(pair => {
        const s = sourceHandles[pair.s as keyof typeof sourceHandles];
        const t = targetHandles[pair.t as keyof typeof targetHandles];
        const dist = Math.hypot(s.x - t.x, s.y - t.y);
        if (dist < minDist) {
            minDist = dist;
            start = s;
            end = t;
            startSide = pair.s;
            endSide = pair.t;
        }
    });

    // Control Points for Cubic Bezier
    let cp1 = { x: start.x, y: start.y };
    let cp2 = { x: end.x, y: end.y };
    const curveStrength = Math.min(100, minDist * 0.5);

    if (startSide === 'right') cp1.x += curveStrength;
    else if (startSide === 'left') cp1.x -= curveStrength;
    else if (startSide === 'bottom') cp1.y += curveStrength;
    else cp1.y -= curveStrength;

    if (endSide === 'right') cp2.x += curveStrength;
    else if (endSide === 'left') cp2.x -= curveStrength;
    else if (endSide === 'bottom') cp2.y += curveStrength;
    else cp2.y -= curveStrength;

    return `M ${start.x} ${start.y} C ${cp1.x} ${cp1.y}, ${cp2.x} ${cp2.y}, ${end.x} ${end.y}`;
};

// Separated Link Component for Performance
const ProcessLinkComponent = React.memo(({ link, steps }: { link: ProcessLink, steps: ProcessStep[] }) => {
    const s = steps.find(n => n.id === link.sourceId);
    const t = steps.find(n => n.id === link.targetId);
    if (!s || !t || !s.position || !t.position) return null;

    const path = getSmartPath(s.position.x, s.position.y, t.position.x, t.position.y);

    return (
        <g className="group pointer-events-auto">
            {/* Thick invisible stroke for easier hovering */}
            <path d={path} stroke="transparent" strokeWidth="15" fill="none" className="cursor-pointer" />
            {/* Visible stroke */}
            <path d={path} stroke="#64748b" strokeWidth="2" fill="none" markerEnd="url(#arrow)" className="group-hover:stroke-blue-500 transition-colors" />
        </g>
    );
}, (prev, next) => {
    // Only re-render link if source or target positions changed
    const ps = prev.steps.find(s => s.id === prev.link.sourceId);
    const pt = prev.steps.find(s => s.id === prev.link.targetId);
    const ns = next.steps.find(s => s.id === next.link.sourceId);
    const nt = next.steps.find(s => s.id === next.link.targetId);
    return ps?.position?.x === ns?.position?.x && ps?.position?.y === ns?.position?.y &&
           pt?.position?.x === nt?.position?.x && pt?.position?.y === nt?.position?.y;
});

export const ProcessDesigner: React.FC = () => {
  const { deployProcess, roles, addNotification, designerDraft, setDesignerDraft, navigateTo } = useBPM();
  const [processName, setProcessName] = useState('Strategic Workflow');
  const [steps, setSteps] = useState<ProcessStep[]>([]);
  const [links, setLinks] = useState<ProcessLink[]>([]);
  const [viewport, setViewport] = useState({ x: 50, y: 50, zoom: 1 });
  const [selectedId, setSelectedId] = useState<string | null>(null);

  // Context Menu & Clipboard State
  const [contextMenu, setContextMenu] = useState<{ position: { x: number; y: number }, targetId: string | null } | null>(null);
  const [clipboard, setClipboard] = useState<ProcessStep | null>(null);

  // AI & Heatmap States
  const [aiPrompt, setAiPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [showHeatmap, setShowHeatmap] = useState(false);

  const [paletteOpen, setPaletteOpen] = useState(true);

  const canvasRef = useRef<HTMLDivElement>(null);
  const isDragging = useRef(false);
  const dragStart = useRef({ x: 0, y: 0 });
  const dragTarget = useRef<'viewport' | 'node' | 'link'>('viewport');
  const activeId = useRef<string | null>(null);
  const ghostLink = useRef<{x1: number, y1: number, x2: number, y2: number} | null>(null);

  // Restore state from context if available
  useEffect(() => {
    if (designerDraft) {
        setSteps(designerDraft.steps);
        setLinks(designerDraft.links);
    }
  }, []);

  // Persist state to context on change
  useEffect(() => {
    setDesignerDraft({ steps, links });
  }, [steps, links, setDesignerDraft]);

  const snapToGrid = (val: number) => Math.round(val / GRID_SIZE) * GRID_SIZE;

  const screenToWorld = useCallback((sx: number, sy: number) => {
    if (!canvasRef.current) return { x: 0, y: 0 };
    const rect = canvasRef.current.getBoundingClientRect();
    return { 
      x: (sx - rect.left - viewport.x) / viewport.zoom, 
      y: (sy - rect.top - viewport.y) / viewport.zoom 
    };
  }, [viewport]);

  // --- Actions ---

  const handleDeploy = async () => {
    const connectedSteps = steps.map(step => {
        const outgoingLinks = links.filter(l => l.sourceId === step.id);
        return {
            ...step,
            nextStepIds: outgoingLinks.map(l => l.targetId)
        };
    });

    await deployProcess({ 
        name: processName, 
        steps: connectedSteps, 
        links, 
        isActive: true, 
        version: 1 
    });
    addNotification('success', 'Process definition deployed successfully.');
  };

  const handleClear = () => {
    if(window.confirm('Clear current design?')) {
        setSteps([]);
        setLinks([]);
        setSelectedId(null);
    }
  };

  const handleAiGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!aiPrompt.trim()) return;
    setIsGenerating(true);
    try {
      const generatedSteps = await generateProcessWorkflow(aiPrompt);
      if (generatedSteps && generatedSteps.length > 0) {
        setSteps(generatedSteps);
        const newLinks: ProcessLink[] = [];
        for(let i=0; i < generatedSteps.length - 1; i++) {
          newLinks.push({ id: `link-auto-${i}`, sourceId: generatedSteps[i].id, targetId: generatedSteps[i+1].id });
        }
        setLinks(newLinks);
        addNotification('success', 'Model synthesized.');
        setAiPrompt('');
      }
    } catch (err) { addNotification('error', 'Generation failure.'); } finally { setIsGenerating(false); }
  };

  const handleSimulation = async () => {
    if (steps.length === 0) {
      addNotification('error', 'Canvas is empty. Add steps to simulate.');
      return;
    }
    navigateTo('simulation-report');
  };

  const addNode = (type: ProcessStepType, position?: { x: number, y: number }) => {
    const world = position || screenToWorld(window.innerWidth / 2, window.innerHeight / 2);
    const metadata = getStepTypeMetadata(type);
    const newNode: ProcessStep = {
      id: `node-${Date.now()}`, name: metadata.defaultName, type, description: '',
      position: { x: snapToGrid(world.x - (position ? 0 : NODE_WIDTH / 2)), y: snapToGrid(world.y - (position ? 0 : NODE_HEIGHT / 2)) },
      requiredSkills: metadata.defaultSkills || [], data: {}
    };
    setSteps(prev => [...prev, newNode]);
    setSelectedId(newNode.id);
  };

  // --- Context Menu Handlers ---

  const handleContextMenu = (e: React.MouseEvent) => {
    e.preventDefault();
    const target = e.target as HTMLElement;
    const nodeEl = target.closest('[data-node-id]');
    const targetId = nodeEl ? nodeEl.getAttribute('data-node-id') : null;

    // Select the node immediately if right-clicked
    if (targetId) setSelectedId(targetId);

    setContextMenu({
      position: { x: e.clientX, y: e.clientY },
      targetId
    });
  };

  const handleMenuAction = (action: string, payload?: any) => {
    if (!contextMenu) return;
    const { targetId, position } = contextMenu;

    switch (action) {
      case 'delete':
        if (targetId) deleteStep(targetId);
        break;
      case 'duplicate':
        if (targetId) {
          const original = steps.find(s => s.id === targetId);
          if (original) {
            const newNode = {
              ...original,
              id: `node-${Date.now()}`,
              name: `${original.name} (Copy)`,
              position: { x: (original.position?.x || 0) + 20, y: (original.position?.y || 0) + 20 }
            };
            setSteps(prev => [...prev, newNode]);
            setSelectedId(newNode.id);
          }
        }
        break;
      case 'copy':
        if (targetId) {
          const node = steps.find(s => s.id === targetId);
          if (node) {
            setClipboard(node);
            addNotification('info', 'Copied to clipboard');
          }
        }
        break;
      case 'paste':
        if (clipboard) {
          const world = screenToWorld(position.x, position.y);
          const newNode = {
            ...clipboard,
            id: `node-${Date.now()}`,
            name: clipboard.name, 
            position: { x: snapToGrid(world.x), y: snapToGrid(world.y) }
          };
          setSteps(prev => [...prev, newNode]);
          setSelectedId(newNode.id);
          addNotification('success', 'Pasted component');
        } else {
          addNotification('info', 'Clipboard is empty');
        }
        break;
      case 'disconnect':
        if (targetId) {
          setLinks(prev => prev.filter(l => l.sourceId !== targetId && l.targetId !== targetId));
          addNotification('info', 'Links removed.');
        }
        break;
      case 'add-node':
        const world = screenToWorld(position.x, position.y);
        addNode(payload, { x: world.x, y: world.y });
        break;
      case 'reset-view':
        setViewport({ x: 50, y: 50, zoom: 1 });
        break;
      case 'clear-canvas':
        handleClear();
        break;
    }
    setContextMenu(null);
  };

  // --- Pointer Events ---

  const handlePointerDown = (e: React.PointerEvent) => {
    if (contextMenu) setContextMenu(null);

    const target = e.target as HTMLElement;
    const nodeEl = target.closest('[data-node-id]');
    const handleEl = target.closest('[data-handle-id]');

    dragStart.current = { x: e.clientX, y: e.clientY };
    isDragging.current = true;

    if (handleEl) { 
        dragTarget.current = 'link'; 
        activeId.current = handleEl.getAttribute('data-handle-id'); 
        e.stopPropagation(); 
    } else if (nodeEl) { 
        dragTarget.current = 'node'; 
        activeId.current = nodeEl.getAttribute('data-node-id'); 
        setSelectedId(activeId.current); 
        e.stopPropagation(); 
    } else { 
        dragTarget.current = 'viewport'; 
        setSelectedId(null); 
    }
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isDragging.current) return;
    const dx = e.clientX - dragStart.current.x;
    const dy = e.clientY - dragStart.current.y;

    if (dragTarget.current === 'viewport') { 
        setViewport(prev => ({ ...prev, x: prev.x + dx, y: prev.y + dy })); 
    } else if (dragTarget.current === 'node' && activeId.current) {
        setSteps(prev => prev.map(s => s.id === activeId.current ? { ...s, position: { x: (s.position?.x || 0) + dx / viewport.zoom, y: (s.position?.y || 0) + dy / viewport.zoom } } : s));
    } else if (dragTarget.current === 'link' && activeId.current) {
        const sNode = steps.find(s => s.id === activeId.current);
        if (sNode && sNode.position) {
            const world = screenToWorld(e.clientX, e.clientY);

            // Check for sticky target
            let targetX = world.x;
            let targetY = world.y;
            const el = document.elementFromPoint(e.clientX, e.clientY);
            const targetNodeEl = el?.closest('[data-node-id]');

            if (targetNodeEl) {
                const tid = targetNodeEl.getAttribute('data-node-id');
                if (tid && tid !== activeId.current) {
                    const tNode = steps.find(s => s.id === tid);
                    if (tNode && tNode.position) {
                        // Snap to center of target node
                        targetX = tNode.position.x + NODE_WIDTH / 2;
                        targetY = tNode.position.y + NODE_HEIGHT / 2;
                    }
                }
            }

            ghostLink.current = { 
                x1: sNode.position.x + NODE_WIDTH, 
                y1: sNode.position.y + NODE_HEIGHT / 2, 
                x2: targetX, 
                y2: targetY 
            };
            setViewport(v => ({...v})); // Force re-render just for ghost line
        }
    }
    dragStart.current = { x: e.clientX, y: e.clientY };
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (dragTarget.current === 'link' && activeId.current) {
      const targetEl = document.elementFromPoint(e.clientX, e.clientY)?.closest('[data-node-id]');
      const tId = targetEl?.getAttribute('data-node-id');
      const sourceId = activeId.current;

      if (tId && sourceId && tId !== sourceId) {
        setLinks(prev => {
            if (prev.some(l => l.sourceId === sourceId && l.targetId === tId)) return prev;
            return [...prev, { id: `link-${Date.now()}`, sourceId, targetId: tId }];
        });
      }
    } else if (dragTarget.current === 'node' && activeId.current) {
       setSteps(prev => prev.map(s => s.id === activeId.current ? { ...s, position: { x: snapToGrid(s.position?.x || 0), y: snapToGrid(s.position?.y || 0) } } : s));
    }

    isDragging.current = false; 
    ghostLink.current = null; 
    activeId.current = null; 
    setViewport(v => ({...v}));
  };

  const selectedStep = useMemo(() => steps.find(s => s.id === selectedId), [selectedId, steps]);
  const updateStep = (updatedStep: ProcessStep) => setSteps(prev => prev.map(s => s.id === updatedStep.id ? updatedStep : s));
  const deleteStep = (id: string) => { 
      setSteps(prev => prev.filter(s => s.id !== id)); 
      setLinks(prev => prev.filter(l => l.sourceId !== id && l.targetId !== id)); 
      setSelectedId(null); 
  };

  // Mock Heatmap Data Generation
  const getHeatmapColor = (stepId: string) => {
      const score = stepId.split('').reduce((a,b) => a + b.charCodeAt(0), 0) % 100;
      if (score > 80) return 'bg-rose-500/30 border-rose-500 shadow-[0_0_15px_rgba(244,63,94,0.5)]';
      if (score > 50) return 'bg-amber-500/30 border-amber-500 shadow-[0_0_15px_rgba(245,158,11,0.5)]';
      return 'bg-emerald-500/30 border-emerald-500 shadow-[0_0_15px_rgba(16,185,129,0.5)]';
  };

  return (
    <div className="h-[calc(100vh-100px)] flex flex-col bg-panel border border-default rounded-base shadow-sm overflow-hidden">
      {/* 1. Rigid Toolbar */}
      <div className="h-header bg-subtle border-b border-default flex items-center justify-between px-3 shrink-0">
         <div className="flex items-center gap-3">
            <button onClick={() => setPaletteOpen(!paletteOpen)} className={`p-1 rounded-base hover:bg-white border border-transparent hover:border-subtle ${paletteOpen ? 'text-blue-600' : 'text-secondary'}`}><LayoutPanelLeft size={16}/></button>
            <div className="h-4 w-px bg-default"></div>
            <input className="bg-transparent text-sm font-bold text-primary w-48 outline-none" value={processName} onChange={e => setProcessName(e.target.value)} />
         </div>
         <div className="flex items-center gap-2">
            <input className="h-7 w-64 bg-panel border border-default rounded-base px-2 text-xs" placeholder="Describe workflow for AI generation..." value={aiPrompt} onChange={e => setAiPrompt(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleAiGenerate(e)} disabled={isGenerating}/>
            <button className="p-1 text-secondary hover:text-primary" onClick={() => setViewport(v => ({...v, zoom: v.zoom * 1.1}))}><ZoomIn size={16}/></button>
            <button className="p-1 text-secondary hover:text-primary" onClick={() => setViewport(v => ({...v, zoom: v.zoom / 1.1}))}><ZoomOut size={16}/></button>
            <button className="p-1 text-secondary hover:text-rose-600" onClick={handleClear} title="Clear Canvas"><Trash2 size={16}/></button>

            <div className="h-4 w-px bg-default mx-1"></div>

            <button 
                onClick={() => setShowHeatmap(!showHeatmap)} 
                className={`p-1 rounded-base transition-colors ${showHeatmap ? 'bg-rose-100 text-rose-600' : 'text-secondary hover:text-primary'}`} 
                title="Toggle Heatmap"
            >
                <Thermometer size={16}/>
            </button>

            <button onClick={handleSimulation} className="flex items-center gap-1 px-3 py-1 bg-indigo-600 text-white rounded-base text-xs hover:bg-indigo-700 shadow-sm"><Cpu size={14}/> Simulate</button>
            <button onClick={handleDeploy} className="flex items-center gap-1 px-3 py-1 bg-brand-slate text-white rounded-base text-xs hover:bg-slate-900 shadow-sm"><Save size={14}/> Save</button>
         </div>
      </div>

      <div className="flex-1 flex overflow-hidden">
        {/* 2. Palette (Standard Sidebar) */}
        {paletteOpen && (
          <div className="w-56 border-r border-default bg-subtle overflow-y-auto">
             <PaletteSidebar onAddNode={addNode} />
          </div>
        )}

        {/* 3. Canvas (Grid) */}
        <div className="flex-1 relative bg-canvas overflow-hidden cursor-grab active:cursor-grabbing designer-grid"
             ref={canvasRef} 
             onPointerDown={handlePointerDown} 
             onPointerMove={handlePointerMove} 
             onPointerUp={handlePointerUp}
             onContextMenu={handleContextMenu}
        >
           <div style={{ transform: `translate(${viewport.x}px, ${viewport.y}px) scale(${viewport.zoom})`, transformOrigin: '0 0' }}>
              {/* SVG Overlay for Links - MUST be pointer-events-none to allow clicking nodes through it */}
              <svg className="overflow-visible absolute top-0 left-0 pointer-events-none" style={{ width: '100%', height: '100%' }}>
                <defs><marker id="arrow" viewBox="0 0 10 10" refX="10" refY="5" markerWidth="6" markerHeight="6" orient="auto"><path d="M 0 0 L 10 5 L 0 10 z" fill="#64748b"/></marker></defs>
                {links.map(l => <ProcessLinkComponent key={l.id} link={l} steps={steps} />)}
                {ghostLink.current && <path d={`M ${ghostLink.current.x1} ${ghostLink.current.y1} L ${ghostLink.current.x2} ${ghostLink.current.y2}`} stroke="#94a3b8" strokeWidth="2" strokeDasharray="5,5" fill="none"/>}
              </svg>

              {/* Nodes Layer */}
              {steps.map(step => (
                  <div key={step.id} className="relative">
                      <NodeComponent step={step} isSelected={selectedId === step.id} />
                      {showHeatmap && step.position && (
                          <div 
                            className={`absolute pointer-events-none z-30 inset-0 rounded-base border-2 ${getHeatmapColor(step.id)}`}
                            style={{ 
                                left: step.position.x, 
                                top: step.position.y,
                                width: `${NODE_WIDTH}px`, 
                                height: `${NODE_HEIGHT}px`,
                                backdropFilter: 'blur(1px)'
                            }}
                          >
                              <div className="absolute -top-6 left-1/2 -translate-x-1/2 bg-black text-white text-[10px] font-bold px-2 py-0.5 rounded-full whitespace-nowrap shadow-lg">
                                  Avg: {Math.floor(Math.random() * 200)}ms
                              </div>
                          </div>
                      )}
                  </div>
              ))}
           </div>
        </div>

        {/* 4. Properties (Rigid Right Panel) */}
        {selectedStep && (
          <div className="w-72 border-l border-default bg-panel overflow-y-auto shadow-xl z-20">
             <PropertiesPanel step={selectedStep} onUpdate={updateStep} onDelete={deleteStep} roles={roles} />
          </div>
        )}
      </div>

      {/* Context Menu Overlay */}
      {contextMenu && (
        <CanvasContextMenu 
          position={contextMenu.position} 
          targetId={contextMenu.targetId} 
          onClose={() => setContextMenu(null)}
          onAction={handleMenuAction}
        />
      )}
    </div>
  );
};

import React, { memo } from 'react';
import { Handle, Position, NodeProps } from 'reactflow';
import { ProcessStep } from '../../types';
import { getStepTypeMetadata } from './designerUtils';
import { FunctionSquare, RefreshCw, Code, AlertCircle, Layers } from 'lucide-react';

// Define the custom data interface
interface CustomNodeData {
  step: ProcessStep;
  // We can pass visual flags via data if needed, but 'selected' comes from props
}

// React Flow passes `selected` as a direct prop to custom nodes
export const NodeComponent = memo(({ data, selected }: NodeProps<CustomNodeData>) => {
  const { step } = data;
  const { icon: Icon, color } = getStepTypeMetadata(step.type);

  // Logic Detection
  const hasRule = !!step.businessRuleId;
  const hasScript = !!step.onEntryAction || !!step.onExitAction;
  const hasRetry = step.retryPolicy?.enabled;
  const isLoop = step.isMultiInstance;
  const missingConfig = step.type === 'service-task' && !step.data?.url;

  return (
    <div 
      className={`w-[200px] h-[80px] bg-panel border flex flex-col shadow-sm transition-shadow select-none group ${
        selected 
          ? 'border-active ring-2 ring-blue-500/20 shadow-md' 
          : 'border-default hover:border-tertiary'
      }`} 
      style={{ 
        borderRadius: 'var(--radius-base)',
      }}
    >
      {/* React Flow Handles */}
      <Handle 
        type="target" 
        position={Position.Left} 
        className="!bg-slate-400 !border-white !w-2.5 !h-2.5 !-left-1.5 hover:!bg-blue-600 transition-colors" 
      />

      {/* Main Body */}
      <div className="flex items-center gap-3 px-3 pt-3 pb-1 flex-1 overflow-hidden pointer-events-none">
        <div className={`w-8 h-8 flex items-center justify-center rounded-base bg-subtle border border-default relative shrink-0`}>
          <Icon size={16} className={color.replace('text-', 'text-opacity-80 text-')} />
          {missingConfig && (
             <div className="absolute -top-1 -right-1 bg-white rounded-full">
                <AlertCircle size={12} className="text-rose-500 fill-white"/>
             </div>
          )}
        </div>

        <div className="flex-1 min-w-0">
          <p className="text-[12px] font-bold text-primary truncate leading-tight">
            {step.name}
          </p>
          <p className="text-[10px] text-secondary uppercase tracking-wide truncate mt-0.5">
            {step.type.replace(/-/g, ' ')}
          </p>
        </div>
      </div>

      {/* Logic Badges Bar */}
      {(hasRule || hasScript || hasRetry || isLoop) && (
          <div className="px-3 pb-2 flex gap-1.5 items-center pointer-events-none">
              {hasRule && (
                  <div className="flex items-center gap-0.5 px-1 py-0.5 bg-indigo-50 border border-indigo-100 rounded-[2px] text-[8px] font-bold text-indigo-700">
                      <FunctionSquare size={8} /> RULE
                  </div>
              )}
              {hasScript && (
                  <div className="flex items-center gap-0.5 px-1 py-0.5 bg-amber-50 border border-amber-100 rounded-[2px] text-[8px] font-bold text-amber-700">
                      <Code size={8} /> FN
                  </div>
              )}
              {hasRetry && (
                  <div className="flex items-center gap-0.5 px-1 py-0.5 bg-blue-50 border border-blue-100 rounded-[2px] text-[8px] font-bold text-blue-700">
                      <RefreshCw size={8} /> {step.retryPolicy?.maxAttempts}x
                  </div>
              )}
              {isLoop && (
                  <div className="ml-auto text-secondary">
                      <Layers size={10} />
                  </div>
              )}
          </div>
      )}

      <Handle 
        type="source" 
        position={Position.Right} 
        className="!bg-slate-400 !border-white !w-2.5 !h-2.5 !-right-1.5 hover:!bg-blue-600 transition-colors" 
      />
    </div>
  );
});

import React, { useState, useRef, useMemo, useEffect, useCallback } from 'react';
import ReactFlow, { 
  Node, 
  Edge, 
  useNodesState, 
  useEdgesState, 
  Controls, 
  Background, 
  MiniMap,
  Connection,
  addEdge,
  MarkerType,
  BackgroundVariant,
  NodeChange,
  EdgeChange,
  applyNodeChanges,
  applyEdgeChanges,
  ReactFlowProvider,
  useReactFlow
} from 'reactflow';
import { ProcessStep, ProcessLink, ProcessStepType } from '../types';
import { useBPM } from '../contexts/BPMContext';
import { 
  Save, Sparkles, Cpu, LayoutPanelLeft, Trash2, Thermometer
} from 'lucide-react';
import { PaletteSidebar } from './designer/PaletteSidebar';
import { NodeComponent } from './designer/NodeComponent';
import { PropertiesPanel } from './designer/PropertiesPanel';
import { CanvasContextMenu } from './designer/CanvasContextMenu';
import { getStepTypeMetadata } from './designer/designerUtils';
import { generateProcessWorkflow } from '../services/geminiService';

// Define the Node Types for React Flow
const nodeTypes = {
  custom: NodeComponent
};

const GRID_SIZE = 20;

// Internal wrapper to use React Flow Hooks
const DesignerFlow = ({ 
  nodes, 
  edges, 
  onNodesChange, 
  onEdgesChange, 
  onConnect, 
  onNodeClick, 
  onPaneClick,
  onContextMenu 
}: any) => {
  return (
    <ReactFlow
      nodes={nodes}
      edges={edges}
      onNodesChange={onNodesChange}
      onEdgesChange={onEdgesChange}
      onConnect={onConnect}
      onNodeClick={onNodeClick}
      onPaneClick={onPaneClick}
      onContextMenu={onContextMenu}
      nodeTypes={nodeTypes}
      snapToGrid={true}
      snapGrid={[GRID_SIZE, GRID_SIZE]}
      fitView
      attributionPosition="bottom-right"
      defaultEdgeOptions={{
        type: 'smoothstep', // 'smoothstep', 'step', 'default' (bezier)
        animated: false,
        style: { stroke: '#64748b', strokeWidth: 2 },
        markerEnd: {
          type: MarkerType.ArrowClosed,
          color: '#64748b',
        },
      }}
    >
      <Background color="#cbd5e1" gap={GRID_SIZE} variant={BackgroundVariant.Dots} />
      <Controls className="bg-white border border-slate-200 shadow-sm rounded-base text-slate-600" />
      <MiniMap 
        className="border border-slate-200 shadow-sm rounded-base" 
        nodeColor="#e2e8f0" 
        maskColor="rgb(248, 250, 252, 0.7)"
      />
    </ReactFlow>
  );
};

export const ProcessDesigner: React.FC = () => {
  const { deployProcess, roles, addNotification, designerDraft, setDesignerDraft, navigateTo } = useBPM();
  const [processName, setProcessName] = useState('Strategic Workflow');

  // React Flow State
  const [nodes, setNodes] = useNodesState([]);
  const [edges, setEdges] = useEdgesState([]);

  const [selectedNodeId, setSelectedNodeId] = useState<string | null>(null);

  // Context Menu State
  const [contextMenu, setContextMenu] = useState<{ position: { x: number; y: number }, targetId: string | null } | null>(null);

  // UI State
  const [paletteOpen, setPaletteOpen] = useState(true);
  const [aiPrompt, setAiPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [showHeatmap, setShowHeatmap] = useState(false); // Placeholder for future heatmap overlay

  // Sync Draft -> Flow State (Initial Load)
  useEffect(() => {
    if (designerDraft) {
      const initialNodes: Node[] = designerDraft.steps.map(s => ({
        id: s.id,
        type: 'custom',
        position: s.position || { x: 0, y: 0 },
        data: { step: s }
      }));

      const initialEdges: Edge[] = designerDraft.links.map(l => ({
        id: l.id,
        source: l.sourceId,
        target: l.targetId,
        type: 'smoothstep'
      }));

      setNodes(initialNodes);
      setEdges(initialEdges);
    }
  }, []); // Only runs once on mount, assumes Draft is loaded

  // Sync Flow State -> Draft (Persistence)
  useEffect(() => {
    const steps: ProcessStep[] = nodes.map(n => ({
      ...n.data.step,
      position: n.position,
      id: n.id // Ensure ID sync
    }));

    const links: ProcessLink[] = edges.map(e => ({
      id: e.id,
      sourceId: e.source,
      targetId: e.target,
      label: e.label as string
    }));

    setDesignerDraft({ steps, links });
  }, [nodes, edges, setDesignerDraft]);

  // --- Handlers ---

  const onConnect = useCallback((params: Connection) => setEdges((eds) => addEdge(params, eds)), [setEdges]);

  const addNode = useCallback((type: ProcessStepType, position?: { x: number, y: number }) => {
    const metadata = getStepTypeMetadata(type);
    const id = `node-${Date.now()}`;

    const newStep: ProcessStep = {
      id,
      name: metadata.defaultName,
      type,
      description: '',
      requiredSkills: metadata.defaultSkills || [],
      data: {}
    };

    const newNode: Node = {
      id,
      type: 'custom',
      position: position || { x: 250, y: 250 }, // Default center-ish or from context menu
      data: { step: newStep }
    };

    setNodes((nds) => nds.concat(newNode));
    setSelectedNodeId(id);
  }, [setNodes]);

  const updateSelectedStep = useCallback((updatedStep: ProcessStep) => {
    setNodes((nds) => nds.map((n) => {
      if (n.id === updatedStep.id) {
        return { ...n, data: { ...n.data, step: updatedStep } };
      }
      return n;
    }));
  }, [setNodes]);

  const deleteNode = useCallback((id: string) => {
    setNodes((nds) => nds.filter((n) => n.id !== id));
    setEdges((eds) => eds.filter((e) => e.source !== id && e.target !== id));
    setSelectedNodeId(null);
  }, [setNodes, setEdges]);

  const handleDeploy = async () => {
    const steps: ProcessStep[] = nodes.map(n => ({
        ...n.data.step,
        position: n.position,
        nextStepIds: edges.filter(e => e.source === n.id).map(e => e.target)
    }));

    const links: ProcessLink[] = edges.map(e => ({
        id: e.id,
        sourceId: e.source,
        targetId: e.target
    }));

    await deployProcess({ 
        name: processName, 
        steps, 
        links, 
        isActive: true, 
        version: 1 
    });
    addNotification('success', 'Process definition deployed successfully.');
  };

  const handleClear = () => {
    if(window.confirm('Clear current design?')) {
        setNodes([]);
        setEdges([]);
        setSelectedNodeId(null);
    }
  };

  const handleAiGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!aiPrompt.trim()) return;
    setIsGenerating(true);
    try {
      const generatedSteps = await generateProcessWorkflow(aiPrompt);
      if (generatedSteps && generatedSteps.length > 0) {
        // Convert to Nodes/Edges
        const newNodes: Node[] = generatedSteps.map(s => ({
            id: s.id,
            type: 'custom',
            position: s.position || { x: 0, y: 0 },
            data: { step: s }
        }));

        const newEdges: Edge[] = [];
        for(let i=0; i < generatedSteps.length - 1; i++) {
            newEdges.push({ 
                id: `link-auto-${i}`, 
                source: generatedSteps[i].id, 
                target: generatedSteps[i+1].id,
                type: 'smoothstep'
            });
        }

        setNodes(newNodes);
        setEdges(newEdges);
        addNotification('success', 'Model synthesized.');
        setAiPrompt('');
      }
    } catch (err) { addNotification('error', 'Generation failure.'); } finally { setIsGenerating(false); }
  };

  const handleSimulation = () => {
    if (nodes.length === 0) {
      addNotification('error', 'Canvas is empty. Add steps to simulate.');
      return;
    }
    navigateTo('simulation-report');
  };

  // --- Context Menu ---
  const onContextMenu = useCallback((event: React.MouseEvent, node?: Node) => {
    event.preventDefault();
    setContextMenu({
      position: { x: event.clientX, y: event.clientY },
      targetId: node ? node.id : null,
    });
  }, []);

  const handleMenuAction = (action: string, payload?: any) => {
    if (!contextMenu) return;
    const { targetId, position } = contextMenu;

    switch (action) {
      case 'delete':
        if (targetId) deleteNode(targetId);
        break;
      case 'duplicate':
        if (targetId) {
          const original = nodes.find(n => n.id === targetId);
          if (original) {
            const id = `node-${Date.now()}`;
            const newNode = {
              ...original,
              id,
              position: { x: original.position.x + 20, y: original.position.y + 20 },
              data: { step: { ...original.data.step, id, name: `${original.data.step.name} (Copy)` } }
            };
            setNodes(nds => nds.concat(newNode));
          }
        }
        break;
      case 'add-node':
        // Calculate React Flow world position from screen position
        // This is complex without access to the ReactFlow instance `screenToFlowPosition`.
        // For simplicity, we'll place it near center or adjust if we wrap this in ReactFlowProvider.
        // Assuming payload is the type string
        addNode(payload, undefined); 
        break;
      case 'clear-canvas':
        handleClear();
        break;
    }
    setContextMenu(null);
  };

  // derived selected step
  const selectedStep = useMemo(() => {
    const node = nodes.find(n => n.id === selectedNodeId);
    return node ? node.data.step : undefined;
  }, [selectedNodeId, nodes]);

  return (
    <ReactFlowProvider>
      <div className="h-[calc(100vh-100px)] flex flex-col bg-panel border border-default rounded-base shadow-sm overflow-hidden">
        {/* 1. Rigid Toolbar */}
        <div className="h-header bg-subtle border-b border-default flex items-center justify-between px-3 shrink-0">
           <div className="flex items-center gap-3">
              <button onClick={() => setPaletteOpen(!paletteOpen)} className={`p-1 rounded-base hover:bg-white border border-transparent hover:border-subtle ${paletteOpen ? 'text-blue-600' : 'text-secondary'}`}><LayoutPanelLeft size={16}/></button>
              <div className="h-4 w-px bg-default"></div>
              <input className="bg-transparent text-sm font-bold text-primary w-48 outline-none" value={processName} onChange={e => setProcessName(e.target.value)} />
           </div>
           <div className="flex items-center gap-2">
              <input className="h-7 w-64 bg-panel border border-default rounded-base px-2 text-xs" placeholder="Describe workflow for AI generation..." value={aiPrompt} onChange={e => setAiPrompt(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleAiGenerate(e)} disabled={isGenerating}/>
              <button className="p-1 text-secondary hover:text-rose-600" onClick={handleClear} title="Clear Canvas"><Trash2 size={16}/></button>

              <div className="h-4 w-px bg-default mx-1"></div>

              <button 
                  onClick={() => setShowHeatmap(!showHeatmap)} 
                  className={`p-1 rounded-base transition-colors ${showHeatmap ? 'bg-rose-100 text-rose-600' : 'text-secondary hover:text-primary'}`} 
                  title="Toggle Heatmap"
              >
                  <Thermometer size={16}/>
              </button>

              <button onClick={handleSimulation} className="flex items-center gap-1 px-3 py-1 bg-indigo-600 text-white rounded-base text-xs hover:bg-indigo-700 shadow-sm"><Cpu size={14}/> Simulate</button>
              <button onClick={handleDeploy} className="flex items-center gap-1 px-3 py-1 bg-brand-slate text-white rounded-base text-xs hover:bg-slate-900 shadow-sm"><Save size={14}/> Save</button>
           </div>
        </div>

        <div className="flex-1 flex overflow-hidden">
          {/* 2. Palette (Standard Sidebar) */}
          {paletteOpen && (
            <div className="w-56 border-r border-default bg-subtle overflow-y-auto z-10">
               <PaletteSidebar onAddNode={(type) => addNode(type)} />
            </div>
          )}

          {/* 3. React Flow Canvas */}
          <div className="flex-1 h-full bg-canvas relative">
             <DesignerFlow 
                nodes={nodes}
                edges={edges}
                onNodesChange={useCallback((changes: NodeChange[]) => setNodes(nds => applyNodeChanges(changes, nds)), [setNodes])}
                onEdgesChange={useCallback((changes: EdgeChange[]) => setEdges(eds => applyEdgeChanges(changes, eds)), [setEdges])}
                onConnect={onConnect}
                onNodeClick={(_: any, node: Node) => setSelectedNodeId(node.id)}
                onPaneClick={() => setSelectedNodeId(null)}
                onContextMenu={onContextMenu}
             />
          </div>

          {/* 4. Properties (Rigid Right Panel) */}
          {selectedStep && (
            <div className="w-72 border-l border-default bg-panel overflow-y-auto shadow-xl z-20">
               <PropertiesPanel step={selectedStep} onUpdate={updateSelectedStep} onDelete={deleteNode} roles={roles} />
            </div>
          )}
        </div>

        {/* Context Menu Overlay */}
        {contextMenu && (
          <CanvasContextMenu 
            position={contextMenu.position} 
            targetId={contextMenu.targetId} 
            onClose={() => setContextMenu(null)}
            onAction={handleMenuAction}
          />
        )}
      </div>
    </ReactFlowProvider>
  );
};

import React, { useState, useRef, useMemo, useEffect, useCallback } from 'react';
