    setNodes((nds) => nds.concat(newNode));
    setSelectedNodeId(id);
  }, [setNodes]);

  const updateSelectedStep = useCallback((updatedStep: ProcessStep) => {
    setNodes((nds) => nds.map((n) => {
      if (n.id === updatedStep.id) {
