               key={ft.type} 
               onClick={() => addField(ft.type)}
               className="flex items-center gap-3 p-3 bg-white border border-slate-200 rounded-sm hover:border-blue-400 hover:shadow-sm transition-all text-left group"
             >
               <ft.icon size={16} className="text-slate-500 group-hover:text-blue-600"/>
               <span className="text-xs font-bold text-slate-700">{ft.label}</span>
               <Plus size={14} className="ml-auto text-slate-300 group-hover:text-blue-500"/>
             </button>
           ))}
        </div>

        {/* Center: Canvas (Responsive & Full Width) */}
        <div className="flex-1 bg-slate-100 border-x border-dashed border-slate-200 p-6 overflow-y-auto">
           <div className="bg-white shadow-sm min-h-full w-full mx-auto rounded-sm p-8 border border-slate-200 flex flex-col">
              <div className="mb-8 border-b border-slate-100 pb-6">
                 <input 
                   className="text-3xl font-bold text-slate-900 w-full outline-none placeholder:text-slate-300" 
                   value={formDef.name} 
                   onChange={e => setFormDef({...formDef, name: e.target.value})}
                   placeholder="Form Title"
                 />
                 <input 
                   className="text-sm text-slate-500 w-full outline-none mt-2" 
                   value={formDef.description} 
                   onChange={e => setFormDef({...formDef, description: e.target.value})}
                   placeholder="Enter form description and instructions..."
                 />
              </div>

              {formDef.fields.length === 0 ? (
                <div className="flex flex-col items-center justify-center py-20 text-slate-300 flex-1 border-2 border-dashed border-slate-100 rounded-sm">
                   <Type size={48} className="mb-4 opacity-50"/>
                   <p className="text-sm font-medium">Form canvas is empty. Add fields from the library.</p>
                </div>
              ) : (
                <div className="space-y-6 flex-1">
                   {formDef.fields.map(field => (
                     <div 
