                       className={`relative group p-6 rounded-sm border transition-all cursor-pointer ${selectedFieldId === field.id ? 'border-blue-500 bg-blue-50/10 ring-1 ring-blue-500/20' : 'border-slate-200 hover:border-slate-300 hover:bg-slate-50'}`}
                     >
                        <div className="flex items-center justify-between mb-2">
                           <label className="text-sm font-bold text-slate-800 flex items-center gap-2">
                             {field.label} 
                             {field.required && <span className="text-rose-500" title="Required">*</span>}
                             {field.visibility && <EyeOff size={14} className="text-amber-500" title="Conditional Visibility"/>}
                             {field.validation?.pattern && <AlertTriangle size={14} className="text-blue-500" title="Custom Validation"/>}
                           </label>
                           <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                              <button onClick={(e) => { e.stopPropagation(); deleteField(field.id); }} className="text-rose-500 hover:bg-rose-100 p-1.5 rounded"><Trash2 size={16}/></button>
                           </div>
                        </div>

                        {/* Interactive Preview of the Field */}
                        <div className="w-full pointer-events-none">
                            {field.type === 'textarea' ? (
                                <div className="h-24 bg-slate-50 border border-slate-300 rounded-sm w-full p-3 text-sm text-slate-400">
                                    {field.defaultValue || field.placeholder || `Enter ${field.label}...`}
                                </div>
                            ) : field.type === 'checkbox' ? (
                                <div className="flex items-center gap-2">
                                    <div className={`w-4 h-4 border rounded-sm ${field.defaultValue === 'true' ? 'bg-blue-600 border-blue-600' : 'border-slate-300 bg-white'}`}></div>
                                    <span className="text-sm text-slate-600">{field.placeholder || 'Yes'}</span>
                                </div>
                            ) : field.type === 'signature' ? (
                                <div className="h-16 bg-slate-50 border border-slate-300 border-dashed rounded-sm w-full flex items-center justify-center text-xs text-slate-400 gap-2">
                                    <PenTool size={14}/> Signature Pad Area
                                </div>
                            ) : (
                                <div className="h-10 bg-slate-50 border border-slate-300 rounded-sm w-full flex items-center px-3 text-sm text-slate-400">
                                    {field.defaultValue || field.placeholder || `Enter ${field.label}...`}
                                </div>
                            )}
                        </div>

                        {field.helpText && (
                            <p className="mt-1 text-xs text-slate-500">{field.helpText}</p>
