import React, { useState, useEffect } from 'react';
import { useBPM } from '../contexts/BPMContext';
import { FormDefinition, FormField, FormFieldType, FormValidation, FormVisibilityRule } from '../types';
import { FormPageLayout } from './shared/PageTemplates';
import { NexFormGroup, NexButton } from './shared/NexUI';
import { 
  Type, Hash, Calendar, CheckSquare, List, AlignLeft, FileText, 
  Trash2, GripVertical, Settings, Plus, Info, Upload, PenTool, EyeOff, AlertTriangle,
  PanelLeft, PanelRight, Smartphone, Monitor, Maximize
} from 'lucide-react';
import { produce } from 'immer';

const FIELD_TYPES: { type: FormFieldType; icon: React.ElementType; label: string }[] = [
  { type: 'text', icon: Type, label: 'Text Field' },
  { type: 'number', icon: Hash, label: 'Number' },
  { type: 'textarea', icon: AlignLeft, label: 'Text Area' },
  { type: 'date', icon: Calendar, label: 'Date Picker' },
  { type: 'select', icon: List, label: 'Dropdown' },
  { type: 'checkbox', icon: CheckSquare, label: 'Checkbox' },
  { type: 'email', icon: FileText, label: 'Email' },
  { type: 'file', icon: Upload, label: 'File Upload' },
  { type: 'signature', icon: PenTool, label: 'Signature' }
];

export const FormDesigner: React.FC = () => {
  const { navigateTo, saveForm, forms, nav } = useBPM();
  const [formDef, setFormDef] = useState<FormDefinition>({
    id: `form-${Date.now()}`,
    name: 'New Form',
    description: '',
    fields: [],
    version: 1,
    lastModified: new Date().toISOString()
  });
  const [selectedFieldId, setSelectedFieldId] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<'general' | 'validation' | 'logic'>('general');

  // UI State
  const [leftOpen, setLeftOpen] = useState(true);
  const [rightOpen, setRightOpen] = useState(true);
  const [previewMode, setPreviewMode] = useState<'desktop' | 'mobile'>('desktop');

  useEffect(() => {
    if (nav.selectedId) {
      const existing = forms.find(f => f.id === nav.selectedId);
      if (existing) setFormDef(existing);
    }
  }, [nav.selectedId, forms]);

  const addField = (type: FormFieldType) => {
    const newField: FormField = {
      id: `f-${Date.now()}`,
      type,
      label: `New ${type}`,
      key: `field_${Date.now()}`,
      required: false,
      placeholder: '',
      options: type === 'select' ? ['Option 1', 'Option 2'] : undefined
    };
    setFormDef(produce(draft => { draft.fields.push(newField); }));
    setSelectedFieldId(newField.id);
    setActiveTab('general');
    // Auto-open property panel if closed
    if(!rightOpen) setRightOpen(true);
  };

  const updateField = (id: string, updates: Partial<FormField>) => {
    setFormDef(produce(draft => {
      const field = draft.fields.find(f => f.id === id);
      if (field) Object.assign(field, updates);
    }));
  };

  const deleteField = (id: string) => {
    setFormDef(produce(draft => { draft.fields = draft.fields.filter(f => f.id !== id); }));
    setSelectedFieldId(null);
  };

  const handleSave = async () => {
    await saveForm({ ...formDef, lastModified: new Date().toISOString() });
    navigateTo('forms');
  };

  const selectedField = formDef.fields.find(f => f.id === selectedFieldId);

  // --- Helpers for Complex Objects ---
  const updateValidation = (val: Partial<FormValidation>) => {
      if (!selectedField) return;
      const current = selectedField.validation || {};
      updateField(selectedField.id, { validation: { ...current, ...val } });
  };

  const updateVisibility = (rule: Partial<FormVisibilityRule>) => {
      if (!selectedField) return;
      const current = selectedField.visibility || { targetFieldKey: '', operator: 'eq' };
      updateField(selectedField.id, { visibility: { ...current, ...rule } as FormVisibilityRule });
  };

  const toggleVisibilityRule = (enabled: boolean) => {
      if (!selectedField) return;
      if (enabled) {
          updateField(selectedField.id, { visibility: { targetFieldKey: '', operator: 'eq', value: '' } });
      } else {
          updateField(selectedField.id, { visibility: undefined });
      }
  }

  return (
    <FormPageLayout title={formDef.name || "Form Designer"} onBack={() => navigateTo('forms')} onSave={handleSave} saveLabel="Publish Form" fullWidth>
      <div className="flex h-full relative overflow-hidden">

        {/* Left: Palette */}
        <div className={`border-r border-slate-200 bg-slate-50 flex flex-col transition-all duration-300 ${leftOpen ? 'w-[240px]' : 'w-0 overflow-hidden'}`}>
           <div className="p-4 border-b border-slate-200 flex items-center justify-between shrink-0">
              <h3 className="text-xs font-bold text-slate-500 uppercase">Field Library</h3>
              <button onClick={() => setLeftOpen(false)} className="text-slate-400 hover:text-slate-600"><PanelLeft size={14}/></button>
           </div>
           <div className="flex-1 overflow-y-auto p-4 space-y-2">
             {FIELD_TYPES.map(ft => (
               <button 
                 key={ft.type} 
                 onClick={() => addField(ft.type)}
                 className="flex items-center gap-3 p-3 bg-white border border-slate-200 rounded-sm hover:border-blue-400 hover:shadow-sm transition-all text-left w-full group"
               >
                 <ft.icon size={16} className="text-slate-500 group-hover:text-blue-600"/>
                 <span className="text-xs font-bold text-slate-700">{ft.label}</span>
                 <Plus size={14} className="ml-auto text-slate-300 group-hover:text-blue-500"/>
               </button>
             ))}
           </div>
        </div>

        {/* Center: Canvas */}
        <div className="flex-1 bg-slate-100 flex flex-col min-w-0">
           {/* Canvas Toolbar */}
           <div className="h-10 bg-white border-b border-slate-200 flex items-center justify-between px-4 shrink-0">
              <div className="flex items-center gap-2">
                 {!leftOpen && <button onClick={() => setLeftOpen(true)} className="p-1.5 hover:bg-slate-50 rounded text-slate-500" title="Open Library"><PanelLeft size={16}/></button>}
              </div>
              <div className="flex items-center gap-2 bg-slate-100 p-1 rounded-sm">
                 <button onClick={() => setPreviewMode('desktop')} className={`p-1.5 rounded-sm transition-all ${previewMode === 'desktop' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-400 hover:text-slate-600'}`}><Monitor size={14}/></button>
                 <button onClick={() => setPreviewMode('mobile')} className={`p-1.5 rounded-sm transition-all ${previewMode === 'mobile' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-400 hover:text-slate-600'}`}><Smartphone size={14}/></button>
              </div>
              <div className="flex items-center gap-2">
                 {!rightOpen && <button onClick={() => setRightOpen(true)} className="p-1.5 hover:bg-slate-50 rounded text-slate-500" title="Open Properties"><PanelRight size={16}/></button>}
              </div>
           </div>

           {/* Canvas Scroll Area */}
           <div className="flex-1 overflow-y-auto p-8 relative">
              <div className={`bg-white shadow-sm min-h-full mx-auto rounded-sm border border-slate-200 flex flex-col transition-all duration-300 ${previewMode === 'mobile' ? 'max-w-[375px] border-x-4 border-x-slate-800 my-4' : 'w-full max-w-4xl p-8'}`}>

                 <div className={`mb-8 border-b border-slate-100 pb-6 ${previewMode === 'mobile' ? 'p-6' : ''}`}>
                    <input 
                      className="text-2xl font-bold text-slate-900 w-full outline-none placeholder:text-slate-300 bg-transparent" 
                      value={formDef.name} 
                      onChange={e => setFormDef({...formDef, name: e.target.value})}
                      placeholder="Form Title"
                    />
                    <input 
                      className="text-sm text-slate-500 w-full outline-none mt-2 bg-transparent" 
                      value={formDef.description} 
                      onChange={e => setFormDef({...formDef, description: e.target.value})}
                      placeholder="Enter form description..."
                    />
                 </div>

                 {formDef.fields.length === 0 ? (
                   <div className="flex flex-col items-center justify-center py-20 text-slate-300 flex-1 border-2 border-dashed border-slate-100 rounded-sm m-4">
                      <Type size={48} className="mb-4 opacity-50"/>
                      <p className="text-sm font-medium">Form canvas is empty.</p>
                      <button onClick={() => setLeftOpen(true)} className="mt-2 text-xs text-blue-500 hover:underline">Open Library</button>
                   </div>
                 ) : (
                   <div className={`space-y-6 flex-1 ${previewMode === 'mobile' ? 'px-4 pb-4' : ''}`}>
                      {formDef.fields.map(field => (
                        <div 
                          key={field.id} 
                          onClick={() => { setSelectedFieldId(field.id); if(!rightOpen) setRightOpen(true); }}
                          className={`relative group rounded-sm border transition-all cursor-pointer ${selectedFieldId === field.id ? 'border-blue-500 bg-blue-50/10 ring-1 ring-blue-500/20' : 'border-transparent hover:border-slate-200 hover:bg-slate-50'} ${previewMode === 'mobile' ? 'p-3' : 'p-4'}`}
                        >
                           <div className="flex items-center justify-between mb-2">
                              <label className="text-sm font-bold text-slate-800 flex items-center gap-2">
                                {field.label} 
                                {field.required && <span className="text-rose-500" title="Required">*</span>}
                                {field.visibility && <EyeOff size={14} className="text-amber-500" title="Conditional Visibility"/>}
                                {field.validation?.pattern && <AlertTriangle size={14} className="text-blue-500" title="Custom Validation"/>}
                              </label>
                              <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                                 <button onClick={(e) => { e.stopPropagation(); deleteField(field.id); }} className="text-rose-500 hover:bg-rose-100 p-1.5 rounded"><Trash2 size={14}/></button>
                              </div>
                           </div>

                           {/* Interactive Preview of the Field */}
                           <div className="w-full pointer-events-none">
                               {field.type === 'textarea' ? (
                                   <div className="h-20 bg-slate-50 border border-slate-300 rounded-sm w-full p-2 text-sm text-slate-400">
                                       {field.defaultValue || field.placeholder || `Enter ${field.label}...`}
                                   </div>
                               ) : field.type === 'checkbox' ? (
                                   <div className="flex items-center gap-2">
                                       <div className={`w-4 h-4 border rounded-sm ${field.defaultValue === 'true' ? 'bg-blue-600 border-blue-600' : 'border-slate-300 bg-white'}`}></div>
                                       <span className="text-sm text-slate-600">{field.placeholder || 'Yes'}</span>
                                   </div>
                               ) : field.type === 'signature' ? (
                                   <div className="h-12 bg-slate-50 border border-slate-300 border-dashed rounded-sm w-full flex items-center justify-center text-xs text-slate-400 gap-2">
                                       <PenTool size={14}/> Signature
                                   </div>
                               ) : (
                                   <div className="h-9 bg-slate-50 border border-slate-300 rounded-sm w-full flex items-center px-3 text-sm text-slate-400">
                                       {field.defaultValue || field.placeholder || `Enter ${field.label}...`}
                                   </div>
                               )}
                           </div>

                           {field.helpText && (
                               <p className="mt-1 text-xs text-slate-500">{field.helpText}</p>
                           )}

                           {field.id === selectedFieldId && <div className="absolute -left-[1px] top-0 bottom-0 w-1 bg-blue-500 rounded-l-sm"></div>}
                        </div>
                      ))}
                   </div>
                 )}
              </div>
           </div>
        </div>

        {/* Right: Properties */}
        <div className={`border-l border-slate-200 bg-white flex flex-col shadow-xl z-10 shrink-0 transition-all duration-300 ${rightOpen ? 'w-[320px]' : 'w-0 overflow-hidden'}`}>
           <div className="p-4 border-b border-slate-100 bg-slate-50 flex items-center justify-between shrink-0">
              <h3 className="text-xs font-bold text-slate-800 uppercase flex items-center gap-2">
                 <Settings size={14}/> Properties
              </h3>
              <button onClick={() => setRightOpen(false)} className="text-slate-400 hover:text-slate-600"><PanelRight size={14}/></button>
           </div>

           {selectedField ? (
             <div className="flex flex-col h-full overflow-hidden">
                <div className="flex border-b border-slate-200">
                    <button onClick={() => setActiveTab('general')} className={`flex-1 py-3 text-[10px] font-bold uppercase transition-all ${activeTab === 'general' ? 'text-blue-600 border-b-2 border-blue-600 bg-white' : 'text-slate-500 bg-slate-50 hover:text-slate-800'}`}>General</button>
                    <button onClick={() => setActiveTab('validation')} className={`flex-1 py-3 text-[10px] font-bold uppercase transition-all ${activeTab === 'validation' ? 'text-blue-600 border-b-2 border-blue-600 bg-white' : 'text-slate-500 bg-slate-50 hover:text-slate-800'}`}>Rules</button>
                    <button onClick={() => setActiveTab('logic')} className={`flex-1 py-3 text-[10px] font-bold uppercase transition-all ${activeTab === 'logic' ? 'text-blue-600 border-b-2 border-blue-600 bg-white' : 'text-slate-500 bg-slate-50 hover:text-slate-800'}`}>Logic</button>
                </div>

                <div className="p-5 space-y-5 overflow-y-auto flex-1">
                    {activeTab === 'general' && (
                        <>
                            <NexFormGroup label="Field Label">
                                <input className="prop-input font-bold" value={selectedField.label} onChange={e => updateField(selectedField.id, { label: e.target.value })} />
                            </NexFormGroup>

                            <NexFormGroup label="Variable Key" helpText="Unique ID for data binding (e.g. 'expenseAmount')">
                                <input className="prop-input font-mono text-xs" value={selectedField.key} onChange={e => updateField(selectedField.id, { key: e.target.value })} />
                            </NexFormGroup>

                            <div className="grid grid-cols-2 gap-4">
                                <NexFormGroup label="Placeholder">
                                    <input className="prop-input" value={selectedField.placeholder || ''} onChange={e => updateField(selectedField.id, { placeholder: e.target.value })} />
                                </NexFormGroup>
                                <NexFormGroup label="Default Value">
                                    <input className="prop-input" value={selectedField.defaultValue || ''} onChange={e => updateField(selectedField.id, { defaultValue: e.target.value })} />
                                </NexFormGroup>
                            </div>

                            <NexFormGroup label="Help Text" helpText="Instructions displayed below the field">
                                <input className="prop-input" value={selectedField.helpText || ''} onChange={e => updateField(selectedField.id, { helpText: e.target.value })} />
                            </NexFormGroup>

                            {selectedField.type === 'select' && (
                                <NexFormGroup label="Options (Comma Separated)">
                                    <textarea 
                                        className="prop-input h-24 font-mono text-xs" 
                                        value={selectedField.options?.join(',')} 
                                        onChange={e => updateField(selectedField.id, { options: e.target.value.split(',').map(s => s.trim()) })} 
                                        placeholder="Option 1, Option 2, Option 3"
                                    />
                                </NexFormGroup>
                            )}

                            <div className="pt-4 border-t border-slate-100">
                                <label className="flex items-center gap-3 cursor-pointer p-2 hover:bg-slate-50 rounded-sm">
                                    <input type="checkbox" checked={selectedField.required} onChange={e => updateField(selectedField.id, { required: e.target.checked })} className="text-blue-600 rounded-sm w-4 h-4" />
                                    <span className="text-sm font-medium text-slate-700">Required Field</span>
                                </label>
                            </div>
                        </>
                    )}

                    {activeTab === 'validation' && (
                        <div className="space-y-5">
                            <p className="text-xs text-slate-500">Define constraints for data integrity.</p>

                            {(selectedField.type === 'number' || selectedField.type === 'text') && (
                                <div className="grid grid-cols-2 gap-4">
                                    <NexFormGroup label="Minimum">
                                        <input type="number" className="prop-input" placeholder={selectedField.type === 'text' ? 'Length' : 'Value'} value={selectedField.validation?.min || ''} onChange={e => updateValidation({ min: parseInt(e.target.value) || undefined })} />
                                    </NexFormGroup>
                                    <NexFormGroup label="Maximum">
                                        <input type="number" className="prop-input" placeholder={selectedField.type === 'text' ? 'Length' : 'Value'} value={selectedField.validation?.max || ''} onChange={e => updateValidation({ max: parseInt(e.target.value) || undefined })} />
                                    </NexFormGroup>
                                </div>
                            )}

                            {(selectedField.type === 'text' || selectedField.type === 'email' || selectedField.type === 'textarea') && (
                                <NexFormGroup label="Regex Pattern" helpText="JavaScript RegExp compatible">
                                    <input className="prop-input font-mono text-xs" placeholder="^[A-Z0-9._%+-]+@[A-Z0-9.-]+$" value={selectedField.validation?.pattern || ''} onChange={e => updateValidation({ pattern: e.target.value })} />
                                </NexFormGroup>
                            )}

                            <NexFormGroup label="Custom Error Message">
                                <textarea className="prop-input h-20 resize-none" placeholder="Please enter a valid value..." value={selectedField.validation?.message || ''} onChange={e => updateValidation({ message: e.target.value })} />
                            </NexFormGroup>
                        </div>
                    )}

                    {activeTab === 'logic' && (
                        <div className="space-y-5">
                            <div className="flex items-center justify-between mb-2">
                                <span className="text-xs font-bold text-slate-700 uppercase">Visibility Logic</span>
                                <label className="relative inline-flex items-center cursor-pointer">
                                    <input type="checkbox" className="sr-only peer" checked={!!selectedField.visibility} onChange={e => toggleVisibilityRule(e.target.checked)} />
                                    <div className="w-9 h-5 bg-slate-200 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-4 after:w-4 after:transition-all peer-checked:bg-blue-600"></div>
                                </label>
                            </div>

                            {selectedField.visibility ? (
                                <div className="p-4 bg-amber-50 border border-amber-200 rounded-sm space-y-4 animate-slide-up">
                                    <NexFormGroup label="Dependent On Field">
                                        <select className="prop-input" value={selectedField.visibility.targetFieldKey} onChange={e => updateVisibility({ targetFieldKey: e.target.value })}>
                                            <option value="">Select Field...</option>
                                            {formDef.fields.filter(f => f.id !== selectedField.id).map(f => (
                                                <option key={f.key} value={f.key}>{f.label} ({f.key})</option>
                                            ))}
                                        </select>
                                    </NexFormGroup>
                                    <div className="grid grid-cols-2 gap-3">
                                        <NexFormGroup label="Operator">
                                            <select className="prop-input" value={selectedField.visibility.operator} onChange={e => updateVisibility({ operator: e.target.value as any })}>
                                                <option value="eq">Equals</option>
                                                <option value="neq">Not Equals</option>
                                                <option value="contains">Contains</option>
                                                <option value="truthy">Is True/Present</option>
                                                <option value="falsy">Is False/Empty</option>
                                            </select>
                                        </NexFormGroup>
                                        {(selectedField.visibility.operator !== 'truthy' && selectedField.visibility.operator !== 'falsy') && (
                                            <NexFormGroup label="Value Match">
                                                <input className="prop-input" value={selectedField.visibility.value || ''} onChange={e => updateVisibility({ value: e.target.value })} />
                                            </NexFormGroup>
                                        )}
                                    </div>
                                    <div className="flex gap-2 text-[10px] text-amber-800 bg-amber-100 p-2 rounded-sm">
                                        <EyeOff size={14} className="shrink-0"/>
                                        <span>Field will be hidden unless the above condition is met.</span>
                                    </div>
                                </div>
                            ) : (
                                <div className="text-center p-6 border border-dashed border-slate-200 rounded-sm text-slate-400 text-xs">
                                    No conditional logic applied.<br/>Field is always visible.
                                </div>
                            )}
                        </div>
                    )}
                </div>
             </div>
           ) : (
             <div className="flex-1 flex flex-col items-center justify-center text-slate-400 p-8 text-center bg-slate-50/50">
                <Settings size={32} className="mb-3 opacity-20"/>
                <p className="text-xs font-bold uppercase tracking-wider">Select a field</p>
                <p className="text-[10px] mt-1">Configure properties here.</p>
             </div>
           )}
        </div>

      </div>
    </FormPageLayout>
  );
};

export enum TaskStatus {
  PENDING = 'Pending',
  CLAIMED = 'Claimed',
  IN_PROGRESS = 'In Progress',
  COMPLETED = 'Completed',
  REJECTED = 'Rejected'
}

export enum TaskPriority {
  LOW = 'Low',
  MEDIUM = 'Medium',
  HIGH = 'High',
  CRITICAL = 'Critical'
}

export enum Permission {
  PROCESS_VIEW = 'process:view',
  PROCESS_DEPLOY = 'process:deploy',
  PROCESS_START = 'process:start',
  TASK_COMPLETE = 'task:complete',
  TASK_OVERRIDE = 'task:override',
  ADMIN_ACCESS = 'admin:access',
  USER_MANAGE = 'user:manage',
  SYSTEM_CONFIG = 'system:config',
  CASE_MANAGE = 'case:manage',
  RULES_MANAGE = 'rules:manage',
  ANALYTICS_VIEW_ALL = 'analytics:view_all'
}

export interface UserRole {
  id: string;
