                                            <NexFormGroup label="Value Match">
                                                <input className="prop-input" value={selectedField.visibility.value || ''} onChange={e => updateField(selectedField.id, { visibility: { ...selectedField.visibility, value: e.target.value } as any })} />
                                            </NexFormGroup>
                                        )}
