// Internal wrapper to use React Flow Hooks
const DesignerFlow = ({ 
  nodes, 
  edges, 
  onNodesChange, 
  onEdgesChange, 
  onConnect, 
  onNodeClick, 
  onPaneClick, 
  onContextMenu, 
  onDrop, 
  onDragOver, 
  onLayout, 
  isValidConnection 
}: any) => {
  return (
    <div className="h-full w-full" onDrop={onDrop} onDragOver={onDragOver}>
      <ReactFlow
        nodes={nodes}
        edges={edges}
        onNodesChange={onNodesChange}
        onEdgesChange={onEdgesChange}
        onConnect={onConnect}
        onNodeClick={onNodeClick}
        onPaneClick={onPaneClick}
        onContextMenu={onContextMenu}
        nodeTypes={nodeTypes}
        edgeTypes={edgeTypes}
        isValidConnection={isValidConnection}
        snapToGrid={true}
        snapGrid={[GRID_SIZE, GRID_SIZE]}
        fitView
        attributionPosition="bottom-right"
        defaultEdgeOptions={{
          type: 'custom', 
          animated: false,
          style: { stroke: '#64748b', strokeWidth: 1.5 },
          markerEnd: {
            type: MarkerType.ArrowClosed,
            color: '#64748b',
          },
        }}
      >
        <Background color="#cbd5e1" gap={GRID_SIZE} variant={BackgroundVariant.Dots} />
        <Controls className="bg-white border border-slate-200 shadow-sm rounded-base text-slate-600" />
        <MiniMap 
          className="border border-slate-200 shadow-sm rounded-base" 
          nodeColor="#e2e8f0" 
          maskColor="rgb(248, 250, 252, 0.7)"
        />
        <Panel position="top-right" className="bg-white p-1 rounded-sm shadow-sm border border-slate-200 flex gap-1">
           <button onClick={() => onLayout('TB')} className="p-1.5 hover:bg-slate-100 rounded text-slate-500" title="Vertical Layout"><Layout size={16} className="rotate-90"/></button>
           <button onClick={() => onLayout('LR')} className="p-1.5 hover:bg-slate-100 rounded text-slate-500" title="Horizontal Layout"><Layout size={16}/></button>
        </Panel>
      </ReactFlow>
    </div>
  );
};

// Main Content Component (Separated to allow ReactFlowProvider wrap)
const ProcessDesignerContent: React.FC = () => {
  const { deployProcess, roles, addNotification, designerDraft, setDesignerDraft, navigateTo, processes, nav, currentUser } = useBPM();

  // React Flow State (Safe to use here as this component is wrapped in ReactFlowProvider)
  const [nodes, setNodes] = useNodesState([]);
  const [edges, setEdges] = useEdgesState([]);

  const [selectedNodeId, setSelectedNodeId] = useState<string | null>(null);
  const [contextMenu, setContextMenu] = useState<{ position: { x: number; y: number }, targetId: string | null } | null>(null);

  // Process Metadata State
  const [processMeta, setProcessMeta] = useState<Partial<ProcessDefinition>>({ 
      name: 'Strategic Workflow', 
      description: '', 
      version: 1, 
      complianceLevel: 'Standard',
      domainId: currentUser?.domainId || 'GLOBAL'
  });

  // UI State
  const [leftOpen, setLeftOpen] = useState(true);
  const [rightOpen, setRightOpen] = useState(true);
  const [viewMode, setViewMode] = useState<'canvas' | 'hierarchy'>('canvas');
  const [aiPrompt, setAiPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [showHeatmap, setShowHeatmap] = useState(false);

  // --- LOADER: Load from DB if ID present, else Draft ---
  useEffect(() => {
      if (nav.selectedId && nav.view === 'designer') {
          const existing = processes.find(p => p.id === nav.selectedId);
          if (existing) {
              setProcessMeta({
                  id: existing.id,
                  name: existing.name,
                  description: existing.description,
                  version: existing.version,
                  complianceLevel: existing.complianceLevel,
                  domainId: existing.domainId
              });

              // Hydrate Nodes
              const dbNodes: Node[] = existing.steps.map(s => ({
                  id: s.id,
                  type: 'custom',
                  position: s.position || { x: 0, y: 0 },
                  data: { step: s }
              }));

              // Hydrate Edges
              const dbEdges: Edge[] = (existing.links || []).map(l => ({
                  id: l.id,
                  source: l.sourceId,
                  target: l.targetId,
                  type: 'custom',
                  label: l.label
              }));

              setNodes(dbNodes);
              setEdges(dbEdges);
              return; // Skip draft load
          }
      }

      // Fallback to Draft
      if (designerDraft && (!nav.selectedId || nav.selectedId === 'new')) {
          const draftNodes: Node[] = designerDraft.steps.map(s => ({
            id: s.id,
            type: 'custom',
            position: s.position || { x: 0, y: 0 },
            data: { step: s }
          }));
          const draftEdges: Edge[] = designerDraft.links.map(l => ({
            id: l.id,
            source: l.sourceId,
            target: l.targetId,
            type: 'custom',
            label: l.label
          }));
          setNodes(draftNodes);
          setEdges(draftEdges);
      }
  }, [nav.selectedId]); // Run when ID changes

  // Ref for stable callback access to avoid infinite loop in useEffect
  const setDesignerDraftRef = useRef(setDesignerDraft);
  useEffect(() => {
      setDesignerDraftRef.current = setDesignerDraft;
  }, [setDesignerDraft]);

  // Sync Flow State -> Draft (Persistence) with Debounce
  useEffect(() => {
    const handler = setTimeout(() => {
        const steps: ProcessStep[] = nodes.map(n => ({
          ...n.data.step,
          position: n.position,
          id: n.id // Ensure ID sync
        }));

        const links: ProcessLink[] = edges.map(e => ({
          id: e.id,
          sourceId: e.source,
          targetId: e.target,
          label: e.label as string
        }));

        setDesignerDraftRef.current({ steps, links });
    }, 1000); // 1s debounce

    return () => clearTimeout(handler);
  }, [nodes, edges]);

  // --- Handlers ---

  // Connection Validation: Enforce BPMN Rules
  const isValidConnection = useCallback((connection: Connection) => {
      const sourceNode = nodes.find(n => n.id === connection.source);
      const targetNode = nodes.find(n => n.id === connection.target);

      if (!sourceNode || !targetNode) return false;
      if (sourceNode.data.step.type === 'end') return false;
      if (targetNode.data.step.type === 'start') return false;
      if (connection.source === connection.target) return false;

      return true;
  }, [nodes]);

  // Auto Layout
  const onLayout = useCallback((direction: 'LR' | 'TB') => {
      const { nodes: layoutedNodes, edges: layoutedEdges } = getLayoutedElements(
        nodes,
        edges,
        direction
      );
      setNodes([...layoutedNodes]);
      setEdges([...layoutedEdges]);
  }, [nodes, edges, setNodes, setEdges]);

  // Auto-Fix Feature
  const handleAutoFix = useCallback(() => {
      let fixesApplied = 0;
      let newNodes = [...nodes];
      let newEdges = [...edges];

      // 1. Ensure Start Node
      if (!newNodes.some(n => n.data.step.type === 'start')) {
          const startId = `node-start-${Date.now()}`;
          const startNode: Node = {
              id: startId,
              type: 'custom',
              position: { x: 50, y: 150 },
              data: { step: { id: startId, name: 'Start', type: 'start', description: 'Auto-added start' } }
          };
          newNodes = [startNode, ...newNodes];
          fixesApplied++;

          // Connect start to first node if exists
          if (newNodes.length > 1) {
              const target = newNodes[1];
              newEdges.push({ id: `edge-fix-${Date.now()}`, source: startId, target: target.id, type: 'custom' });
          }
      }

      // 2. Ensure End Node
      if (!newNodes.some(n => n.data.step.type === 'end')) {
          // Find node with no outgoing edges
          const sources = new Set(newEdges.map(e => e.source));
          const leafNodes = newNodes.filter(n => !sources.has(n.id) && n.data.step.type !== 'start');

          const endId = `node-end-${Date.now()}`;
          const endNode: Node = {
              id: endId,
              type: 'custom',
              position: { x: 800, y: 150 }, // Default position, layout will fix
              data: { step: { id: endId, name: 'End', type: 'end', description: 'Auto-added end' } }
          };
          newNodes.push(endNode);
          fixesApplied++;

          // Connect leaves to End
          leafNodes.forEach((leaf, idx) => {
              newEdges.push({ id: `edge-fix-end-${idx}-${Date.now()}`, source: leaf.id, target: endId, type: 'custom' });
          });
      }

      if (fixesApplied > 0) {
          // Apply layout to cleanup the mess
          const { nodes: layoutedNodes, edges: layoutedEdges } = getLayoutedElements(newNodes, newEdges, 'LR');
          setNodes(layoutedNodes);
          setEdges(layoutedEdges);
          addNotification('success', `Auto-fix applied: Added ${fixesApplied} missing elements and reorganized.`);
      } else {
          addNotification('info', 'Structure appears valid. Re-running layout.');
          onLayout('LR');
      }
  }, [nodes, edges, setNodes, setEdges, addNotification, onLayout]);

  // DnD Handlers
  const onDragOver = useCallback((event: React.DragEvent) => {
    event.preventDefault();
    event.dataTransfer.dropEffect = 'move';
  }, []);

  const onDrop = useCallback(
    (event: React.DragEvent) => {
      event.preventDefault();
      const type = event.dataTransfer.getData('application/reactflow');
      if (!type) return;

      // Simple screen-to-flow projection (approximate)
      const position = {
        x: event.clientX - 280, 
        y: event.clientY - 80, 
      };

      addNode(type as ProcessStepType, position);
    },
    [nodes] 
  );

  const onConnect = useCallback((params: Connection) => setEdges((eds) => addEdge({ ...params, type: 'custom' }, eds)), [setEdges]);

  const addNode = useCallback((type: ProcessStepType, position?: { x: number, y: number }) => {
    const metadata = getStepTypeMetadata(type);
    const id = `node-${Date.now()}`;

    const newStep: ProcessStep = {
      id,
      name: metadata.defaultName,
      type,
      description: '',
      requiredSkills: metadata.defaultSkills || [],
      data: {}
    };

    const newNode: Node = {
      id,
      type: 'custom',
      position: position || { x: 250, y: 250 }, 
      data: { step: newStep }
    };

    setNodes((nds) => nds.concat(newNode));
    setSelectedNodeId(id);
    if (!rightOpen) setRightOpen(true);
  }, [setNodes, rightOpen]);

  const updateSelectedStep = useCallback((updatedStep: ProcessStep) => {
    setNodes((nds) => nds.map((n) => {
      if (n.id === updatedStep.id) {
        return { ...n, data: { ...n.data, step: updatedStep } };
      }
      return n;
    }));
  }, [setNodes]);

  const deleteNode = useCallback((id: string) => {
    setNodes((nds) => nds.filter((n) => n.id !== id));
    setEdges((eds) => eds.filter((e) => e.source !== id && e.target !== id));
    setSelectedNodeId(null);
  }, [setNodes, setEdges]);

  const handleDeploy = async () => {
    // PRE-FLIGHT CHECK
    const invalidNodes = nodes.filter(n => !validateStepConfiguration(n.data.step.type, n.data.step.data));
    if (invalidNodes.length > 0) {
        addNotification('error', `Deploy Failed: ${invalidNodes.length} steps have missing configuration. Check indicators.`);
        // Optionally select the first invalid node
        setSelectedNodeId(invalidNodes[0].id);
        setRightOpen(true);
        return;
    }

    const steps: ProcessStep[] = nodes.map(n => ({
        ...n.data.step,
        position: n.position,
        nextStepIds: edges.filter(e => e.source === n.id).map(e => e.target)
    }));

    const links: ProcessLink[] = edges.map(e => ({
        id: e.id,
        sourceId: e.source,
        targetId: e.target
    }));

    await deployProcess({ 
        ...processMeta,
        steps, 
        links, 
        isActive: true, 
        // Increment version if updating existing
        version: (processMeta.version || 1) + 1 
    });
    addNotification('success', `Process ${processMeta.name} deployed successfully.`);
  };

  const handleClear = () => {
    if(window.confirm('Clear current design?')) {
        setNodes([]);
        setEdges([]);
        setSelectedNodeId(null);
    }
  };

  const handleAiGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!aiPrompt.trim()) return;
    setIsGenerating(true);
    try {
      const generatedSteps = await generateProcessWorkflow(aiPrompt);
      if (generatedSteps && generatedSteps.length > 0) {
        const newNodes: Node[] = generatedSteps.map(s => ({
            id: s.id,
            type: 'custom',
            position: s.position || { x: 0, y: 0 },
            data: { step: s }
        }));

        const newEdges: Edge[] = [];
        for(let i=0; i < generatedSteps.length - 1; i++) {
            newEdges.push({ 
                id: `link-auto-${i}`, 
                source: generatedSteps[i].id, 
                target: generatedSteps[i+1].id,
                type: 'custom'
            });
        }

        const { nodes: layoutedNodes, edges: layoutedEdges } = getLayoutedElements(newNodes, newEdges, 'LR');

        setNodes(layoutedNodes);
        setEdges(layoutedEdges);
        addNotification('success', 'Model synthesized and auto-layout applied.');
        setAiPrompt('');
      }
    } catch (err) { addNotification('error', 'Generation failure.'); } finally { setIsGenerating(false); }
  };

  const handleSimulation = () => {
    if (nodes.length === 0) {
      addNotification('error', 'Canvas is empty. Add steps to simulate.');
      return;
    }
    navigateTo('simulation-report');
  };

  // --- Context Menu ---
  const onContextMenu = useCallback((event: React.MouseEvent, node?: Node) => {
    event.preventDefault();
    setContextMenu({
      position: { x: event.clientX, y: event.clientY },
      targetId: node ? node.id : null,
    });
  }, []);

  const handleMenuAction = (action: string, payload?: any) => {
    if (!contextMenu) return;
    const { targetId, position } = contextMenu;

    switch (action) {
      case 'delete':
        if (targetId) deleteNode(targetId);
        break;
      case 'duplicate':
        if (targetId) {
          const original = nodes.find(n => n.id === targetId);
          if (original) {
            const id = `node-${Date.now()}`;
            const newNode = {
              ...original,
              id,
              position: { x: original.position.x + 50, y: original.position.y + 50 },
              data: { step: { ...original.data.step, id, name: `${original.data.step.name} (Copy)` } },
              selected: true
            };
            setNodes(nds => nds.map(n => ({...n, selected: false})).concat(newNode));
            setSelectedNodeId(id);
          }
        }
        break;
      case 'add-node':
        addNode(payload, { x: 250, y: 250 });
        break;
      case 'clear-canvas':
        handleClear();
        break;
    }
    setContextMenu(null);
  };

  // derived selected step
  const selectedStep = useMemo(() => {
    const node = nodes.find(n => n.id === selectedNodeId);
    return node ? node.data.step : undefined;
  }, [selectedNodeId, nodes]);

  // When node selected, ensure right panel is open
  useEffect(() => {
      if (selectedNodeId && !rightOpen) {
          setRightOpen(true);
      }
  }, [selectedNodeId]);

  return (
      <div className="h-[calc(100vh-100px)] flex flex-col bg-panel border border-default rounded-base shadow-sm overflow-hidden">
        {/* 1. Rigid Toolbar */}
        <div className="h-header bg-subtle border-b border-default flex items-center justify-between px-3 shrink-0">
           <div className="flex items-center gap-3">
              <button 
                onClick={() => setLeftOpen(!leftOpen)} 
                className={`p-1 rounded-base hover:bg-white border border-transparent hover:border-subtle ${leftOpen ? 'text-blue-600' : 'text-secondary'}`}
                title="Toggle Library"
              >
                <LayoutPanelLeft size={16}/>
              </button>
              <div className="h-4 w-px bg-default"></div>
              {/* Process Name Input */}
              <div className="flex flex-col justify-center">
                  <input 
                    className="bg-transparent text-sm font-bold text-primary w-48 outline-none" 
                    value={processMeta.name} 
                    onChange={e => setProcessMeta(p => ({ ...p, name: e.target.value }))} 
                  />
                  {processMeta.id && <span className="text-[9px] text-slate-400 font-mono leading-none">ID: {processMeta.id}</span>}
              </div>
           </div>

           {/* Center Controls */}
           <div className="flex items-center gap-1 bg-slate-200/50 p-0.5 rounded-base border border-default">
              <button 
                onClick={() => setViewMode('canvas')}
                className={`flex items-center gap-2 px-3 py-1 rounded-sm text-xs font-medium transition-all ${viewMode === 'canvas' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
              >
                <Grid size={14}/> Canvas
              </button>
              <button 
                onClick={() => setViewMode('hierarchy')}
                className={`flex items-center gap-2 px-3 py-1 rounded-sm text-xs font-medium transition-all ${viewMode === 'hierarchy' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
              >
                <ListTree size={14}/> Hierarchy
              </button>
           </div>

           <div className="flex items-center gap-2">
              <input className="h-7 w-48 bg-panel border border-default rounded-base px-2 text-xs hidden lg:block" placeholder="Describe workflow for AI generation..." value={aiPrompt} onChange={e => setAiPrompt(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleAiGenerate(e)} disabled={isGenerating}/>

              <button 
                className="p-1.5 text-amber-600 hover:bg-amber-50 rounded-base border border-transparent hover:border-amber-200 transition-all" 
                onClick={handleAutoFix} 
                title="Auto-Fix Structure"
              >
                <Wand2 size={16}/>
              </button>

              <button className="p-1 text-secondary hover:text-rose-600" onClick={handleClear} title="Clear Canvas"><Trash2 size={16}/></button>

              <div className="h-4 w-px bg-default mx-1"></div>

              <button 
                  onClick={() => setShowHeatmap(!showHeatmap)} 
                  className={`p-1 rounded-base transition-colors ${showHeatmap ? 'bg-rose-100 text-rose-600' : 'text-secondary hover:text-primary'}`} 
                  title="Toggle Heatmap"
              >
                  <Thermometer size={16}/>
              </button>

              <button onClick={handleSimulation} className="flex items-center gap-1 px-3 py-1 bg-indigo-600 text-white rounded-base text-xs hover:bg-indigo-700 shadow-sm"><Cpu size={14}/> Simulate</button>
              <button onClick={handleDeploy} className="flex items-center gap-1 px-3 py-1 bg-brand-slate text-white rounded-base text-xs hover:bg-slate-900 shadow-sm"><Save size={14}/> Save</button>

              <div className="h-4 w-px bg-default mx-1"></div>

              <button 
                onClick={() => setRightOpen(!rightOpen)} 
                className={`p-1 rounded-base hover:bg-white border border-transparent hover:border-subtle ${rightOpen ? 'text-blue-600' : 'text-secondary'}`}
                title="Toggle Properties"
              >
                <PanelRight size={16}/>
              </button>
           </div>
        </div>

        <div className="flex-1 flex overflow-hidden">
          {/* 2. Palette (Standard Sidebar) - Collapsible */}
          <div className={`border-r border-default bg-subtle overflow-y-auto z-10 transition-all duration-300 ${leftOpen ? 'w-56' : 'w-0 border-none'}`}>
             <PaletteSidebar onAddNode={(type) => addNode(type)} />
          </div>

          {/* 3. Main View Area (Canvas OR Hierarchy) */}
          <div className="flex-1 h-full bg-canvas relative">
             {viewMode === 'canvas' ? (
                 <DesignerFlow 
                    nodes={nodes}
                    edges={edges}
                    onNodesChange={useCallback((changes: NodeChange[]) => setNodes(nds => applyNodeChanges(changes, nds)), [setNodes])}
                    onEdgesChange={useCallback((changes: EdgeChange[]) => setEdges(eds => applyEdgeChanges(changes, eds)), [setEdges])}
                    onConnect={onConnect}
                    onNodeClick={(_: any, node: Node) => setSelectedNodeId(node.id)}
                    onPaneClick={() => setSelectedNodeId(null)}
                    onContextMenu={onContextMenu}
                    onDrop={onDrop}
                    onDragOver={onDragOver}
                    onLayout={onLayout}
                    isValidConnection={isValidConnection}
                 />
             ) : (
                 <HierarchyView 
                    nodes={nodes} 
                    edges={edges} 
                    onSelectNode={setSelectedNodeId}
                    selectedNodeId={selectedNodeId}
                 />
             )}
          </div>

          {/* 4. Properties (Flexible Right Panel) - Collapsible */}
          <div className={`flex-none border-l border-default bg-panel overflow-hidden shadow-xl z-20 transition-all duration-300 ease-in-out ${rightOpen ? '' : '!w-0 !border-l-0'}`}>
             {selectedStep ? (
               <PropertiesPanel step={selectedStep} onUpdate={updateSelectedStep} onDelete={deleteNode} roles={roles} onClose={() => setRightOpen(false)} />
             ) : (
               <ProcessSettingsPanel meta={processMeta} onChange={upd => setProcessMeta(prev => ({ ...prev, ...upd }))} onClose={() => setRightOpen(false)} />
             )}
          </div>
        </div>

        {/* Context Menu Overlay (Only on Canvas mode effectively) */}
        {contextMenu && viewMode === 'canvas' && (
          <CanvasContextMenu 
            position={contextMenu.position} 
            targetId={contextMenu.targetId} 
            onClose={() => setContextMenu(null)}
            onAction={handleMenuAction}
          />
        )}
      </div>
  );
};

// Export the Wrapped Component
export const ProcessDesigner: React.FC = () => {
  return (
    <ReactFlowProvider>
      <ProcessDesignerContent />
    </ReactFlowProvider>
  );
};

import React, { useState, useMemo } from 'react';
import { ProcessStep, UserRole, IOMapping, RetryPolicy, EscalationRule } from '../../types';
import { useBPM } from '../../contexts/BPMContext';
import { 
  Trash2, Compass, X, ExternalLink, 
  Settings, Database, RefreshCw, ArrowRightLeft, 
  Braces, ShieldAlert, Plus, Minimize2, Key, Sparkles, FunctionSquare, Layout, Clock, AlertCircle
} from 'lucide-react';
import { NexFormGroup } from '../shared/NexUI';
import { getStepTypeMetadata } from './designerUtils';
import { DataMapper } from '../shared/DataMapper';
import { STEP_SCHEMAS, ConfigField } from './stepSchemas';

// Mock variables available in the process context
const PROCESS_VARS = [
    'request.id', 'request.amount', 'request.requester', 'request.date', 
    'approval.status', 'approval.comment', 
    'user.email', 'user.department',
    'system.timestamp', 'case.id'
];

// Mock inputs expected by various step types
const GET_TARGET_SCHEMA = (type: string): string[] => {
    // Generate target schema keys from the static schema definition
    const schema = STEP_SCHEMAS[type as any];
    if (schema) {
        return schema.map(f => f.key);
    }
    return ['config', 'input'];
};

export const PropertiesPanel = ({ 
  step, 
  onUpdate, 
  onDelete, 
  roles,
  onClose
}: { 
  step: ProcessStep | undefined; 
  onUpdate: (step: ProcessStep) => void; 
  onDelete: (id: string) => void; 
  roles: UserRole[]; 
  onClose?: () => void;
}) => {
    const { rules, forms, navigateTo } = useBPM();
    const [activeTab, setActiveTab] = useState<'config' | 'data' | 'logic' | 'policy'>('config');

    // Always call hooks regardless of step existence
    const panelWidthClass = useMemo(() => {
        if (!step) return 'w-[320px]';

        // Data Mapper needs wide view
        if (activeTab === 'data') return 'w-[600px]';

        // Logic with Scripts needs medium wide
        if (activeTab === 'logic' && (step.onEntryAction || step.onExitAction)) return 'w-[450px]';

        // Specific complex steps
        if (['script-task', 'pdf-generate', 'template-render', 'xml-transform', 'json-map', 'api-gateway', 'sql-query', 'graphql-query'].includes(step.type)) {
            return 'w-[480px]';
        }

        if (['sendgrid-email', 'email-send'].includes(step.type)) return 'w-[400px]';

        return 'w-[320px]';
    }, [step?.type, activeTab, step?.onEntryAction, step?.onExitAction]);

    // Render Empty State early return is safe here ONLY because we don't call hooks after.
    // However, for consistency we'll use a conditional variable approach if complex logic was involved.
    // Given the current structure, if (!step) is safe because no hooks follow it. 
    // But let's verify no hooks are hidden in helper functions called later.
    // updateField, updateDataField, etc are closures, not hooks.
    // renderDynamicField is a function, not a hook.

    if (!step) {
      return (
        <aside className={`${panelWidthClass} hidden md:flex h-full flex-col items-center justify-center text-center p-8 bg-white border-l border-slate-300 transition-all duration-300 ease-in-out`}>
          <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mb-4 border border-slate-200">
            <Compass size={32} strokeWidth={1} className="text-slate-300" />
          </div>
          <h3 className="text-sm font-bold text-slate-800">Inspector</h3>
          <p className="text-xs text-slate-500 mt-2 max-w-[200px]">Select a component to configure properties.</p>
        </aside>
      );
    }

    const meta = getStepTypeMetadata(step.type);
    const schema = STEP_SCHEMAS[step.type] || [];

    const updateField = (field: keyof ProcessStep, value: any) => { onUpdate({ ...step, [field]: value }); };
    const updateDataField = (key: string, value: any) => { onUpdate({ ...step, data: { ...step.data, [key]: value } }); };

    const updateEscalation = (field: keyof EscalationRule, value: any) => {
        const current = step.escalation || { enabled: false, daysAfterDue: 1, action: 'notify_manager' };
        onUpdate({ ...step, escalation: { ...current, [field]: value } });
    };

    const updateRetry = (field: keyof RetryPolicy, value: any) => {
        const current = step.retryPolicy || { enabled: false, maxAttempts: 3, strategy: 'fixed', delayMs: 1000 };
        onUpdate({ ...step, retryPolicy: { ...current, [field]: value } });
    };

    const renderDynamicField = (field: ConfigField) => {
        const value = step.data?.[field.key] ?? field.defaultValue ?? '';

        switch(field.type) {
            case 'select':
                return (
                    <NexFormGroup key={field.key} label={field.label} helpText={field.helpText}>
                        <select className="prop-input" value={value} onChange={e => updateDataField(field.key, e.target.value)}>
                            {field.options?.map(opt => <option key={opt} value={opt}>{opt}</option>)}
                        </select>
                    </NexFormGroup>
                );
            case 'textarea':
            case 'json':
            case 'code':
                return (
                    <NexFormGroup key={field.key} label={field.label} helpText={field.helpText}>
                        <textarea 
                            className={`prop-input min-h-[100px] resize-y ${field.type === 'code' || field.type === 'json' ? 'font-mono text-[10px]' : ''}`}
                            value={value} 
                            onChange={e => updateDataField(field.key, e.target.value)} 
                            placeholder={field.placeholder}
                        />
                    </NexFormGroup>
                );
            case 'boolean':
                return (
                    <div key={field.key} className="mb-4 flex items-center justify-between">
                        <label className="prop-label mb-0">{field.label}</label>
                        <input type="checkbox" checked={!!value} onChange={e => updateDataField(field.key, e.target.checked)} className="rounded-sm text-blue-600 focus:ring-blue-500" />
                    </div>
                );
            default:
                return (
                    <NexFormGroup key={field.key} label={field.label} helpText={field.helpText}>
                        <input 
                            type={field.type === 'number' ? 'number' : 'text'}
                            className="prop-input" 
                            value={value} 
                            onChange={e => updateDataField(field.key, e.target.value)} 
                            placeholder={field.placeholder}
                        />
                    </NexFormGroup>
                );
        }
    };

    return (
      <aside className={`${panelWidthClass} h-full bg-white border-l border-slate-300 flex flex-col shadow-xl z-20 transition-all duration-300 ease-in-out`}>
        {/* Header */}
        <div className="h-10 flex items-center justify-between px-4 border-b border-slate-300 bg-slate-50">
          <div className="flex items-center gap-2">
            <meta.icon size={14} className={meta.color} />
            <h3 className="text-xs font-bold text-slate-800 uppercase tracking-wider">{meta.category}</h3>
            <span className="text-[10px] text-slate-400 font-mono">| {step.type}</span>
          </div>
          <div className="flex items-center gap-2">
            <button onClick={() => onUpdate({ ...step, id: step.id } as any)} className="text-slate-400 hover:text-slate-800" title="Minimize/Refresh"><Minimize2 size={14}/></button>
            {onClose && <button onClick={onClose} className="text-slate-400 hover:text-slate-800"><X size={14}/></button>}
          </div>
        </div>

        {/* Identity Block (Always Visible) */}
        <div className="p-4 border-b border-slate-100 bg-white">
            <input 
              type="text" 
              className="text-sm font-bold text-slate-900 w-full outline-none border-b border-transparent focus:border-blue-500 placeholder:text-slate-300 transition-all mb-1" 
              value={step.name} 
              onChange={e => updateField('name', e.target.value)}
              placeholder="Step Name"
            />
            <input 
              type="text"
              className="text-xs text-slate-500 w-full outline-none bg-transparent"
              value={step.description || ''}
              onChange={e => updateField('description', e.target.value)}
              placeholder="Add technical description..."
            />
        </div>

        {/* Tabs */}
        <div className="flex border-b border-slate-200 bg-slate-50/50">
            {[
                { id: 'config', icon: Settings, label: 'Config' },
                { id: 'data', icon: Database, label: 'Wiring' },
                { id: 'logic', icon: FunctionSquare, label: 'Rules' },
                { id: 'policy', icon: ShieldAlert, label: 'Policy' }
            ].map(tab => (
                <button 
                    key={tab.id}
                    onClick={() => setActiveTab(tab.id as any)}
                    className={`flex-1 py-2 flex items-center justify-center gap-1.5 text-[10px] font-bold uppercase transition-all border-b-2 ${activeTab === tab.id ? 'border-blue-600 text-blue-600 bg-white' : 'border-transparent text-slate-500 hover:bg-white hover:text-slate-700'}`}
                >
                    <tab.icon size={12}/> {tab.label}
                </button>
            ))}
        </div>

        <div className="flex-1 p-4 overflow-y-auto no-scrollbar bg-slate-50/30">

          {/* TAB: CONFIGURATION (Dynamic based on type) */}
          {activeTab === 'config' && (
             <div className="space-y-4">
                {/* User Task Specifics */}
                {step.type === 'user-task' && (
                    <div className="space-y-4">
                        <NexFormGroup label="User Interface">
                            <div className="flex items-center gap-2">
                                <Layout size={16} className="text-slate-400"/>
                                <select className="prop-input" value={step.formId || ''} onChange={e => updateField('formId', e.target.value)}>
                                    <option value="">Generic Task View</option>
                                    {forms.map(f => <option key={f.id} value={f.id}>{f.name}</option>)}
                                </select>
                            </div>
                            {step.formId && <button onClick={() => navigateTo('form-designer', step.formId)} className="text-[10px] text-blue-600 hover:underline mt-1 ml-6">Edit Form Definition</button>}
                        </NexFormGroup>

                        <div className="h-px bg-slate-200 my-2"></div>

                        <NexFormGroup label="Role Assignment">
                            <select className="prop-input" value={step.role || ''} onChange={e => updateField('role', e.target.value)}>
                                <option value="">Unassigned</option>
                                {roles.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
                            </select>
                        </NexFormGroup>
                        <NexFormGroup label="Candidate Groups">
                            <input className="prop-input" placeholder="group1, group2" value={step.data?.candidateGroups || ''} onChange={e => updateDataField('candidateGroups', e.target.value)} />
                        </NexFormGroup>
                    </div>
                )}

                {/* Gateway Specifics */}
                {meta.category === 'Gateways' && (
                    <div className="space-y-4">
                        <NexFormGroup label="Default Route ID">
                            <input className="prop-input font-mono" placeholder="Flow ID" value={step.data?.defaultFlow || ''} onChange={e => updateDataField('defaultFlow', e.target.value)} />
                        </NexFormGroup>
                        {step.type === 'exclusive-gateway' && (
                            <NexFormGroup label="Condition Expression (CEL)">
                                <textarea className="prop-input h-24 font-mono text-xs" placeholder="amount > 1000 && approved == true" value={step.data?.condition || ''} onChange={e => updateDataField('condition', e.target.value)} />
                            </NexFormGroup>
                        )}
                    </div>
                )}

                {/* DYNAMIC SCHEMA RENDERING FOR ALL OTHER TYPES */}
                {schema.map(renderDynamicField)}

                {schema.length === 0 && step.type !== 'user-task' && meta.category !== 'Gateways' && (
                    <div className="p-4 text-center text-slate-400 italic text-xs">
                        No configuration required for this component.
                    </div>
                )}
             </div>
          )}

          {/* TAB: DATA WIRING (Visual Mapper) */}
          {activeTab === 'data' && (
              <div className="space-y-6">
                  <div>
                      <div className="flex items-center justify-between mb-2">
                          <h4 className="text-[10px] font-bold text-slate-500 uppercase flex items-center gap-1"><ArrowRightLeft size={10}/> Input Transformation</h4>
                      </div>
                      <DataMapper 
                        mappings={step.inputs || []}
                        onChange={(m) => updateField('inputs', m)}
                        sourceSchema={PROCESS_VARS}
                        targetSchema={GET_TARGET_SCHEMA(step.type)}
                      />
                  </div>
              </div>
          )}

          {/* TAB: LOGIC (Rules & Triggers) */}
          {activeTab === 'logic' && (
              <div className="space-y-4">
                  <NexFormGroup label="Pre-Flight Rule" helpText="Execute business rule before step starts">
                        <select className="prop-input" value={step.businessRuleId || ''} onChange={e => updateField('businessRuleId', e.target.value)}>
                            <option value="">None</option>
                            {rules.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
                        </select>
                        {step.businessRuleId && (
                            <button onClick={() => navigateTo('rules', step.businessRuleId)} className="mt-1 text-[10px] text-blue-600 flex items-center gap-1 hover:underline">
                                Edit Rule <ExternalLink size={10}/>
                            </button>
                        )}
                  </NexFormGroup>

                  <NexFormGroup label="On Entry Script">
                      <div className="relative">
                        <textarea className="prop-input h-20 font-mono text-[10px]" placeholder="console.log('Entering step');" value={step.onEntryAction || ''} onChange={e => updateField('onEntryAction', e.target.value)} />
                        {step.onEntryAction && <Sparkles size={12} className="absolute right-2 bottom-2 text-amber-500 animate-pulse"/>}
                      </div>
                  </NexFormGroup>

                  <NexFormGroup label="On Exit Script">
                      <textarea className="prop-input h-20 font-mono text-[10px]" placeholder="execution.setVariable('status', 'done');" value={step.onExitAction || ''} onChange={e => updateField('onExitAction', e.target.value)} />
                  </NexFormGroup>
              </div>
          )}

          {/* TAB: POLICY (Retry, Timeout, Escalation) */}
          {activeTab === 'policy' && (
              <div className="space-y-6">
                  {/* Retry Section */}
                  <div className="space-y-3">
                      <div className="flex items-center justify-between">
                          <h4 className="text-xs font-bold text-slate-700 flex items-center gap-2"><RefreshCw size={12}/> Retry Policy</h4>
                          <label className="relative inline-flex items-center cursor-pointer">
                            <input type="checkbox" className="sr-only peer" checked={step.retryPolicy?.enabled || false} onChange={e => updateRetry('enabled', e.target.checked)} />
                            <div className="w-8 h-4 bg-slate-200 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-3 after:w-3 after:transition-all peer-checked:bg-blue-600"></div>
                          </label>
                      </div>

                      {step.retryPolicy?.enabled && (
                          <div className="p-3 bg-white border border-slate-200 rounded-sm space-y-3 animate-slide-up">
                              <NexFormGroup label="Strategy">
                                  <select className="prop-input" value={step.retryPolicy?.strategy || 'fixed'} onChange={e => updateRetry('strategy', e.target.value)}>
                                      <option value="fixed">Fixed Delay</option>
                                      <option value="exponential">Exponential Backoff</option>
                                      <option value="linear">Linear Backoff</option>
                                  </select>
                              </NexFormGroup>
                              <div className="grid grid-cols-2 gap-2">
                                  <NexFormGroup label="Max Attempts">
                                      <input type="number" className="prop-input" value={step.retryPolicy?.maxAttempts || 3} onChange={e => updateRetry('maxAttempts', parseInt(e.target.value))} />
                                  </NexFormGroup>
                                  <NexFormGroup label="Delay (ms)">
                                      <input type="number" className="prop-input" value={step.retryPolicy?.delayMs || 1000} onChange={e => updateRetry('delayMs', parseInt(e.target.value))} />
                                  </NexFormGroup>
                              </div>
                          </div>
                      )}
                  </div>

                  <div className="h-px bg-slate-200"></div>

                  {/* Escalation Section */}
                  <div className="space-y-3">
                      <div className="flex items-center justify-between">
                          <h4 className="text-xs font-bold text-slate-700 flex items-center gap-2"><Clock size={12}/> SLA & Escalation</h4>
                          <label className="relative inline-flex items-center cursor-pointer">
                            <input type="checkbox" className="sr-only peer" checked={step.escalation?.enabled || false} onChange={e => updateEscalation('enabled', e.target.checked)} />
                            <div className="w-8 h-4 bg-slate-200 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-3 after:w-3 after:transition-all peer-checked:bg-rose-500"></div>
                          </label>
                      </div>

                      {step.escalation?.enabled && (
                          <div className="p-3 bg-rose-50 border border-rose-100 rounded-sm space-y-3 animate-slide-up">
                              <NexFormGroup label="Trigger After (Days Overdue)">
                                  <input type="number" className="prop-input" value={step.escalation.daysAfterDue} onChange={e => updateEscalation('daysAfterDue', parseInt(e.target.value))} />
                              </NexFormGroup>
                              <NexFormGroup label="Escalation Action">
                                  <select className="prop-input" value={step.escalation.action} onChange={e => updateEscalation('action', e.target.value)}>
                                      <option value="notify_manager">Notify Manager</option>
                                      <option value="reassign">Auto-Reassign</option>
                                      <option value="auto_complete">Force Complete</option>
                                      <option value="trigger_bot">Trigger Remediation Bot</option>
                                  </select>
                              </NexFormGroup>
                              {step.escalation.action === 'reassign' && (
                                  <NexFormGroup label="Target Role ID">
                                      <input className="prop-input" value={step.escalation.targetId || ''} onChange={e => updateEscalation('targetId', e.target.value)} placeholder="e.g. manager" />
                                  </NexFormGroup>
                              )}
                          </div>
                      )}
                  </div>
              </div>
          )}

        </div>

        {/* Footer Actions */}
        <div className="p-4 border-t border-slate-200 bg-slate-50 flex justify-between items-center">
          <button onClick={() => onDelete(step.id)} className="text-rose-600 hover:bg-rose-50 p-2 rounded-sm transition-colors" title="Delete Step">
              <Trash2 size={16}/>
          </button>
          <div className="text-[9px] text-slate-400 font-mono">ID: {step.id}</div>
        </div>
      </aside>
    );
};

export enum TaskStatus {
  PENDING = 'Pending',
  CLAIMED = 'Claimed',
  IN_PROGRESS = 'In Progress',
  COMPLETED = 'Completed',
  REJECTED = 'Rejected'
}

export enum TaskPriority {
  LOW = 'Low',
  MEDIUM = 'Medium',
  HIGH = 'High',
  CRITICAL = 'Critical'
}

export enum Permission {
  PROCESS_VIEW = 'process:view',
  PROCESS_DEPLOY = 'process:deploy',
  PROCESS_START = 'process:start',
  TASK_COMPLETE = 'task:complete',
  TASK_OVERRIDE = 'task:override',
  ADMIN_ACCESS = 'admin:access',
  USER_MANAGE = 'user:manage',
  SYSTEM_CONFIG = 'system:config',
  CASE_MANAGE = 'case:manage',
  RULES_MANAGE = 'rules:manage',
  ANALYTICS_VIEW_ALL = 'analytics:view_all'
}

export interface UserRole {
  id: string;
  name: string;
  permissions: Permission[];
}

export interface UserGroup {
  id: string;
  name: string;
  parentGroupId?: string;
  description: string;
}

export interface User {
  id: string;
  name: string;
  email: string;
  avatar?: string;
  roleIds: string[];
  groupIds: string[];
  skills: string[];
  location: string;
  status: 'Active' | 'On Leave' | 'Terminated';
  delegateToId?: string; 
  lastLogin?: string;
  domainId: string;
}

export interface Delegation {
  id: string;
  fromUserId: string;
  toUserId: string;
  startDate: string;
  endDate: string;
  isActive: boolean;
  scope: 'All' | 'Critical Only';
}

export interface Comment {
  id: string;
  userId: string;
  userName: string;
  text: string;
  timestamp: string;
}

export interface Attachment {
  id: string;
  name: string;
  type: 'internal' | 'external-link';
  size?: number;
  uploadDate: string;
  url?: string; // For external CMIS links
}

export interface Task {
  id:string;
  title: string;
  processName: string; // "Ad-Hoc" if case task
  processInstanceId: string; // or caseId
  assignee: string; 
  candidateRoles: string[]; 
  candidateGroups: string[];
  requiredSkills: string[];
  dueDate: string;
  status: TaskStatus;
  priority: TaskPriority;
  description?: string;
  stepId: string; // or 'adhoc'
  data?: any;
  comments: Comment[];
  attachments: Attachment[];
  isAdHoc: boolean;
  caseId?: string;
  triggerSource?: 'Manual' | 'Rule' | 'System' | 'Escalation';
  // New Features
  tags?: string[];
  isStarred?: boolean;
  snoozeUntil?: string;
  formId?: string; // Phase 2: Link to Form Definition
}

export type ProcessStepType = 
  // --- CORE ---
  | 'start' | 'end' | 'user-task' | 'service-task' | 'sub-process' | 'script-task'
  // --- GATEWAYS ---
  | 'exclusive-gateway' | 'parallel-gateway' | 'inclusive-gateway' | 'complex-gateway' | 'event-gateway'
  // --- EVENTS ---
  | 'timer-event' | 'message-event' | 'signal-event' | 'error-event' | 'escalation-event' | 'compensation-event'
  // --- COMMUNICATION ---
  | 'email-send' | 'slack-post' | 'teams-message' | 'sms-twilio' | 'whatsapp-msg' | 'push-notification' | 'sendgrid-email' | 'mailchimp-add'
  // --- DOCUMENTS ---
  | 'pdf-generate' | 'doc-sign' | 'ocr-extract' | 's3-upload' | 'gdrive-save' | 'sharepoint-store' | 'dropbox-save' | 'template-render'
  // --- CRM & SALES ---
  | 'salesforce-create' | 'salesforce-update' | 'hubspot-add' | 'zoho-lead' | 'pipedrive-deal' | 'dynamics-record' | 'zendesk-ticket' | 'intercom-msg'
  // --- DEV TOOLS ---
  | 'jira-issue' | 'github-pr' | 'gitlab-merge' | 'bitbucket-commit' | 'trello-card' | 'asana-task' | 'linear-issue' | 'pagerduty-alert'
  // --- CLOUD INFRA ---
  | 'aws-lambda' | 'azure-func' | 'gcp-function' | 'kubernetes-job' | 'vm-provision' | 'db-provision' | 'dns-update' | 'cdn-purge'
  // --- DATA & INTEGRATION ---
  | 'sql-query' | 'rest-api' | 'graphql-query' | 'soap-call' | 'kafka-publish' | 'rabbit-mq' | 'ftp-upload' | 'csv-parse' | 'xml-transform' | 'json-map'
  // --- AI & ML ---
  | 'ai-text-gen' | 'ai-summarize' | 'ai-sentiment' | 'ai-vision' | 'ai-translate' | 'ai-classify' | 'automl-predict' | 'vector-embed'
  // --- FINANCE ---
  | 'stripe-charge' | 'paypal-payout' | 'quickbooks-invoice' | 'xero-bill' | 'sap-posting' | 'oracle-ledger' | 'expensify-report'
  // --- LOGIC & RULES ---
  | 'business-rule' | 'decision-table' | 'wait-state' | 'terminate-end' | 'loop-container';

export interface IOMapping {
  source: string; // e.g. "variables.orderId" or "result.id"
  target: string; // e.g. "api.params.id" or "variables.externalId"
  transform?: string; // Optional JS one-liner
}

export interface RetryPolicy {
  enabled: boolean;
  maxAttempts: number;
  strategy: 'fixed' | 'exponential' | 'linear';
  delayMs: number;
}

export interface EscalationRule {
  enabled: boolean;
  daysAfterDue: number;
  action: 'notify_manager' | 'reassign' | 'auto_complete' | 'trigger_bot';
  targetId?: string; // Role ID or User ID
}

export interface StepMetrics {
