import { useBPM } from '../contexts/BPMContext';
import { Play, FileText, Layers, Plus, Activity, Eye, ChevronRight, Globe, ShieldCheck, Clock, Hash, MoreVertical, Copy, Trash2, Edit, PauseCircle, StopCircle, Search, History } from 'lucide-react';
